{
  "name": "939PRO Bubble Pop",
  "description": "A high-octane, neon-colored bubble shooter game with fluid animations, level progression, and AI-powered strategy tips.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type BubbleColor = 'rose' | 'amber' | 'lime' | 'sky' | 'violet' | 'fuchsia';

export interface Bubble {
  x: number;
  y: number;
  color: BubbleColor;
  row: number;
  col: number;
}

export interface Projectile {
  x: number;
  y: number;
  vx: number;
  vy: number;
  color: BubbleColor;
}

export interface GameState {
  score: number;
  level: number;
  grid: (Bubble | null)[][];
  currentBubble: BubbleColor;
  nextBubble: BubbleColor;
  isGameOver: boolean;
  isWon: boolean;
}

export interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  radius: number;
  color: string;
  life: number;
}

import { BubbleColor } from './types';

export const CANVAS_WIDTH = 400;
export const CANVAS_HEIGHT = 600;

export const BUBBLE_RADIUS = 20;
export const GRID_ROWS = 12;
export const GRID_COLS = 8;

export const COLOR_MAP: Record<BubbleColor, string> = {
  rose: '#f43f5e',
  amber: '#f59e0b',
  lime: '#84cc16',
  sky: '#0ea5e9',
  violet: '#8b5cf6',
  fuchsia: '#d946ef'
};

export const BUBBLE_COLORS: BubbleColor[] = ['rose', 'amber', 'lime', 'sky', 'violet', 'fuchsia'];

export const SHOOTER_Y = CANVAS_HEIGHT - 60;
export const SHOOTER_X = CANVAS_WIDTH / 2;

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getAITip = async (score: number, level: number): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `The player is currently at score ${score} on level ${level} in a 939PRO Bubble Shooter game. Provide a short, exciting, one-sentence pro tip or motivational message that mentions the 939PRO brand.`,
      config: {
        maxOutputTokens: 50,
        temperature: 0.7,
      }
    });
    return response.text || "Keep popping for 939PRO glory!";
  } catch (error) {
    console.error("AI tip error:", error);
    return "Precision is the key to 939PRO dominance!";
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import GameBoard from './components/GameBoard';
import { getAITip } from './services/geminiService';

const App: React.FC = () => {
  const [score, setScore] = useState(0);
  const [level, setLevel] = useState(1);
  const [aiTip, setAiTip] = useState("Welcome to 939PRO Bubble Pop!");
  const [gameState, setGameState] = useState<'start' | 'playing' | 'gameover' | 'win'>('start');

  const updateTip = useCallback(async (s: number, l: number) => {
    const tip = await getAITip(s, l);
    setAiTip(tip);
  }, []);

  useEffect(() => {
    if (gameState === 'playing' && score > 0 && score % 500 === 0) {
      updateTip(score, level);
    }
  }, [score, level, gameState, updateTip]);

  const handleStart = () => {
    setScore(0);
    setLevel(1);
    setGameState('playing');
  };

  const handleGameOver = (finalScore: number) => {
    setScore(finalScore);
    setGameState('gameover');
  };

  const handleWin = () => {
    setGameState('win');
  };

  return (
    <div className="fixed inset-0 bg-slate-900 flex flex-col items-center justify-center p-4">
      {/* Header Branding */}
      <div className="w-full max-w-[400px] flex justify-between items-center mb-4 px-2">
        <div className="flex flex-col">
          <h1 className="text-3xl font-black text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-fuchsia-500 tracking-tighter">
            939PRO
          </h1>
          <span className="text-[10px] text-cyan-500/80 font-mono tracking-[0.2em] uppercase">Bubble Shooter Elite</span>
        </div>
        <div className="flex flex-col items-end">
          <div className="text-white font-bold text-lg">Score: <span className="text-cyan-400">{score}</span></div>
          <div className="text-xs text-slate-400 uppercase tracking-widest">Level {level}</div>
        </div>
      </div>

      {/* Main Game Container */}
      <div className="relative w-full max-w-[400px] aspect-[2/3] bg-slate-800 rounded-3xl overflow-hidden border-4 border-slate-700 shadow-2xl shadow-cyan-500/20">
        {gameState === 'playing' ? (
          <GameBoard 
            onScoreChange={setScore} 
            onGameOver={handleGameOver} 
            onWin={handleWin}
          />
        ) : (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/90 backdrop-blur-sm z-50 p-8 text-center">
            {gameState === 'start' && (
              <>
                <div className="w-24 h-24 mb-6 rounded-full bg-gradient-to-tr from-cyan-500 to-fuchsia-500 flex items-center justify-center animate-pulse">
                  <div className="w-16 h-16 rounded-full bg-slate-900 flex items-center justify-center">
                    <span className="text-3xl font-black text-white">939</span>
                  </div>
                </div>
                <h2 className="text-2xl font-bold text-white mb-2">Ready to Pop?</h2>
                <p className="text-slate-400 mb-8">Master the physics of 939PRO and clear the board.</p>
                <button 
                  onClick={handleStart}
                  className="w-full py-4 bg-gradient-to-r from-cyan-500 to-fuchsia-500 rounded-2xl text-white font-black text-xl hover:scale-105 active:scale-95 transition-all shadow-lg shadow-cyan-500/40"
                >
                  START GAME
                </button>
              </>
            )}

            {(gameState === 'gameover' || gameState === 'win') && (
              <>
                <h2 className={`text-4xl font-black mb-2 ${gameState === 'win' ? 'text-green-400' : 'text-rose-500'}`}>
                  {gameState === 'win' ? 'VICTORY' : 'GAME OVER'}
                </h2>
                <div className="text-slate-300 mb-8">
                  <p className="text-lg">Final Score: <span className="font-bold text-white">{score}</span></p>
                  <p className="text-xs mt-2 text-slate-500 italic">"939PRO: Perfection is just a pop away."</p>
                </div>
                <button 
                  onClick={handleStart}
                  className="w-full py-4 bg-slate-100 rounded-2xl text-slate-900 font-black text-xl hover:bg-white active:scale-95 transition-all"
                >
                  PLAY AGAIN
                </button>
              </>
            )}
          </div>
        )}
      </div>

      {/* AI Tip / Footer */}
      <div className="w-full max-w-[400px] mt-4 p-4 bg-slate-800/50 rounded-2xl border border-slate-700/50">
        <p className="text-xs text-slate-400 text-center leading-relaxed font-medium">
          <span className="text-fuchsia-500 font-bold mr-2 uppercase">AI Insight:</span>
          {aiTip}
        </p>
      </div>

      {/* Navigation Simulation for iOS look */}
      <div className="mt-auto pb-4">
        <div className="w-32 h-1.5 bg-slate-700 rounded-full"></div>
      </div>
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { Bubble, BubbleColor, Projectile, Particle } from '../types';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, BUBBLE_RADIUS, GRID_ROWS, GRID_COLS, 
  COLOR_MAP, BUBBLE_COLORS, SHOOTER_X, SHOOTER_Y 
} from '../constants';

interface GameBoardProps {
  onScoreChange: (score: number) => void;
  onGameOver: (score: number) => void;
  onWin: () => void;
}

const GameBoard: React.FC<GameBoardProps> = ({ onScoreChange, onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [score, setScore] = useState(0);
  const [grid, setGrid] = useState<(Bubble | null)[][]>([]);
  const [projectile, setProjectile] = useState<Projectile | null>(null);
  const [nextColor, setNextColor] = useState<BubbleColor>(BUBBLE_COLORS[0]);
  const [activeColor, setActiveColor] = useState<BubbleColor>(BUBBLE_COLORS[1]);
  const [particles, setParticles] = useState<Particle[]>([]);

  const mousePos = useRef({ x: SHOOTER_X, y: 0 });

  // Initialize Grid
  useEffect(() => {
    const newGrid: (Bubble | null)[][] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      newGrid[r] = [];
      const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < colsInRow; c++) {
        if (r < 5) {
          const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
          const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
          newGrid[r][c] = { 
            x, y, 
            color: BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)],
            row: r,
            col: c
          };
        } else {
          newGrid[r][c] = null;
        }
      }
    }
    setGrid(newGrid);
    setNextColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
    setActiveColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
  }, []);

  const getDistance = (x1: number, y1: number, x2: number, y2: number) => {
    return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);
  };

  const getNeighbors = (r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const neighbors: { r: number, c: number }[] = [];
    const evenRowOffsets = [
      { dr: -1, dc: -1 }, { dr: -1, dc: 0 },
      { dr: 0, dc: -1 }, { dr: 0, dc: 1 },
      { dr: 1, dc: -1 }, { dr: 1, dc: 0 }
    ];
    const oddRowOffsets = [
      { dr: -1, dc: 0 }, { dr: -1, dc: 1 },
      { dr: 0, dc: -1 }, { dr: 0, dc: 1 },
      { dr: 1, dc: 0 }, { dr: 1, dc: 1 }
    ];

    const offsets = r % 2 === 0 ? evenRowOffsets : oddRowOffsets;
    for (const off of offsets) {
      const nr = r + off.dr;
      const nc = c + off.dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
        neighbors.push({ r: nr, c: nc });
      }
    }
    return neighbors;
  };

  const handleShoot = useCallback(() => {
    if (projectile) return;

    const dx = mousePos.current.x - SHOOTER_X;
    const dy = mousePos.current.y - SHOOTER_Y;
    const angle = Math.atan2(dy, dx);
    const speed = 12;

    setProjectile({
      x: SHOOTER_X,
      y: SHOOTER_Y,
      vx: Math.cos(angle) * speed,
      vy: Math.sin(angle) * speed,
      color: activeColor
    });

    setActiveColor(nextColor);
    setNextColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
  }, [projectile, activeColor, nextColor]);

  const explode = (x: number, y: number, color: string) => {
    const newParticles: Particle[] = [];
    for (let i = 0; i < 8; i++) {
      newParticles.push({
        x, y,
        vx: (Math.random() - 0.5) * 10,
        vy: (Math.random() - 0.5) * 10,
        radius: Math.random() * 4 + 2,
        color,
        life: 1.0
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
  };

  // Game Loop
  useEffect(() => {
    let animationFrameId: number;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const update = () => {
      // Update Particles
      setParticles(prev => prev.map(p => ({
        ...p,
        x: p.x + p.vx,
        y: p.y + p.vy,
        life: p.life - 0.02
      })).filter(p => p.life > 0));

      // Update Projectile
      if (projectile) {
        let nextX = projectile.x + projectile.vx;
        let nextY = projectile.y + projectile.vy;

        // Wall collisions
        if (nextX - BUBBLE_RADIUS < 0 || nextX + BUBBLE_RADIUS > CANVAS_WIDTH) {
          projectile.vx *= -1;
          nextX = projectile.x + projectile.vx;
        }

        // Ceiling collision or Bubble collision
        let collided = false;
        let bestR = -1;
        let bestC = -1;

        if (nextY - BUBBLE_RADIUS < 0) {
          collided = true;
          // Find best slot in top row
          let minD = Infinity;
          for (let c = 0; c < GRID_COLS; c++) {
            const sx = c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS;
            const d = Math.abs(nextX - sx);
            if (d < minD) { minD = d; bestR = 0; bestC = c; }
          }
        } else {
          for (let r = 0; r < GRID_ROWS; r++) {
            const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
            for (let c = 0; c < colsInRow; c++) {
              const b = grid[r][c];
              if (b && getDistance(nextX, nextY, b.x, b.y) < BUBBLE_RADIUS * 1.8) {
                collided = true;
                // Find empty neighboring slot
                let minD = Infinity;
                const neighbors = getNeighbors(r, c, grid);
                for (const n of neighbors) {
                  if (!grid[n.r][n.c]) {
                    const nx = (n.r % 2 === 0 ? n.c * BUBBLE_RADIUS * 2 : n.c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
                    const ny = n.r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
                    const d = getDistance(nextX, nextY, nx, ny);
                    if (d < minD) { minD = d; bestR = n.r; bestC = n.c; }
                  }
                }
              }
            }
          }
        }

        if (collided) {
          if (bestR === -1) {
            // Fallback: simple snap
            bestR = Math.min(GRID_ROWS - 1, Math.max(0, Math.floor(nextY / (BUBBLE_RADIUS * 1.732))));
            const offset = bestR % 2 === 0 ? 0 : BUBBLE_RADIUS;
            bestC = Math.floor((nextX - offset) / (BUBBLE_RADIUS * 2));
            const maxC = bestR % 2 === 0 ? GRID_COLS - 1 : GRID_COLS - 2;
            bestC = Math.min(maxC, Math.max(0, bestC));
          }

          if (bestR >= GRID_ROWS - 1) {
            onGameOver(score);
          } else {
            const newGrid = [...grid.map(row => [...row])];
            const px = (bestR % 2 === 0 ? bestC * BUBBLE_RADIUS * 2 : bestC * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const py = bestR * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            newGrid[bestR][bestC] = { x: px, y: py, color: projectile.color, row: bestR, col: bestC };

            // Check matches
            const matches: {r: number, c: number}[] = [{ r: bestR, c: bestC }];
            const visited = new Set<string>();
            visited.add(`${bestR},${bestC}`);
            let i = 0;
            while (i < matches.length) {
              const curr = matches[i++];
              const neighbors = getNeighbors(curr.r, curr.c, newGrid);
              for (const n of neighbors) {
                const b = newGrid[n.r][n.c];
                if (b && b.color === projectile.color && !visited.has(`${n.r},${n.c}`)) {
                  visited.add(`${n.r},${n.c}`);
                  matches.push(n);
                }
              }
            }

            if (matches.length >= 3) {
              matches.forEach(m => {
                const b = newGrid[m.r][m.c];
                if (b) explode(b.x, b.y, COLOR_MAP[b.color]);
                newGrid[m.r][m.c] = null;
              });
              setScore(s => {
                const ns = s + matches.length * 10;
                onScoreChange(ns);
                return ns;
              });

              // Drop floating bubbles
              const anchored = new Set<string>();
              const q: {r: number, c: number}[] = [];
              for (let c = 0; c < GRID_COLS; c++) {
                if (newGrid[0][c]) {
                  anchored.add(`0,${c}`);
                  q.push({ r: 0, c });
                }
              }
              let qi = 0;
              while (qi < q.length) {
                const curr = q[qi++];
                const neighbors = getNeighbors(curr.r, curr.c, newGrid);
                for (const n of neighbors) {
                  if (newGrid[n.r][n.c] && !anchored.has(`${n.r},${n.c}`)) {
                    anchored.add(`${n.r},${n.c}`);
                    q.push(n);
                  }
                }
              }

              for (let r = 0; r < GRID_ROWS; r++) {
                const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
                for (let c = 0; c < colsInRow; c++) {
                  if (newGrid[r][c] && !anchored.has(`${r},${c}`)) {
                    const b = newGrid[r][c]!;
                    explode(b.x, b.y, COLOR_MAP[b.color]);
                    newGrid[r][c] = null;
                    setScore(s => {
                      const ns = s + 20;
                      onScoreChange(ns);
                      return ns;
                    });
                  }
                }
              }
            }

            setGrid(newGrid);
            setProjectile(null);

            // Win check
            const hasBubbles = newGrid.some(row => row.some(b => b !== null));
            if (!hasBubbles) onWin();
          }
        } else {
          setProjectile({ ...projectile, x: nextX, y: nextY });
        }
      }

      render();
      animationFrameId = requestAnimationFrame(update);
    };

    const drawBubble = (x: number, y: number, color: string, radius: number = BUBBLE_RADIUS, alpha: number = 1.0) => {
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.beginPath();
      ctx.arc(x, y, radius - 1, 0, Math.PI * 2);
      ctx.fillStyle = color;
      ctx.shadowBlur = 10;
      ctx.shadowColor = color;
      ctx.fill();

      // Shine
      ctx.beginPath();
      ctx.arc(x - radius/3, y - radius/3, radius/4, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(255,255,255,0.4)';
      ctx.fill();
      ctx.restore();
    };

    const render = () => {
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // Draw Grid
      grid.forEach(row => row.forEach(b => {
        if (b) drawBubble(b.x, b.y, COLOR_MAP[b.color]);
      }));

      // Draw Aiming Line
      const dx = mousePos.current.x - SHOOTER_X;
      const dy = mousePos.current.y - SHOOTER_Y;
      const angle = Math.atan2(dy, dx);
      ctx.beginPath();
      ctx.setLineDash([5, 5]);
      ctx.moveTo(SHOOTER_X, SHOOTER_Y);
      ctx.lineTo(SHOOTER_X + Math.cos(angle) * 100, SHOOTER_Y + Math.sin(angle) * 100);
      ctx.strokeStyle = 'rgba(255,255,255,0.2)';
      ctx.stroke();
      ctx.setLineDash([]);

      // Draw Projectile
      if (projectile) {
        drawBubble(projectile.x, projectile.y, COLOR_MAP[projectile.color]);
      }

      // Draw Particles
      particles.forEach(p => {
        drawBubble(p.x, p.y, p.color, p.radius, p.life);
      });

      // Draw Shooter UI
      drawBubble(SHOOTER_X, SHOOTER_Y, COLOR_MAP[activeColor], BUBBLE_RADIUS + 2);
      drawBubble(SHOOTER_X + 60, SHOOTER_Y + 15, COLOR_MAP[nextColor], BUBBLE_RADIUS * 0.7);

      ctx.fillStyle = 'rgba(255,255,255,0.5)';
      ctx.font = '10px Inter';
      ctx.textAlign = 'center';
      ctx.fillText('NEXT', SHOOTER_X + 60, SHOOTER_Y + 45);
    };

    update();
    return () => cancelAnimationFrame(animationFrameId);
  }, [grid, projectile, activeColor, nextColor, particles, onGameOver, onScoreChange, onWin, score]);

  const handlePointer = (e: React.PointerEvent) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    mousePos.current = {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top
    };
  };

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onPointerMove={handlePointer}
      onPointerDown={(e) => {
        handlePointer(e);
        handleShoot();
      }}
      className="w-full h-full cursor-crosshair touch-none"
    />
  );
};

export default GameBoard;

