import React, { useRef, useEffect, useState, useCallback } from 'react';
import { Bubble, BubbleColor, Projectile, Particle } from '../types';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, BUBBLE_RADIUS, GRID_ROWS, GRID_COLS, 
  COLOR_PALETTES, BUBBLE_COLORS, SHOOTER_X, SHOOTER_Y, SHOTS_TO_DROP
} from '../constants';

interface GameBoardProps {
  level: number;
  onScoreChange: (score: number) => void;
  onGameOver: (score: number) => void;
  onWin: () => void;
}

const GameBoard: React.FC<GameBoardProps> = ({ level, onScoreChange, onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [score, setScore] = useState(0);
  const [grid, setGrid] = useState<(Bubble | null)[][]>([]);
  const [projectile, setProjectile] = useState<Projectile | null>(null);
  const [nextColor, setNextColor] = useState<BubbleColor>(BUBBLE_COLORS[0]);
  const [activeColor, setActiveColor] = useState<BubbleColor>(BUBBLE_COLORS[1]);
  const [particles, setParticles] = useState<Particle[]>([]);
  const [shotsTaken, setShotsTaken] = useState(0);

  const mousePos = useRef({ x: SHOOTER_X, y: 0 });

  // Current Palette based on level
  const palette = COLOR_PALETTES[(level - 1) % COLOR_PALETTES.length];

  // Initialize/Reset Grid when Level Changes
  useEffect(() => {
    const startRows = Math.min(GRID_ROWS - 2, 4 + Math.floor(level / 2));
    const newGrid: (Bubble | null)[][] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      newGrid[r] = [];
      const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < colsInRow; c++) {
        if (r < startRows) {
          const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
          const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
          newGrid[r][c] = { 
            x, y, 
            color: BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)],
            row: r,
            col: c
          };
        } else {
          newGrid[r][c] = null;
        }
      }
    }
    setGrid(newGrid);
    setShotsTaken(0);
    setNextColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
    setActiveColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
  }, [level]);

  const getDistance = (x1: number, y1: number, x2: number, y2: number) => {
    return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);
  };

  const getNeighbors = (r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const neighbors: { r: number, c: number }[] = [];
    const evenRowOffsets = [
      { dr: -1, dc: -1 }, { dr: -1, dc: 0 },
      { dr: 0, dc: -1 }, { dr: 0, dc: 1 },
      { dr: 1, dc: -1 }, { dr: 1, dc: 0 }
    ];
    const oddRowOffsets = [
      { dr: -1, dc: 0 }, { dr: -1, dc: 1 },
      { dr: 0, dc: -1 }, { dr: 0, dc: 1 },
      { dr: 1, dc: 0 }, { dr: 1, dc: 1 }
    ];

    const offsets = r % 2 === 0 ? evenRowOffsets : oddRowOffsets;
    for (const off of offsets) {
      const nr = r + off.dr;
      const nc = c + off.dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
        neighbors.push({ r: nr, c: nc });
      }
    }
    return neighbors;
  };

  const dropGrid = useCallback(() => {
    setGrid(oldGrid => {
      const newGrid: (Bubble | null)[][] = [];
      // Push every row down
      for (let r = 0; r < GRID_ROWS; r++) {
        newGrid[r] = [];
        const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;

        if (r === 0) {
          // New row at the top
          for (let c = 0; c < colsInRow; c++) {
            const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            newGrid[r][c] = { 
              x, y, 
              color: BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)],
              row: r,
              col: c
            };
          }
        } else {
          // Copy from row above
          const prevRow = oldGrid[r - 1];
          const prevCols = (r - 1) % 2 === 0 ? GRID_COLS : GRID_COLS - 1;

          for (let c = 0; c < colsInRow; c++) {
            // This is complex because hex grid shifts columns. 
            // Simplified: we re-calculate positions and just carry over the colors.
            // A more robust shift would use a stable grid index.
            // Let's just shift colors based on index for now.
            const sourceColor = c < prevCols ? prevRow[c]?.color : null;

            const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;

            if (sourceColor) {
              newGrid[r][c] = { x, y, color: sourceColor, row: r, col: c };
            } else {
              newGrid[r][c] = null;
            }
          }
        }
      }

      // Check if any bubble hit the bottom row
      const lastRow = newGrid[GRID_ROWS - 2];
      if (lastRow.some(b => b !== null)) {
        onGameOver(score);
      }

      return newGrid;
    });
  }, [score, onGameOver]);

  const handleShoot = useCallback(() => {
    if (projectile) return;

    const dx = mousePos.current.x - SHOOTER_X;
    const dy = mousePos.current.y - SHOOTER_Y;
    const angle = Math.atan2(dy, dx);
    const speed = 12 + (level * 0.5); // Faster projectile as level increases

    setProjectile({
      x: SHOOTER_X,
      y: SHOOTER_Y,
      vx: Math.cos(angle) * speed,
      vy: Math.sin(angle) * speed,
      color: activeColor
    });

    setShotsTaken(prev => {
      const next = prev + 1;
      if (next % SHOTS_TO_DROP === 0) {
        // We drop after the collision logic in the loop usually, 
        // but let's trigger a drop state if needed.
      }
      return next;
    });

    setActiveColor(nextColor);
    setNextColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
  }, [projectile, activeColor, nextColor, level]);

  const explode = (x: number, y: number, color: string) => {
    const newParticles: Particle[] = [];
    for (let i = 0; i < 8; i++) {
      newParticles.push({
        x, y,
        vx: (Math.random() - 0.5) * 10,
        vy: (Math.random() - 0.5) * 10,
        radius: Math.random() * 4 + 2,
        color,
        life: 1.0
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
  };

  // Game Loop
  useEffect(() => {
    let animationFrameId: number;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const update = () => {
      // Update Particles
      setParticles(prev => prev.map(p => ({
        ...p,
        x: p.x + p.vx,
        y: p.y + p.vy,
        life: p.life - 0.02
      })).filter(p => p.life > 0));

      // Update Projectile
      if (projectile) {
        let nextX = projectile.x + projectile.vx;
        let nextY = projectile.y + projectile.vy;

        // Wall collisions
        if (nextX - BUBBLE_RADIUS < 0 || nextX + BUBBLE_RADIUS > CANVAS_WIDTH) {
          projectile.vx *= -1;
          nextX = projectile.x + projectile.vx;
        }

        let collided = false;
        let bestR = -1;
        let bestC = -1;

        if (nextY - BUBBLE_RADIUS < 0) {
          collided = true;
          let minD = Infinity;
          for (let c = 0; c < GRID_COLS; c++) {
            const sx = c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS;
            const d = Math.abs(nextX - sx);
            if (d < minD) { minD = d; bestR = 0; bestC = c; }
          }
        } else {
          for (let r = 0; r < GRID_ROWS; r++) {
            const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
            for (let c = 0; c < colsInRow; c++) {
              const b = grid[r][c];
              if (b && getDistance(nextX, nextY, b.x, b.y) < BUBBLE_RADIUS * 1.8) {
                collided = true;
                let minD = Infinity;
                const neighbors = getNeighbors(r, c, grid);
                for (const n of neighbors) {
                  if (!grid[n.r][n.c]) {
                    const nx = (n.r % 2 === 0 ? n.c * BUBBLE_RADIUS * 2 : n.c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
                    const ny = n.r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
                    const d = getDistance(nextX, nextY, nx, ny);
                    if (d < minD) { minD = d; bestR = n.r; bestC = n.c; }
                  }
                }
              }
            }
          }
        }

        if (collided) {
          if (bestR === -1) {
            bestR = Math.min(GRID_ROWS - 1, Math.max(0, Math.floor(nextY / (BUBBLE_RADIUS * 1.732))));
            const offset = bestR % 2 === 0 ? 0 : BUBBLE_RADIUS;
            bestC = Math.floor((nextX - offset) / (BUBBLE_RADIUS * 2));
            const maxC = bestR % 2 === 0 ? GRID_COLS - 1 : GRID_COLS - 2;
            bestC = Math.min(maxC, Math.max(0, bestC));
          }

          if (bestR >= GRID_ROWS - 2) {
            onGameOver(score);
          } else {
            const newGrid = [...grid.map(row => [...row])];
            const px = (bestR % 2 === 0 ? bestC * BUBBLE_RADIUS * 2 : bestC * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const py = bestR * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            newGrid[bestR][bestC] = { x: px, y: py, color: projectile.color, row: bestR, col: bestC };

            const matches: {r: number, c: number}[] = [{ r: bestR, c: bestC }];
            const visited = new Set<string>();
            visited.add(`${bestR},${bestC}`);
            let i = 0;
            while (i < matches.length) {
              const curr = matches[i++];
              const neighbors = getNeighbors(curr.r, curr.c, newGrid);
              for (const n of neighbors) {
                const b = newGrid[n.r][n.c];
                if (b && b.color === projectile.color && !visited.has(`${n.r},${n.c}`)) {
                  visited.add(`${n.r},${n.c}`);
                  matches.push(n);
                }
              }
            }

            if (matches.length >= 3) {
              matches.forEach(m => {
                const b = newGrid[m.r][m.c];
                if (b) explode(b.x, b.y, palette[b.color]);
                newGrid[m.r][m.c] = null;
              });
              setScore(s => {
                const ns = s + matches.length * 10;
                onScoreChange(ns);
                return ns;
              });

              const anchored = new Set<string>();
              const q: {r: number, c: number}[] = [];
              for (let c = 0; c < GRID_COLS; c++) {
                if (newGrid[0][c]) {
                  anchored.add(`0,${c}`);
                  q.push({ r: 0, c });
                }
              }
              let qi = 0;
              while (qi < q.length) {
                const curr = q[qi++];
                const neighbors = getNeighbors(curr.r, curr.c, newGrid);
                for (const n of neighbors) {
                  if (newGrid[n.r][n.c] && !anchored.has(`${n.r},${n.c}`)) {
                    anchored.add(`${n.r},${n.c}`);
                    q.push(n);
                  }
                }
              }

              for (let r = 0; r < GRID_ROWS; r++) {
                const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
                for (let c = 0; c < colsInRow; c++) {
                  if (newGrid[r][c] && !anchored.has(`${r},${c}`)) {
                    const b = newGrid[r][c]!;
                    explode(b.x, b.y, palette[b.color]);
                    newGrid[r][c] = null;
                    setScore(s => {
                      const ns = s + 20;
                      onScoreChange(ns);
                      return ns;
                    });
                  }
                }
              }
            }

            setGrid(newGrid);
            setProjectile(null);

            // Check if grid should drop
            if (shotsTaken > 0 && shotsTaken % SHOTS_TO_DROP === 0) {
              dropGrid();
            }

            // Win check
            const hasBubbles = newGrid.some(row => row.some(b => b !== null));
            if (!hasBubbles) onWin();
          }
        } else {
          setProjectile({ ...projectile, x: nextX, y: nextY });
        }
      }

      render();
      animationFrameId = requestAnimationFrame(update);
    };

    const drawBubble = (x: number, y: number, color: string, radius: number = BUBBLE_RADIUS, alpha: number = 1.0) => {
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.beginPath();
      ctx.arc(x, y, radius - 1, 0, Math.PI * 2);
      ctx.fillStyle = color;
      ctx.shadowBlur = 10;
      ctx.shadowColor = color;
      ctx.fill();

      ctx.beginPath();
      ctx.arc(x - radius/3, y - radius/3, radius/4, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(255,255,255,0.4)';
      ctx.fill();
      ctx.restore();
    };

    const render = () => {
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      grid.forEach(row => row.forEach(b => {
        if (b) drawBubble(b.x, b.y, palette[b.color]);
      }));

      const dx = mousePos.current.x - SHOOTER_X;
      const dy = mousePos.current.y - SHOOTER_Y;
      const angle = Math.atan2(dy, dx);
      ctx.beginPath();
      ctx.setLineDash([5, 5]);
      ctx.moveTo(SHOOTER_X, SHOOTER_Y);
      ctx.lineTo(SHOOTER_X + Math.cos(angle) * 100, SHOOTER_Y + Math.sin(angle) * 100);
      ctx.strokeStyle = 'rgba(255,255,255,0.2)';
      ctx.stroke();
      ctx.setLineDash([]);

      if (projectile) {
        drawBubble(projectile.x, projectile.y, palette[projectile.color]);
      }

      particles.forEach(p => {
        drawBubble(p.x, p.y, p.color, p.radius, p.life);
      });

      // Drop Warning UI
      const dropsIn = SHOTS_TO_DROP - (shotsTaken % SHOTS_TO_DROP);
      ctx.fillStyle = dropsIn <= 1 ? 'rgba(244, 63, 94, 0.8)' : 'rgba(255, 255, 255, 0.3)';
      ctx.font = 'bold 10px Inter';
      ctx.textAlign = 'left';
      ctx.fillText(`DROP IN: ${dropsIn}`, 20, CANVAS_HEIGHT - 20);

      drawBubble(SHOOTER_X, SHOOTER_Y, palette[activeColor], BUBBLE_RADIUS + 2);
      drawBubble(SHOOTER_X + 60, SHOOTER_Y + 15, palette[nextColor], BUBBLE_RADIUS * 0.7);

      ctx.fillStyle = 'rgba(255,255,255,0.5)';
      ctx.font = '10px Inter';
      ctx.textAlign = 'center';
      ctx.fillText('NEXT', SHOOTER_X + 60, SHOOTER_Y + 45);
    };

    update();
    return () => cancelAnimationFrame(animationFrameId);
  }, [grid, projectile, activeColor, nextColor, particles, onGameOver, onScoreChange, onWin, score, palette, shotsTaken, dropGrid]);

  const handlePointer = (e: React.PointerEvent) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    mousePos.current = {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top
    };
  };

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onPointerMove={handlePointer}
      onPointerDown={(e) => {
        handlePointer(e);
        handleShoot();
      }}
      className="w-full h-full cursor-crosshair touch-none"
    />
  );
};

export default GameBoard;

export type BubbleColor = 'rose' | 'amber' | 'lime' | 'sky' | 'violet' | 'fuchsia';
export type BubbleType = 'normal' | 'bomb' | 'laser';

export interface Bubble {
  x: number;
  y: number;
  color: BubbleColor;
  row: number;
  col: number;
  type?: BubbleType;
}

export interface Projectile {
  x: number;
  y: number;
  vx: number;
  vy: number;
  color: BubbleColor;
}

export interface GameState {
  score: number;
  level: number;
  grid: (Bubble | null)[][];
  currentBubble: BubbleColor;
  nextBubble: BubbleColor;
  isGameOver: boolean;
  isWon: boolean;
}

export interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  radius: number;
  color: string;
  life: number;
  type?: 'sparkle' | 'smoke' | 'beam';
}

import { BubbleColor } from './types';

export const CANVAS_WIDTH = 400;
export const CANVAS_HEIGHT = 600;

export const BUBBLE_RADIUS = 20;
export const GRID_ROWS = 14; 
export const GRID_COLS = 8;

export const BUBBLE_COLORS: BubbleColor[] = ['rose', 'amber', 'lime', 'sky', 'violet', 'fuchsia'];

export const COLOR_PALETTES: Record<BubbleColor, string>[] = [
  { // Standard Neon
    rose: '#f43f5e',
    amber: '#f59e0b',
    lime: '#84cc16',
    sky: '#0ea5e9',
    violet: '#8b5cf6',
    fuchsia: '#d946ef'
  },
  { // Cyberpunk Night
    rose: '#ff0055',
    amber: '#ffcc00',
    lime: '#00ff66',
    sky: '#00ffff',
    violet: '#9900ff',
    fuchsia: '#ff00ff'
  },
  { // Retro Sunset
    rose: '#ef4444',
    amber: '#f97316',
    lime: '#fbbf24',
    sky: '#38bdf8',
    violet: '#818cf8',
    fuchsia: '#c084fc'
  },
  { // Arctic Pulse
    rose: '#fb7185',
    amber: '#fbbf24',
    lime: '#4ade80',
    sky: '#22d3ee',
    violet: '#a78bfa',
    fuchsia: '#f472b6'
  }
];

export const POWER_UP_CHANCE = 0.08; // 8% chance for a bubble to be a power-up
export const SHOOTER_Y = CANVAS_HEIGHT - 60;
export const SHOOTER_X = CANVAS_WIDTH / 2;
export const SHOTS_TO_DROP = 6;

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { Bubble, BubbleColor, Projectile, Particle, BubbleType } from '../types';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, BUBBLE_RADIUS, GRID_ROWS, GRID_COLS, 
  COLOR_PALETTES, BUBBLE_COLORS, SHOOTER_X, SHOOTER_Y, SHOTS_TO_DROP, POWER_UP_CHANCE
} from '../constants';

interface GameBoardProps {
  level: number;
  onScoreChange: (score: number) => void;
  onGameOver: (score: number) => void;
  onWin: () => void;
}

const GameBoard: React.FC<GameBoardProps> = ({ level, onScoreChange, onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [score, setScore] = useState(0);
  const [grid, setGrid] = useState<(Bubble | null)[][]>([]);
  const [projectile, setProjectile] = useState<Projectile | null>(null);
  const [nextColor, setNextColor] = useState<BubbleColor>(BUBBLE_COLORS[0]);
  const [activeColor, setActiveColor] = useState<BubbleColor>(BUBBLE_COLORS[1]);
  const [particles, setParticles] = useState<Particle[]>([]);
  const [shotsTaken, setShotsTaken] = useState(0);
  const [shake, setShake] = useState(0);

  const mousePos = useRef({ x: SHOOTER_X, y: 0 });
  const palette = COLOR_PALETTES[(level - 1) % COLOR_PALETTES.length];

  const generateBubble = (r: number, c: number): Bubble => {
    const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
    const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
    const isPowerUp = Math.random() < POWER_UP_CHANCE;
    const type: BubbleType = isPowerUp ? (Math.random() > 0.5 ? 'bomb' : 'laser') : 'normal';
    return { 
      x, y, 
      color: BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)],
      row: r,
      col: c,
      type
    };
  };

  useEffect(() => {
    const startRows = Math.min(GRID_ROWS - 2, 4 + Math.floor(level / 2));
    const newGrid: (Bubble | null)[][] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      newGrid[r] = [];
      const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < colsInRow; c++) {
        if (r < startRows) {
          newGrid[r][c] = generateBubble(r, c);
        } else {
          newGrid[r][c] = null;
        }
      }
    }
    setGrid(newGrid);
    setShotsTaken(0);
    setNextColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
    setActiveColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
  }, [level]);

  const getDistance = (x1: number, y1: number, x2: number, y2: number) => {
    return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);
  };

  const getNeighbors = (r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const neighbors: { r: number, c: number }[] = [];
    const evenRowOffsets = [
      { dr: -1, dc: -1 }, { dr: -1, dc: 0 },
      { dr: 0, dc: -1 }, { dr: 0, dc: 1 },
      { dr: 1, dc: -1 }, { dr: 1, dc: 0 }
    ];
    const oddRowOffsets = [
      { dr: -1, dc: 0 }, { dr: -1, dc: 1 },
      { dr: 0, dc: -1 }, { dr: 0, dc: 1 },
      { dr: 1, dc: 0 }, { dr: 1, dc: 1 }
    ];
    const offsets = r % 2 === 0 ? evenRowOffsets : oddRowOffsets;
    for (const off of offsets) {
      const nr = r + off.dr;
      const nc = c + off.dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
        neighbors.push({ r: nr, c: nc });
      }
    }
    return neighbors;
  };

  const explode = (x: number, y: number, color: string, count: number = 8) => {
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      newParticles.push({
        x, y,
        vx: (Math.random() - 0.5) * 10,
        vy: (Math.random() - 0.5) * 10,
        radius: Math.random() * 4 + 2,
        color,
        life: 1.0
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
  };

  const triggerLaser = useCallback((r: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
    let clearedCount = 0;

    // Visual Beam Effect
    setParticles(prev => [...prev, {
      x: CANVAS_WIDTH / 2,
      y: r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS,
      vx: 0, vy: 0, radius: 20, color: '#00ffff', life: 0.5, type: 'beam'
    }]);

    for (let c = 0; c < colsInRow; c++) {
      if (newGrid[r][c]) {
        const b = newGrid[r][c]!;
        explode(b.x, b.y, '#ffffff', 12);
        newGrid[r][c] = null;
        clearedCount++;
      }
    }
    setScore(s => s + clearedCount * 20);
    return newGrid;
  }, []);

  const triggerBomb = useCallback((r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const center = newGrid[r][c];
    if (!center) return newGrid;

    setShake(10);
    explode(center.x, center.y, '#ff4400', 30);

    let clearedCount = 0;
    for (let dr = -2; dr <= 2; dr++) {
      for (let dc = -2; dc <= 2; dc++) {
        const nr = r + dr;
        const nc = c + dc;
        if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
          const b = newGrid[nr][nc];
          if (b && getDistance(center.x, center.y, b.x, b.y) < BUBBLE_RADIUS * 3.5) {
            explode(b.x, b.y, palette[b.color], 5);
            newGrid[nr][nc] = null;
            clearedCount++;
          }
        }
      }
    }
    setScore(s => s + clearedCount * 15);
    return newGrid;
  }, [palette]);

  const dropGrid = useCallback(() => {
    setGrid(oldGrid => {
      const newGrid: (Bubble | null)[][] = [];
      for (let r = 0; r < GRID_ROWS; r++) {
        newGrid[r] = [];
        const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
        if (r === 0) {
          for (let c = 0; c < colsInRow; c++) {
            newGrid[r][c] = generateBubble(r, c);
          }
        } else {
          const prevRow = oldGrid[r - 1];
          const prevCols = (r - 1) % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < colsInRow; c++) {
            const source = c < prevCols ? prevRow[c] : null;
            const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            if (source) {
              newGrid[r][c] = { ...source, x, y, row: r, col: c };
            } else {
              newGrid[r][c] = null;
            }
          }
        }
      }
      if (newGrid[GRID_ROWS - 2].some(b => b !== null)) onGameOver(score);
      return newGrid;
    });
  }, [score, onGameOver]);

  const handleShoot = useCallback(() => {
    if (projectile) return;
    const dx = mousePos.current.x - SHOOTER_X;
    const dy = mousePos.current.y - SHOOTER_Y;
    const angle = Math.atan2(dy, dx);
    const speed = 12 + (level * 0.5);
    setProjectile({
      x: SHOOTER_X, y: SHOOTER_Y, vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed, color: activeColor
    });
    setShotsTaken(prev => prev + 1);
    setActiveColor(nextColor);
    setNextColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
  }, [projectile, activeColor, nextColor, level]);

  useEffect(() => {
    let animationFrameId: number;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const update = () => {
      setParticles(prev => prev.map(p => ({
        ...p, x: p.x + p.vx, y: p.y + p.vy, life: p.life - 0.02
      })).filter(p => p.life > 0));

      if (shake > 0) setShake(s => Math.max(0, s - 0.5));

      if (projectile) {
        let nextX = projectile.x + projectile.vx;
        let nextY = projectile.y + projectile.vy;
        if (nextX - BUBBLE_RADIUS < 0 || nextX + BUBBLE_RADIUS > CANVAS_WIDTH) {
          projectile.vx *= -1;
          nextX = projectile.x + projectile.vx;
        }
        let collided = false;
        let bestR = -1;
        let bestC = -1;
        let hitBubble: Bubble | null = null;

        if (nextY - BUBBLE_RADIUS < 0) {
          collided = true;
          let minD = Infinity;
          for (let c = 0; c < GRID_COLS; c++) {
            const sx = c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS;
            const d = Math.abs(nextX - sx);
            if (d < minD) { minD = d; bestR = 0; bestC = c; }
          }
        } else {
          for (let r = 0; r < GRID_ROWS; r++) {
            const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
            for (let c = 0; c < cols; c++) {
              const b = grid[r][c];
              if (b && getDistance(nextX, nextY, b.x, b.y) < BUBBLE_RADIUS * 1.8) {
                collided = true;
                hitBubble = b;
                let minD = Infinity;
                const neighbors = getNeighbors(r, c, grid);
                for (const n of neighbors) {
                  if (!grid[n.r][n.c]) {
                    const nx = (n.r % 2 === 0 ? n.c * BUBBLE_RADIUS * 2 : n.c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
                    const ny = n.r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
                    const d = getDistance(nextX, nextY, nx, ny);
                    if (d < minD) { minD = d; bestR = n.r; bestC = n.c; }
                  }
                }
              }
            }
          }
        }

        if (collided) {
          let updatedGrid = [...grid.map(row => [...row])];

          // Power-up hit logic
          if (hitBubble?.type === 'bomb') {
            updatedGrid = triggerBomb(hitBubble.row, hitBubble.col, updatedGrid);
          } else if (hitBubble?.type === 'laser') {
            updatedGrid = triggerLaser(hitBubble.row, updatedGrid);
          } else if (bestR !== -1) {
            const px = (bestR % 2 === 0 ? bestC * BUBBLE_RADIUS * 2 : bestC * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const py = bestR * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            updatedGrid[bestR][bestC] = { x: px, y: py, color: projectile.color, row: bestR, col: bestC, type: 'normal' };

            const matches: {r: number, c: number}[] = [{ r: bestR, c: bestC }];
            const visited = new Set<string>(); visited.add(`${bestR},${bestC}`);
            let mi = 0;
            while (mi < matches.length) {
              const curr = matches[mi++];
              const neighbors = getNeighbors(curr.r, curr.c, updatedGrid);
              for (const n of neighbors) {
                const b = updatedGrid[n.r][n.c];
                if (b && b.color === projectile.color && b.type === 'normal' && !visited.has(`${n.r},${n.c}`)) {
                  visited.add(`${n.r},${n.c}`);
                  matches.push(n);
                }
              }
            }

            if (matches.length >= 3) {
              matches.forEach(m => {
                const b = updatedGrid[m.r][m.c];
                if (b) explode(b.x, b.y, palette[b.color]);
                updatedGrid[m.r][m.c] = null;
              });
              setScore(s => s + matches.length * 10);
            }
          }

          // Falling logic
          const anchored = new Set<string>();
          const q: {r: number, c: number}[] = [];
          for (let c = 0; c < GRID_COLS; c++) { if (updatedGrid[0][c]) { anchored.add(`0,${c}`); q.push({ r: 0, c }); } }
          let qi = 0;
          while (qi < q.length) {
            const curr = q[qi++];
            const neighbors = getNeighbors(curr.r, curr.c, updatedGrid);
            for (const n of neighbors) {
              if (updatedGrid[n.r][n.c] && !anchored.has(`${n.r},${n.c}`)) {
                anchored.add(`${n.r},${n.c}`); q.push(n);
              }
            }
          }
          for (let r = 0; r < GRID_ROWS; r++) {
            const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
            for (let c = 0; c < cols; c++) {
              if (updatedGrid[r][c] && !anchored.has(`${r},${c}`)) {
                const b = updatedGrid[r][c]!;
                explode(b.x, b.y, palette[b.color]);
                updatedGrid[r][c] = null;
                setScore(s => s + 20);
              }
            }
          }

          setGrid(updatedGrid);
          setProjectile(null);
          if (shotsTaken > 0 && shotsTaken % SHOTS_TO_DROP === 0) dropGrid();
          if (!updatedGrid.some(row => row.some(b => b !== null))) onWin();
          if (bestR >= GRID_ROWS - 2) onGameOver(score);
        } else {
          setProjectile({ ...projectile, x: nextX, y: nextY });
        }
      }
      render();
      animationFrameId = requestAnimationFrame(update);
    };

    const drawBubble = (b: Bubble, radius: number = BUBBLE_RADIUS, alpha: number = 1.0) => {
      const { x, y, color, type } = b;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.beginPath();
      ctx.arc(x, y, radius - 1, 0, Math.PI * 2);

      if (type === 'bomb') {
        ctx.fillStyle = '#2d2d2d';
        ctx.shadowBlur = 15;
        ctx.shadowColor = '#ff6600';
      } else if (type === 'laser') {
        ctx.fillStyle = '#006666';
        ctx.shadowBlur = 15;
        ctx.shadowColor = '#00ffff';
      } else {
        ctx.fillStyle = palette[color];
        ctx.shadowBlur = 10;
        ctx.shadowColor = palette[color];
      }
      ctx.fill();

      // Power-up Icons
      if (type === 'bomb') {
        ctx.fillStyle = '#ff6600';
        ctx.beginPath();
        ctx.arc(x, y, radius / 2.5, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(x - 2, y - 8, 4, 10);
      } else if (type === 'laser') {
        ctx.strokeStyle = '#00ffff';
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.moveTo(x - radius/2, y);
        ctx.lineTo(x + radius/2, y);
        ctx.stroke();
      } else {
        ctx.beginPath();
        ctx.arc(x - radius/3, y - radius/3, radius/4, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255,255,255,0.4)';
        ctx.fill();
      }
      ctx.restore();
    };

    const render = () => {
      ctx.save();
      if (shake > 0) ctx.translate(Math.random() * shake - shake/2, Math.random() * shake - shake/2);
      ctx.clearRect(-10, -10, CANVAS_WIDTH + 20, CANVAS_HEIGHT + 20);

      grid.forEach(row => row.forEach(b => b && drawBubble(b)));

      const dx = mousePos.current.x - SHOOTER_X;
      const dy = mousePos.current.y - SHOOTER_Y;
      const angle = Math.atan2(dy, dx);
      ctx.beginPath();
      ctx.setLineDash([5, 5]);
      ctx.moveTo(SHOOTER_X, SHOOTER_Y);
      ctx.lineTo(SHOOTER_X + Math.cos(angle) * 100, SHOOTER_Y + Math.sin(angle) * 100);
      ctx.strokeStyle = 'rgba(255,255,255,0.2)';
      ctx.stroke();
      ctx.setLineDash([]);

      if (projectile) {
        drawBubble({ x: projectile.x, y: projectile.y, color: projectile.color, row: 0, col: 0, type: 'normal' });
      }

      particles.forEach(p => {
        if (p.type === 'beam') {
          ctx.save();
          ctx.beginPath();
          ctx.fillStyle = `rgba(0, 255, 255, ${p.life})`;
          ctx.fillRect(0, p.y - 10, CANVAS_WIDTH, 20);
          ctx.fillStyle = `rgba(255, 255, 255, ${p.life * 1.5})`;
          ctx.fillRect(0, p.y - 3, CANVAS_WIDTH, 6);
          ctx.restore();
        } else {
          ctx.save();
          ctx.globalAlpha = p.life;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
          ctx.fillStyle = p.color;
          ctx.fill();
          ctx.restore();
        }
      });

      const dropsIn = SHOTS_TO_DROP - (shotsTaken % SHOTS_TO_DROP);
      ctx.fillStyle = dropsIn <= 1 ? 'rgba(244, 63, 94, 0.8)' : 'rgba(255, 255, 255, 0.3)';
      ctx.font = 'bold 10px Inter';
      ctx.textAlign = 'left';
      ctx.fillText(`DROP IN: ${dropsIn}`, 20, CANVAS_HEIGHT - 20);

      drawBubble({ x: SHOOTER_X, y: SHOOTER_Y, color: activeColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS + 2);
      drawBubble({ x: SHOOTER_X + 60, y: SHOOTER_Y + 15, color: nextColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS * 0.7);

      ctx.fillStyle = 'rgba(255,255,255,0.5)';
      ctx.font = '10px Inter';
      ctx.textAlign = 'center';
      ctx.fillText('NEXT', SHOOTER_X + 60, SHOOTER_Y + 45);
      ctx.restore();
    };

    update();
    return () => cancelAnimationFrame(animationFrameId);
  }, [grid, projectile, activeColor, nextColor, particles, onGameOver, onScoreChange, onWin, score, palette, shotsTaken, dropGrid, triggerBomb, triggerLaser, shake]);

  const handlePointer = (e: React.PointerEvent) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    mousePos.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onPointerMove={handlePointer}
      onPointerDown={(e) => { handlePointer(e); handleShoot(); }}
      className="w-full h-full cursor-crosshair touch-none"
    />
  );
};

export default GameBoard;

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { Bubble, BubbleColor, Projectile, Particle, BubbleType } from '../types';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, BUBBLE_RADIUS, GRID_ROWS, GRID_COLS, 
  COLOR_PALETTES, BUBBLE_COLORS, SHOOTER_X, SHOOTER_Y, SHOTS_TO_DROP, POWER_UP_CHANCE
} from '../constants';

interface GameBoardProps {
  level: number;
  onScoreChange: (score: number) => void;
  onGameOver: (score: number) => void;
  onWin: () => void;
}

const GameBoard: React.FC<GameBoardProps> = ({ level, onScoreChange, onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [score, setScore] = useState(0);
  const [grid, setGrid] = useState<(Bubble | null)[][]>([]);
  const [projectile, setProjectile] = useState<Projectile | null>(null);
  const [nextColor, setNextColor] = useState<BubbleColor>(BUBBLE_COLORS[0]);
  const [activeColor, setActiveColor] = useState<BubbleColor>(BUBBLE_COLORS[1]);
  const [particles, setParticles] = useState<Particle[]>([]);
  const [shotsTaken, setShotsTaken] = useState(0);
  const [shake, setShake] = useState(0);

  const mousePos = useRef({ x: SHOOTER_X, y: 0 });
  const palette = COLOR_PALETTES[(level - 1) % COLOR_PALETTES.length];

  const generateBubble = (r: number, c: number): Bubble => {
    const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
    const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
    const isPowerUp = Math.random() < POWER_UP_CHANCE;
    const type: BubbleType = isPowerUp ? (Math.random() > 0.5 ? 'bomb' : 'laser') : 'normal';
    return { 
      x, y, 
      color: BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)],
      row: r,
      col: c,
      type
    };
  };

  useEffect(() => {
    const startRows = Math.min(GRID_ROWS - 2, 4 + Math.floor(level / 2));
    const newGrid: (Bubble | null)[][] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      newGrid[r] = [];
      const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < colsInRow; c++) {
        if (r < startRows) {
          newGrid[r][c] = generateBubble(r, c);
        } else {
          newGrid[r][c] = null;
        }
      }
    }
    setGrid(newGrid);
    setShotsTaken(0);
    setNextColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
    setActiveColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
  }, [level]);

  const getDistance = (x1: number, y1: number, x2: number, y2: number) => {
    return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);
  };

  const getNeighbors = (r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const neighbors: { r: number, c: number }[] = [];
    const evenRowOffsets = [
      { dr: -1, dc: -1 }, { dr: -1, dc: 0 },
      { dr: 0, dc: -1 }, { dr: 0, dc: 1 },
      { dr: 1, dc: -1 }, { dr: 1, dc: 0 }
    ];
    const oddRowOffsets = [
      { dr: -1, dc: 0 }, { dr: -1, dc: 1 },
      { dr: 0, dc: -1 }, { dr: 0, dc: 1 },
      { dr: 1, dc: 0 }, { dr: 1, dc: 1 }
    ];
    const offsets = r % 2 === 0 ? evenRowOffsets : oddRowOffsets;
    for (const off of offsets) {
      const nr = r + off.dr;
      const nc = c + off.dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
        neighbors.push({ r: nr, c: nc });
      }
    }
    return neighbors;
  };

  const explode = (x: number, y: number, color: string, count: number = 8) => {
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      newParticles.push({
        x, y,
        vx: (Math.random() - 0.5) * 10,
        vy: (Math.random() - 0.5) * 10,
        radius: Math.random() * 4 + 2,
        color,
        life: 1.0
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
  };

  const triggerLaser = useCallback((r: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
    let clearedCount = 0;

    // Visual Beam Effect
    setParticles(prev => [...prev, {
      x: CANVAS_WIDTH / 2,
      y: r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS,
      vx: 0, vy: 0, radius: 20, color: '#00ffff', life: 0.5, type: 'beam'
    }]);

    for (let c = 0; c < colsInRow; c++) {
      if (newGrid[r][c]) {
        const b = newGrid[r][c]!;
        explode(b.x, b.y, '#ffffff', 12);
        newGrid[r][c] = null;
        clearedCount++;
      }
    }
    const bonus = clearedCount * 20;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });
    return newGrid;
  }, [onScoreChange]);

  const triggerBomb = useCallback((r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const center = newGrid[r][c];
    if (!center) return newGrid;

    setShake(15);
    explode(center.x, center.y, '#ff4400', 40);

    let clearedCount = 0;
    const explosionRadius = BUBBLE_RADIUS * 6; // 3 bubble diameters (2 radii per diameter)

    for (let row = 0; row < GRID_ROWS; row++) {
      const cols = row % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let col = 0; col < cols; col++) {
        const b = newGrid[row][col];
        if (b) {
          const dist = getDistance(center.x, center.y, b.x, b.y);
          if (dist <= explosionRadius) {
            explode(b.x, b.y, palette[b.color] || '#ffffff', 8);
            newGrid[row][col] = null;
            clearedCount++;
          }
        }
      }
    }

    // Ensure the bomb itself is cleared
    newGrid[r][c] = null;

    const bonus = clearedCount * 15;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });

    return newGrid;
  }, [palette, onScoreChange]);

  const dropGrid = useCallback(() => {
    setGrid(oldGrid => {
      const newGrid: (Bubble | null)[][] = [];
      for (let r = 0; r < GRID_ROWS; r++) {
        newGrid[r] = [];
        const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
        if (r === 0) {
          for (let c = 0; c < colsInRow; c++) {
            newGrid[r][c] = generateBubble(r, c);
          }
        } else {
          const prevRow = oldGrid[r - 1];
          const prevCols = (r - 1) % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < colsInRow; c++) {
            const source = c < prevCols ? prevRow[c] : null;
            const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            if (source) {
              newGrid[r][c] = { ...source, x, y, row: r, col: c };
            } else {
              newGrid[r][c] = null;
            }
          }
        }
      }
      if (newGrid[GRID_ROWS - 2].some(b => b !== null)) onGameOver(score);
      return newGrid;
    });
  }, [score, onGameOver]);

  const handleShoot = useCallback(() => {
    if (projectile) return;
    const dx = mousePos.current.x - SHOOTER_X;
    const dy = mousePos.current.y - SHOOTER_Y;
    const angle = Math.atan2(dy, dx);
    const speed = 12 + (level * 0.5);
    setProjectile({
      x: SHOOTER_X, y: SHOOTER_Y, vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed, color: activeColor
    });
    setShotsTaken(prev => prev + 1);
    setActiveColor(nextColor);
    setNextColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
  }, [projectile, activeColor, nextColor, level]);

  useEffect(() => {
    let animationFrameId: number;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const update = () => {
      setParticles(prev => prev.map(p => ({
        ...p, x: p.x + p.vx, y: p.y + p.vy, life: p.life - 0.02
      })).filter(p => p.life > 0));

      if (shake > 0) setShake(s => Math.max(0, s - 0.5));

      if (projectile) {
        let nextX = projectile.x + projectile.vx;
        let nextY = projectile.y + projectile.vy;
        if (nextX - BUBBLE_RADIUS < 0 || nextX + BUBBLE_RADIUS > CANVAS_WIDTH) {
          projectile.vx *= -1;
          nextX = projectile.x + projectile.vx;
        }
        let collided = false;
        let bestR = -1;
        let bestC = -1;
        let hitBubble: Bubble | null = null;

        if (nextY - BUBBLE_RADIUS < 0) {
          collided = true;
          let minD = Infinity;
          for (let c = 0; c < GRID_COLS; c++) {
            const sx = c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS;
            const d = Math.abs(nextX - sx);
            if (d < minD) { minD = d; bestR = 0; bestC = c; }
          }
        } else {
          for (let r = 0; r < GRID_ROWS; r++) {
            const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
            for (let c = 0; c < cols; c++) {
              const b = grid[r][c];
              if (b && getDistance(nextX, nextY, b.x, b.y) < BUBBLE_RADIUS * 1.8) {
                collided = true;
                hitBubble = b;
                let minD = Infinity;
                const neighbors = getNeighbors(r, c, grid);
                for (const n of neighbors) {
                  if (!grid[n.r][n.c]) {
                    const nx = (n.r % 2 === 0 ? n.c * BUBBLE_RADIUS * 2 : n.c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
                    const ny = n.r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
                    const d = getDistance(nextX, nextY, nx, ny);
                    if (d < minD) { minD = d; bestR = n.r; bestC = n.c; }
                  }
                }
              }
            }
          }
        }

        if (collided) {
          let updatedGrid = [...grid.map(row => [...row])];

          // Power-up hit logic
          if (hitBubble?.type === 'bomb') {
            updatedGrid = triggerBomb(hitBubble.row, hitBubble.col, updatedGrid);
          } else if (hitBubble?.type === 'laser') {
            updatedGrid = triggerLaser(hitBubble.row, updatedGrid);
          } else if (bestR !== -1) {
            const px = (bestR % 2 === 0 ? bestC * BUBBLE_RADIUS * 2 : bestC * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const py = bestR * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            updatedGrid[bestR][bestC] = { x: px, y: py, color: projectile.color, row: bestR, col: bestC, type: 'normal' };

            const matches: {r: number, c: number}[] = [{ r: bestR, c: bestC }];
            const visited = new Set<string>(); visited.add(`${bestR},${bestC}`);
            let mi = 0;
            while (mi < matches.length) {
              const curr = matches[mi++];
              const neighbors = getNeighbors(curr.r, curr.c, updatedGrid);
              for (const n of neighbors) {
                const b = updatedGrid[n.r][n.c];
                if (b && b.color === projectile.color && b.type === 'normal' && !visited.has(`${n.r},${n.c}`)) {
                  visited.add(`${n.r},${n.c}`);
                  matches.push(n);
                }
              }
            }

            if (matches.length >= 3) {
              matches.forEach(m => {
                const b = updatedGrid[m.r][m.c];
                if (b) explode(b.x, b.y, palette[b.color]);
                updatedGrid[m.r][m.c] = null;
              });
              setScore(s => {
                const ns = s + matches.length * 10;
                onScoreChange(ns);
                return ns;
              });
            }
          }

          // Falling logic
          const anchored = new Set<string>();
          const q: {r: number, c: number}[] = [];
          for (let c = 0; c < GRID_COLS; c++) { if (updatedGrid[0][c]) { anchored.add(`0,${c}`); q.push({ r: 0, c }); } }
          let qi = 0;
          while (qi < q.length) {
            const curr = q[qi++];
            const neighbors = getNeighbors(curr.r, curr.c, updatedGrid);
            for (const n of neighbors) {
              if (updatedGrid[n.r][n.c] && !anchored.has(`${n.r},${n.c}`)) {
                anchored.add(`${n.r},${n.c}`); q.push(n);
              }
            }
          }
          for (let r = 0; r < GRID_ROWS; r++) {
            const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
            for (let c = 0; c < cols; c++) {
              if (updatedGrid[r][c] && !anchored.has(`${r},${c}`)) {
                const b = updatedGrid[r][c]!;
                explode(b.x, b.y, palette[b.color]);
                updatedGrid[r][c] = null;
                setScore(s => {
                  const ns = s + 20;
                  onScoreChange(ns);
                  return ns;
                });
              }
            }
          }

          setGrid(updatedGrid);
          setProjectile(null);
          if (shotsTaken > 0 && shotsTaken % SHOTS_TO_DROP === 0) dropGrid();
          if (!updatedGrid.some(row => row.some(b => b !== null))) onWin();
          if (bestR >= GRID_ROWS - 2) onGameOver(score);
        } else {
          setProjectile({ ...projectile, x: nextX, y: nextY });
        }
      }
      render();
      animationFrameId = requestAnimationFrame(update);
    };

    const drawBubble = (b: Bubble, radius: number = BUBBLE_RADIUS, alpha: number = 1.0) => {
      const { x, y, color, type } = b;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.beginPath();
      ctx.arc(x, y, radius - 1, 0, Math.PI * 2);

      if (type === 'bomb') {
        ctx.fillStyle = '#2d2d2d';
        ctx.shadowBlur = 15;
        ctx.shadowColor = '#ff6600';
      } else if (type === 'laser') {
        ctx.fillStyle = '#006666';
        ctx.shadowBlur = 15;
        ctx.shadowColor = '#00ffff';
      } else {
        ctx.fillStyle = palette[color];
        ctx.shadowBlur = 10;
        ctx.shadowColor = palette[color];
      }
      ctx.fill();

      // Power-up Icons
      if (type === 'bomb') {
        ctx.fillStyle = '#ff6600';
        ctx.beginPath();
        ctx.arc(x, y, radius / 2.5, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(x - 2, y - 8, 4, 10);
      } else if (type === 'laser') {
        ctx.strokeStyle = '#00ffff';
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.moveTo(x - radius/2, y);
        ctx.lineTo(x + radius/2, y);
        ctx.stroke();
      } else {
        ctx.beginPath();
        ctx.arc(x - radius/3, y - radius/3, radius/4, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255,255,255,0.4)';
        ctx.fill();
      }
      ctx.restore();
    };

    const render = () => {
      ctx.save();
      if (shake > 0) ctx.translate(Math.random() * shake - shake/2, Math.random() * shake - shake/2);
      ctx.clearRect(-10, -10, CANVAS_WIDTH + 20, CANVAS_HEIGHT + 20);

      grid.forEach(row => row.forEach(b => b && drawBubble(b)));

      const dx = mousePos.current.x - SHOOTER_X;
      const dy = mousePos.current.y - SHOOTER_Y;
      const angle = Math.atan2(dy, dx);
      ctx.beginPath();
      ctx.setLineDash([5, 5]);
      ctx.moveTo(SHOOTER_X, SHOOTER_Y);
      ctx.lineTo(SHOOTER_X + Math.cos(angle) * 100, SHOOTER_Y + Math.sin(angle) * 100);
      ctx.strokeStyle = 'rgba(255,255,255,0.2)';
      ctx.stroke();
      ctx.setLineDash([]);

      if (projectile) {
        drawBubble({ x: projectile.x, y: projectile.y, color: projectile.color, row: 0, col: 0, type: 'normal' });
      }

      particles.forEach(p => {
        if (p.type === 'beam') {
          ctx.save();
          ctx.beginPath();
          ctx.fillStyle = `rgba(0, 255, 255, ${p.life})`;
          ctx.fillRect(0, p.y - 10, CANVAS_WIDTH, 20);
          ctx.fillStyle = `rgba(255, 255, 255, ${p.life * 1.5})`;
          ctx.fillRect(0, p.y - 3, CANVAS_WIDTH, 6);
          ctx.restore();
        } else {
          ctx.save();
          ctx.globalAlpha = p.life;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
          ctx.fillStyle = p.color;
          ctx.fill();
          ctx.restore();
        }
      });

      const dropsIn = SHOTS_TO_DROP - (shotsTaken % SHOTS_TO_DROP);
      ctx.fillStyle = dropsIn <= 1 ? 'rgba(244, 63, 94, 0.8)' : 'rgba(255, 255, 255, 0.3)';
      ctx.font = 'bold 10px Inter';
      ctx.textAlign = 'left';
      ctx.fillText(`DROP IN: ${dropsIn}`, 20, CANVAS_HEIGHT - 20);

      drawBubble({ x: SHOOTER_X, y: SHOOTER_Y, color: activeColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS + 2);
      drawBubble({ x: SHOOTER_X + 60, y: SHOOTER_Y + 15, color: nextColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS * 0.7);

      ctx.fillStyle = 'rgba(255,255,255,0.5)';
      ctx.font = '10px Inter';
      ctx.textAlign = 'center';
      ctx.fillText('NEXT', SHOOTER_X + 60, SHOOTER_Y + 45);
      ctx.restore();
    };

    update();
    return () => cancelAnimationFrame(animationFrameId);
  }, [grid, projectile, activeColor, nextColor, particles, onGameOver, onScoreChange, onWin, score, palette, shotsTaken, dropGrid, triggerBomb, triggerLaser, shake]);

  const handlePointer = (e: React.PointerEvent) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    mousePos.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onPointerMove={handlePointer}
      onPointerDown={(e) => { handlePointer(e); handleShoot(); }}
      className="w-full h-full cursor-crosshair touch-none"
    />
  );
};

export default GameBoard;

class AudioService {
  private ctx: AudioContext | null = null;
  private muted: boolean = false;

  private init() {
    if (!this.ctx) {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (this.ctx.state === 'suspended') {
      this.ctx.resume();
    }
  }

  public setMuted(muted: boolean) {
    this.muted = muted;
  }

  public playPop(frequency: number = 600) {
    if (this.muted) return;
    this.init();
    const osc = this.ctx!.createOscillator();
    const gain = this.ctx!.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(frequency, this.ctx!.currentTime);
    osc.frequency.exponentialRampToValueAtTime(frequency * 2, this.ctx!.currentTime + 0.1);

    gain.gain.setValueAtTime(0.3, this.ctx!.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx!.currentTime + 0.1);

    osc.connect(gain);
    gain.connect(this.ctx!.destination);

    osc.start();
    osc.stop(this.ctx!.currentTime + 0.1);
  }

  public playShoot() {
    if (this.muted) return;
    this.init();
    const osc = this.ctx!.createOscillator();
    const gain = this.ctx!.createGain();

    osc.type = 'triangle';
    osc.frequency.setValueAtTime(150, this.ctx!.currentTime);
    osc.frequency.exponentialRampToValueAtTime(400, this.ctx!.currentTime + 0.05);

    gain.gain.setValueAtTime(0.1, this.ctx!.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx!.currentTime + 0.05);

    osc.connect(gain);
    gain.connect(this.ctx!.destination);

    osc.start();
    osc.stop(this.ctx!.currentTime + 0.05);
  }

  public playBomb() {
    if (this.muted) return;
    this.init();
    const osc = this.ctx!.createOscillator();
    const gain = this.ctx!.createGain();

    osc.type = 'square';
    osc.frequency.setValueAtTime(100, this.ctx!.currentTime);
    osc.frequency.exponentialRampToValueAtTime(20, this.ctx!.currentTime + 0.5);

    gain.gain.setValueAtTime(0.4, this.ctx!.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, this.ctx!.currentTime + 0.6);

    osc.connect(gain);
    gain.connect(this.ctx!.destination);

    osc.start();
    osc.stop(this.ctx!.currentTime + 0.6);
  }

  public playLaser() {
    if (this.muted) return;
    this.init();
    const osc = this.ctx!.createOscillator();
    const gain = this.ctx!.createGain();

    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(2000, this.ctx!.currentTime);
    osc.frequency.exponentialRampToValueAtTime(400, this.ctx!.currentTime + 0.3);

    gain.gain.setValueAtTime(0.1, this.ctx!.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx!.currentTime + 0.3);

    osc.connect(gain);
    gain.connect(this.ctx!.destination);

    osc.start();
    osc.stop(this.ctx!.currentTime + 0.3);
  }

  public playWin() {
    if (this.muted) return;
    this.init();
    const notes = [523.25, 659.25, 783.99, 1046.50];
    notes.forEach((freq, i) => {
      const osc = this.ctx!.createOscillator();
      const gain = this.ctx!.createGain();
      osc.frequency.value = freq;
      gain.gain.setValueAtTime(0.1, this.ctx!.currentTime + i * 0.1);
      gain.gain.exponentialRampToValueAtTime(0.01, this.ctx!.currentTime + i * 0.1 + 0.2);
      osc.connect(gain);
      gain.connect(this.ctx!.destination);
      osc.start(this.ctx!.currentTime + i * 0.1);
      osc.stop(this.ctx!.currentTime + i * 0.1 + 0.2);
    });
  }

  public playGameOver() {
    if (this.muted) return;
    this.init();
    const notes = [440, 349, 261, 196];
    notes.forEach((freq, i) => {
      const osc = this.ctx!.createOscillator();
      const gain = this.ctx!.createGain();
      osc.frequency.value = freq;
      gain.gain.setValueAtTime(0.1, this.ctx!.currentTime + i * 0.2);
      gain.gain.exponentialRampToValueAtTime(0.01, this.ctx!.currentTime + i * 0.2 + 0.4);
      osc.connect(gain);
      gain.connect(this.ctx!.destination);
      osc.start(this.ctx!.currentTime + i * 0.2);
      osc.stop(this.ctx!.currentTime + i * 0.2 + 0.4);
    });
  }
}

