import React, { useRef, useEffect, useState, useCallback } from 'react';
import { Bubble, BubbleColor, Projectile, Particle, BubbleType } from '../types';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, BUBBLE_RADIUS, GRID_ROWS, GRID_COLS, 
  COLOR_PALETTES, BUBBLE_COLORS, SHOOTER_X, SHOOTER_Y, SHOTS_TO_DROP, POWER_UP_CHANCE
} from '../constants';
import { audio } from '../services/audioService';

interface GameBoardProps {
  level: number;
  onScoreChange: (score: number) => void;
  onGameOver: (score: number) => void;
  onWin: () => void;
}

const GameBoard: React.FC<GameBoardProps> = ({ level, onScoreChange, onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [score, setScore] = useState(0);
  const [grid, setGrid] = useState<(Bubble | null)[][]>([]);
  const [projectile, setProjectile] = useState<Projectile | null>(null);
  const [nextColor, setNextColor] = useState<BubbleColor>(BUBBLE_COLORS[0]);
  const [activeColor, setActiveColor] = useState<BubbleColor>(BUBBLE_COLORS[1]);
  const [particles, setParticles] = useState<Particle[]>([]);
  const [shotsTaken, setShotsTaken] = useState(0);
  const [shake, setShake] = useState(0);

  const mousePos = useRef({ x: SHOOTER_X, y: 0 });
  const palette = COLOR_PALETTES[(level - 1) % COLOR_PALETTES.length];

  const generateBubble = (r: number, c: number): Bubble => {
    const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
    const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
    const isPowerUp = Math.random() < POWER_UP_CHANCE;
    const type: BubbleType = isPowerUp ? (Math.random() > 0.5 ? 'bomb' : 'laser') : 'normal';
    return { 
      x, y, 
      color: BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)],
      row: r,
      col: c,
      type
    };
  };

  useEffect(() => {
    const startRows = Math.min(GRID_ROWS - 2, 4 + Math.floor(level / 2));
    const newGrid: (Bubble | null)[][] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      newGrid[r] = [];
      const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < colsInRow; c++) {
        if (r < startRows) {
          newGrid[r][c] = generateBubble(r, c);
        } else {
          newGrid[r][c] = null;
        }
      }
    }
    setGrid(newGrid);
    setShotsTaken(0);
    setNextColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
    setActiveColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
  }, [level]);

  const getDistance = (x1: number, y1: number, x2: number, y2: number) => {
    return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);
  };

  const getNeighbors = (r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const neighbors: { r: number, c: number }[] = [];
    const evenRowOffsets = [
      { dr: -1, dc: -1 }, { dr: -1, dc: 0 },
      { dr: 0, dc: -1 }, { dr: 0, dc: 1 },
      { dr: 1, dc: -1 }, { dr: 1, dc: 0 }
    ];
    const oddRowOffsets = [
      { dr: -1, dc: 0 }, { dr: -1, dc: 1 },
      { dr: 0, dc: -1 }, { dr: 0, dc: 1 },
      { dr: 1, dc: 0 }, { dr: 1, dc: 1 }
    ];
    const offsets = r % 2 === 0 ? evenRowOffsets : oddRowOffsets;
    for (const off of offsets) {
      const nr = r + off.dr;
      const nc = c + off.dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
        neighbors.push({ r: nr, c: nc });
      }
    }
    return neighbors;
  };

  const explode = (x: number, y: number, color: string, count: number = 8) => {
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      newParticles.push({
        x, y,
        vx: (Math.random() - 0.5) * 10,
        vy: (Math.random() - 0.5) * 10,
        radius: Math.random() * 4 + 2,
        color,
        life: 1.0
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
  };

  const triggerLaser = useCallback((r: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
    let clearedCount = 0;

    audio.playLaser();

    // Visual Beam Effect
    setParticles(prev => [...prev, {
      x: CANVAS_WIDTH / 2,
      y: r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS,
      vx: 0, vy: 0, radius: 20, color: '#00ffff', life: 0.5, type: 'beam'
    }]);

    for (let c = 0; c < colsInRow; c++) {
      if (newGrid[r][c]) {
        const b = newGrid[r][c]!;
        explode(b.x, b.y, '#ffffff', 12);
        newGrid[r][c] = null;
        clearedCount++;
      }
    }
    const bonus = clearedCount * 20;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });
    return newGrid;
  }, [onScoreChange]);

  const triggerBomb = useCallback((r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const center = newGrid[r][c];
    if (!center) return newGrid;

    audio.playBomb();
    setShake(15);
    explode(center.x, center.y, '#ff4400', 40);

    let clearedCount = 0;
    const explosionRadius = BUBBLE_RADIUS * 6; // 3 bubble diameters (2 radii per diameter)

    for (let row = 0; row < GRID_ROWS; row++) {
      const cols = row % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let col = 0; col < cols; col++) {
        const b = newGrid[row][col];
        if (b) {
          const dist = getDistance(center.x, center.y, b.x, b.y);
          if (dist <= explosionRadius) {
            explode(b.x, b.y, palette[b.color] || '#ffffff', 8);
            newGrid[row][col] = null;
            clearedCount++;
          }
        }
      }
    }

    // Ensure the bomb itself is cleared
    newGrid[r][c] = null;

    const bonus = clearedCount * 15;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });

    return newGrid;
  }, [palette, onScoreChange]);

  const dropGrid = useCallback(() => {
    setGrid(oldGrid => {
      const newGrid: (Bubble | null)[][] = [];
      for (let r = 0; r < GRID_ROWS; r++) {
        newGrid[r] = [];
        const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
        if (r === 0) {
          for (let c = 0; c < colsInRow; c++) {
            newGrid[r][c] = generateBubble(r, c);
          }
        } else {
          const prevRow = oldGrid[r - 1];
          const prevCols = (r - 1) % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < colsInRow; c++) {
            const source = c < prevCols ? prevRow[c] : null;
            const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            if (source) {
              newGrid[r][c] = { ...source, x, y, row: r, col: c };
            } else {
              newGrid[r][c] = null;
            }
          }
        }
      }
      if (newGrid[GRID_ROWS - 2].some(b => b !== null)) onGameOver(score);
      return newGrid;
    });
  }, [score, onGameOver]);

  const handleShoot = useCallback(() => {
    if (projectile) return;
    const dx = mousePos.current.x - SHOOTER_X;
    const dy = mousePos.current.y - SHOOTER_Y;
    const angle = Math.atan2(dy, dx);
    const speed = 12 + (level * 0.5);
    setProjectile({
      x: SHOOTER_X, y: SHOOTER_Y, vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed, color: activeColor
    });
    audio.playShoot();
    setShotsTaken(prev => prev + 1);
    setActiveColor(nextColor);
    setNextColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
  }, [projectile, activeColor, nextColor, level]);

  useEffect(() => {
    let animationFrameId: number;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const update = () => {
      setParticles(prev => prev.map(p => ({
        ...p, x: p.x + p.vx, y: p.y + p.vy, life: p.life - 0.02
      })).filter(p => p.life > 0));

      if (shake > 0) setShake(s => Math.max(0, s - 0.5));

      if (projectile) {
        let nextX = projectile.x + projectile.vx;
        let nextY = projectile.y + projectile.vy;
        if (nextX - BUBBLE_RADIUS < 0 || nextX + BUBBLE_RADIUS > CANVAS_WIDTH) {
          projectile.vx *= -1;
          nextX = projectile.x + projectile.vx;
        }
        let collided = false;
        let bestR = -1;
        let bestC = -1;
        let hitBubble: Bubble | null = null;

        if (nextY - BUBBLE_RADIUS < 0) {
          collided = true;
          let minD = Infinity;
          for (let c = 0; c < GRID_COLS; c++) {
            const sx = c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS;
            const d = Math.abs(nextX - sx);
            if (d < minD) { minD = d; bestR = 0; bestC = c; }
          }
        } else {
          for (let r = 0; r < GRID_ROWS; r++) {
            const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
            for (let c = 0; c < cols; c++) {
              const b = grid[r][c];
              if (b && getDistance(nextX, nextY, b.x, b.y) < BUBBLE_RADIUS * 1.8) {
                collided = true;
                hitBubble = b;
                let minD = Infinity;
                const neighbors = getNeighbors(r, c, grid);
                for (const n of neighbors) {
                  if (!grid[n.r][n.c]) {
                    const nx = (n.r % 2 === 0 ? n.c * BUBBLE_RADIUS * 2 : n.c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
                    const ny = n.r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
                    const d = getDistance(nextX, nextY, nx, ny);
                    if (d < minD) { minD = d; bestR = n.r; bestC = n.c; }
                  }
                }
              }
            }
          }
        }

        if (collided) {
          let updatedGrid = [...grid.map(row => [...row])];

          // Power-up hit logic
          if (hitBubble?.type === 'bomb') {
            updatedGrid = triggerBomb(hitBubble.row, hitBubble.col, updatedGrid);
          } else if (hitBubble?.type === 'laser') {
            updatedGrid = triggerLaser(hitBubble.row, updatedGrid);
          } else if (bestR !== -1) {
            const px = (bestR % 2 === 0 ? bestC * BUBBLE_RADIUS * 2 : bestC * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const py = bestR * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            updatedGrid[bestR][bestC] = { x: px, y: py, color: projectile.color, row: bestR, col: bestC, type: 'normal' };

            const matches: {r: number, c: number}[] = [{ r: bestR, c: bestC }];
            const visited = new Set<string>(); visited.add(`${bestR},${bestC}`);
            let mi = 0;
            while (mi < matches.length) {
              const curr = matches[mi++];
              const neighbors = getNeighbors(curr.r, curr.c, updatedGrid);
              for (const n of neighbors) {
                const b = updatedGrid[n.r][n.c];
                if (b && b.color === projectile.color && b.type === 'normal' && !visited.has(`${n.r},${n.c}`)) {
                  visited.add(`${n.r},${n.c}`);
                  matches.push(n);
                }
              }
            }

            if (matches.length >= 3) {
              audio.playPop(400 + matches.length * 20);
              matches.forEach(m => {
                const b = updatedGrid[m.r][m.c];
                if (b) explode(b.x, b.y, palette[b.color]);
                updatedGrid[m.r][m.c] = null;
              });
              setScore(s => {
                const ns = s + matches.length * 10;
                onScoreChange(ns);
                return ns;
              });
            } else {
              audio.playShoot(); // Small tap sound for non-matching collision
            }
          }

          // Falling logic
          const anchored = new Set<string>();
          const q: {r: number, c: number}[] = [];
          for (let c = 0; c < GRID_COLS; c++) { if (updatedGrid[0][c]) { anchored.add(`0,${c}`); q.push({ r: 0, c }); } }
          let qi = 0;
          while (qi < q.length) {
            const curr = q[qi++];
            const neighbors = getNeighbors(curr.r, curr.c, updatedGrid);
            for (const n of neighbors) {
              if (updatedGrid[n.r][n.c] && !anchored.has(`${n.r},${n.c}`)) {
                anchored.add(`${n.r},${n.c}`); q.push(n);
              }
            }
          }
          let fallingCount = 0;
          for (let r = 0; r < GRID_ROWS; r++) {
            const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
            for (let c = 0; c < cols; c++) {
              if (updatedGrid[r][c] && !anchored.has(`${r},${c}`)) {
                const b = updatedGrid[r][c]!;
                explode(b.x, b.y, palette[b.color]);
                updatedGrid[r][c] = null;
                fallingCount++;
                setScore(s => {
                  const ns = s + 20;
                  onScoreChange(ns);
                  return ns;
                });
              }
            }
          }
          if (fallingCount > 0) {
            audio.playPop(300);
          }

          setGrid(updatedGrid);
          setProjectile(null);
          if (shotsTaken > 0 && shotsTaken % SHOTS_TO_DROP === 0) {
            dropGrid();
            audio.playPop(200); // Low sound for grid drop
          }
          if (!updatedGrid.some(row => row.some(b => b !== null))) onWin();
          if (bestR >= GRID_ROWS - 2) onGameOver(score);
        } else {
          setProjectile({ ...projectile, x: nextX, y: nextY });
        }
      }
      render();
      animationFrameId = requestAnimationFrame(update);
    };

    const drawBubble = (b: Bubble, radius: number = BUBBLE_RADIUS, alpha: number = 1.0) => {
      const { x, y, color, type } = b;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.beginPath();
      ctx.arc(x, y, radius - 1, 0, Math.PI * 2);

      if (type === 'bomb') {
        ctx.fillStyle = '#2d2d2d';
        ctx.shadowBlur = 15;
        ctx.shadowColor = '#ff6600';
      } else if (type === 'laser') {
        ctx.fillStyle = '#006666';
        ctx.shadowBlur = 15;
        ctx.shadowColor = '#00ffff';
      } else {
        ctx.fillStyle = palette[color];
        ctx.shadowBlur = 10;
        ctx.shadowColor = palette[color];
      }
      ctx.fill();

      // Power-up Icons
      if (type === 'bomb') {
        ctx.fillStyle = '#ff6600';
        ctx.beginPath();
        ctx.arc(x, y, radius / 2.5, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(x - 2, y - 8, 4, 10);
      } else if (type === 'laser') {
        ctx.strokeStyle = '#00ffff';
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.moveTo(x - radius/2, y);
        ctx.lineTo(x + radius/2, y);
        ctx.stroke();
      } else {
        ctx.beginPath();
        ctx.arc(x - radius/3, y - radius/3, radius/4, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255,255,255,0.4)';
        ctx.fill();
      }
      ctx.restore();
    };

    const render = () => {
      ctx.save();
      if (shake > 0) ctx.translate(Math.random() * shake - shake/2, Math.random() * shake - shake/2);
      ctx.clearRect(-10, -10, CANVAS_WIDTH + 20, CANVAS_HEIGHT + 20);

      grid.forEach(row => row.forEach(b => b && drawBubble(b)));

      const dx = mousePos.current.x - SHOOTER_X;
      const dy = mousePos.current.y - SHOOTER_Y;
      const angle = Math.atan2(dy, dx);
      ctx.beginPath();
      ctx.setLineDash([5, 5]);
      ctx.moveTo(SHOOTER_X, SHOOTER_Y);
      ctx.lineTo(SHOOTER_X + Math.cos(angle) * 100, SHOOTER_Y + Math.sin(angle) * 100);
      ctx.strokeStyle = 'rgba(255,255,255,0.2)';
      ctx.stroke();
      ctx.setLineDash([]);

      if (projectile) {
        drawBubble({ x: projectile.x, y: projectile.y, color: projectile.color, row: 0, col: 0, type: 'normal' });
      }

      particles.forEach(p => {
        if (p.type === 'beam') {
          ctx.save();
          ctx.beginPath();
          ctx.fillStyle = `rgba(0, 255, 255, ${p.life})`;
          ctx.fillRect(0, p.y - 10, CANVAS_WIDTH, 20);
          ctx.fillStyle = `rgba(255, 255, 255, ${p.life * 1.5})`;
          ctx.fillRect(0, p.y - 3, CANVAS_WIDTH, 6);
          ctx.restore();
        } else {
          ctx.save();
          ctx.globalAlpha = p.life;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
          ctx.fillStyle = p.color;
          ctx.fill();
          ctx.restore();
        }
      });

      const dropsIn = SHOTS_TO_DROP - (shotsTaken % SHOTS_TO_DROP);
      ctx.fillStyle = dropsIn <= 1 ? 'rgba(244, 63, 94, 0.8)' : 'rgba(255, 255, 255, 0.3)';
      ctx.font = 'bold 10px Inter';
      ctx.textAlign = 'left';
      ctx.fillText(`DROP IN: ${dropsIn}`, 20, CANVAS_HEIGHT - 20);

      drawBubble({ x: SHOOTER_X, y: SHOOTER_Y, color: activeColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS + 2);
      drawBubble({ x: SHOOTER_X + 60, y: SHOOTER_Y + 15, color: nextColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS * 0.7);

      ctx.fillStyle = 'rgba(255,255,255,0.5)';
      ctx.font = '10px Inter';
      ctx.textAlign = 'center';
      ctx.fillText('NEXT', SHOOTER_X + 60, SHOOTER_Y + 45);
      ctx.restore();
    };

    update();
    return () => cancelAnimationFrame(animationFrameId);
  }, [grid, projectile, activeColor, nextColor, particles, onGameOver, onScoreChange, onWin, score, palette, shotsTaken, dropGrid, triggerBomb, triggerLaser, shake, level]);

  const handlePointer = (e: React.PointerEvent) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    mousePos.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onPointerMove={handlePointer}
      onPointerDown={(e) => { handlePointer(e); handleShoot(); }}
      className="w-full h-full cursor-crosshair touch-none"
    />
  );
};

export default GameBoard;

import { BubbleColor } from './types';

export const CANVAS_WIDTH = 400;
export const CANVAS_HEIGHT = 600;

export const BUBBLE_RADIUS = 20;
export const GRID_ROWS = 14; 
export const GRID_COLS = 8;

export const BUBBLE_COLORS: BubbleColor[] = ['rose', 'amber', 'lime', 'sky', 'violet', 'fuchsia'];

export const COLOR_PALETTES: Record<BubbleColor, string>[] = [
  { // Standard Neon
    rose: '#f43f5e',
    amber: '#f59e0b',
    lime: '#84cc16',
    sky: '#0ea5e9',
    violet: '#8b5cf6',
    fuchsia: '#d946ef'
  },
  { // Cyberpunk Night
    rose: '#ff0055',
    amber: '#ffcc00',
    lime: '#00ff66',
    sky: '#00ffff',
    violet: '#9900ff',
    fuchsia: '#ff00ff'
  },
  { // Retro Sunset
    rose: '#ef4444',
    amber: '#f97316',
    lime: '#fbbf24',
    sky: '#38bdf8',
    violet: '#818cf8',
    fuchsia: '#c084fc'
  },
  { // Arctic Pulse
    rose: '#fb7185',
    amber: '#fbbf24',
    lime: '#4ade80',
    sky: '#22d3ee',
    violet: '#a78bfa',
    fuchsia: '#f472b6'
  }
];

export const POWER_UP_CHANCE = 0.08; // 8% chance for a bubble to be a power-up
export const SHOOTER_Y = CANVAS_HEIGHT - 60;
export const SHOOTER_X = CANVAS_WIDTH / 2;
export const SHOTS_TO_DROP = 5; // Slightly faster grid drops for higher tension
export const PROJECTILE_BASE_SPEED = 18; // Increased from 12 for high-octane feel
export const COLLISION_THRESHOLD = 1.9; // Refined distance multiplier for snappier hits

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { Bubble, BubbleColor, Projectile, Particle, BubbleType } from '../types';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, BUBBLE_RADIUS, GRID_ROWS, GRID_COLS, 
  COLOR_PALETTES, BUBBLE_COLORS, SHOOTER_X, SHOOTER_Y, SHOTS_TO_DROP, 
  POWER_UP_CHANCE, PROJECTILE_BASE_SPEED, COLLISION_THRESHOLD
} from '../constants';
import { audio } from '../services/audioService';

interface GameBoardProps {
  level: number;
  onScoreChange: (score: number) => void;
  onGameOver: (score: number) => void;
  onWin: () => void;
}

const GameBoard: React.FC<GameBoardProps> = ({ level, onScoreChange, onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [score, setScore] = useState(0);
  const [grid, setGrid] = useState<(Bubble | null)[][]>([]);
  const [projectile, setProjectile] = useState<Projectile | null>(null);
  const [nextColor, setNextColor] = useState<BubbleColor>(BUBBLE_COLORS[0]);
  const [activeColor, setActiveColor] = useState<BubbleColor>(BUBBLE_COLORS[1]);
  const [particles, setParticles] = useState<Particle[]>([]);
  const [shotsTaken, setShotsTaken] = useState(0);
  const [shake, setShake] = useState(0);

  const mousePos = useRef({ x: SHOOTER_X, y: 0 });
  const palette = COLOR_PALETTES[(level - 1) % COLOR_PALETTES.length];

  const generateBubble = (r: number, c: number): Bubble => {
    const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
    const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
    const isPowerUp = Math.random() < POWER_UP_CHANCE;
    const type: BubbleType = isPowerUp ? (Math.random() > 0.5 ? 'bomb' : 'laser') : 'normal';
    return { 
      x, y, 
      color: BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)],
      row: r,
      col: c,
      type
    };
  };

  useEffect(() => {
    const startRows = Math.min(GRID_ROWS - 2, 4 + Math.floor(level / 2));
    const newGrid: (Bubble | null)[][] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      newGrid[r] = [];
      const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < colsInRow; c++) {
        if (r < startRows) {
          newGrid[r][c] = generateBubble(r, c);
        } else {
          newGrid[r][c] = null;
        }
      }
    }
    setGrid(newGrid);
    setShotsTaken(0);
    setNextColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
    setActiveColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
  }, [level]);

  const getDistance = (x1: number, y1: number, x2: number, y2: number) => {
    return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);
  };

  const getNeighbors = (r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const neighbors: { r: number, c: number }[] = [];
    const evenRowOffsets = [
      { dr: -1, dc: -1 }, { dr: -1, dc: 0 },
      { dr: 0, dc: -1 }, { dr: 0, dc: 1 },
      { dr: 1, dc: -1 }, { dr: 1, dc: 0 }
    ];
    const oddRowOffsets = [
      { dr: -1, dc: 0 }, { dr: -1, dc: 1 },
      { dr: 0, dc: -1 }, { dr: 0, dc: 1 },
      { dr: 1, dc: 0 }, { dr: 1, dc: 1 }
    ];
    const offsets = r % 2 === 0 ? evenRowOffsets : oddRowOffsets;
    for (const off of offsets) {
      const nr = r + off.dr;
      const nc = c + off.dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
        neighbors.push({ r: nr, c: nc });
      }
    }
    return neighbors;
  };

  const explode = (x: number, y: number, color: string, count: number = 8, velocityMult: number = 1.0) => {
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      newParticles.push({
        x, y,
        vx: (Math.random() - 0.5) * 14 * velocityMult, // Faster particles
        vy: (Math.random() - 0.5) * 14 * velocityMult,
        radius: Math.random() * 4 + 1.5,
        color,
        life: 1.0
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
  };

  const triggerLaser = useCallback((r: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
    let clearedCount = 0;

    audio.playLaser();
    setShake(8);

    // Visual Beam Effect
    setParticles(prev => [...prev, {
      x: CANVAS_WIDTH / 2,
      y: r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS,
      vx: 0, vy: 0, radius: 24, color: '#00ffff', life: 0.6, type: 'beam'
    }]);

    for (let c = 0; c < colsInRow; c++) {
      if (newGrid[r][c]) {
        const b = newGrid[r][c]!;
        explode(b.x, b.y, '#ffffff', 14, 1.2);
        newGrid[r][c] = null;
        clearedCount++;
      }
    }
    const bonus = clearedCount * 25;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });
    return newGrid;
  }, [onScoreChange]);

  const triggerBomb = useCallback((r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const center = newGrid[r][c];
    if (!center) return newGrid;

    audio.playBomb();
    setShake(25);
    explode(center.x, center.y, '#ff4400', 50, 1.5);

    let clearedCount = 0;
    const explosionRadius = BUBBLE_RADIUS * 6.2; // Slightly larger for power-feel

    for (let row = 0; row < GRID_ROWS; row++) {
      const cols = row % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let col = 0; col < cols; col++) {
        const b = newGrid[row][col];
        if (b) {
          const dist = getDistance(center.x, center.y, b.x, b.y);
          if (dist <= explosionRadius) {
            explode(b.x, b.y, palette[b.color] || '#ffffff', 10, 1.1);
            newGrid[row][col] = null;
            clearedCount++;
          }
        }
      }
    }

    newGrid[r][c] = null;
    const bonus = clearedCount * 20;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });

    return newGrid;
  }, [palette, onScoreChange]);

  const dropGrid = useCallback(() => {
    setGrid(oldGrid => {
      const newGrid: (Bubble | null)[][] = [];
      for (let r = 0; r < GRID_ROWS; r++) {
        newGrid[r] = [];
        const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
        if (r === 0) {
          for (let c = 0; c < colsInRow; c++) {
            newGrid[r][c] = generateBubble(r, c);
          }
        } else {
          const prevRow = oldGrid[r - 1];
          const prevCols = (r - 1) % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < colsInRow; c++) {
            const source = c < prevCols ? prevRow[c] : null;
            const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            if (source) {
              newGrid[r][c] = { ...source, x, y, row: r, col: c };
            } else {
              newGrid[r][c] = null;
            }
          }
        }
      }
      if (newGrid[GRID_ROWS - 2].some(b => b !== null)) onGameOver(score);
      return newGrid;
    });
  }, [score, onGameOver]);

  const handleShoot = useCallback(() => {
    if (projectile) return;
    const dx = mousePos.current.x - SHOOTER_X;
    const dy = mousePos.current.y - SHOOTER_Y;
    const angle = Math.atan2(dy, dx);
    const speed = PROJECTILE_BASE_SPEED + (level * 0.4);

    // Muzzle flash effect
    explode(SHOOTER_X, SHOOTER_Y, palette[activeColor], 15, 0.8);
    setShake(3);

    setProjectile({
      x: SHOOTER_X, y: SHOOTER_Y, vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed, color: activeColor
    });
    audio.playShoot();
    setShotsTaken(prev => prev + 1);
    setActiveColor(nextColor);
    setNextColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
  }, [projectile, activeColor, nextColor, level, palette]);

  useEffect(() => {
    let animationFrameId: number;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const update = () => {
      // Particle cleanup and physics
      setParticles(prev => prev.map(p => ({
        ...p, 
        x: p.x + p.vx, 
        y: p.y + p.vy, 
        life: p.life - (p.type === 'beam' ? 0.04 : 0.035) // Faster fade for high octane
      })).filter(p => p.life > 0));

      if (shake > 0) setShake(s => Math.max(0, s - 0.6));

      if (projectile) {
        let nextX = projectile.x + projectile.vx;
        let nextY = projectile.y + projectile.vy;

        // Sub-step physics for high speed precision
        const steps = 2; 
        let collided = false;
        let bestR = -1;
        let bestC = -1;
        let hitBubble: Bubble | null = null;

        for (let s = 0; s < steps && !collided; s++) {
          const stepX = projectile.x + (projectile.vx / steps) * (s + 1);
          const stepY = projectile.y + (projectile.vy / steps) * (s + 1);

          if (stepX - BUBBLE_RADIUS < 0 || stepX + BUBBLE_RADIUS > CANVAS_WIDTH) {
            projectile.vx *= -1;
          }

          if (stepY - BUBBLE_RADIUS < 0) {
            collided = true;
            let minD = Infinity;
            for (let c = 0; c < GRID_COLS; c++) {
              const sx = c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS;
              const d = Math.abs(stepX - sx);
              if (d < minD) { minD = d; bestR = 0; bestC = c; }
            }
          } else {
            // Collision detection with existing bubbles
            for (let r = 0; r < GRID_ROWS; r++) {
              const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
              for (let c = 0; c < cols; c++) {
                const b = grid[r][c];
                if (b && getDistance(stepX, stepY, b.x, b.y) < BUBBLE_RADIUS * COLLISION_THRESHOLD) {
                  collided = true;
                  hitBubble = b;

                  // Find the best empty slot nearby
                  let minD = Infinity;
                  const neighbors = getNeighbors(r, c, grid);
                  for (const n of neighbors) {
                    if (!grid[n.r][n.c]) {
                      const nx = (n.r % 2 === 0 ? n.c * BUBBLE_RADIUS * 2 : n.c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
                      const ny = n.r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
                      const d = getDistance(stepX, stepY, nx, ny);
                      if (d < minD) { minD = d; bestR = n.r; bestC = n.c; }
                    }
                  }
                }
              }
            }
          }

          if (!collided) {
            projectile.x = stepX;
            projectile.y = stepY;
          }
        }

        if (collided) {
          let updatedGrid = [...grid.map(row => [...row])];

          if (hitBubble?.type === 'bomb') {
            updatedGrid = triggerBomb(hitBubble.row, hitBubble.col, updatedGrid);
          } else if (hitBubble?.type === 'laser') {
            updatedGrid = triggerLaser(hitBubble.row, updatedGrid);
          } else if (bestR !== -1) {
            const px = (bestR % 2 === 0 ? bestC * BUBBLE_RADIUS * 2 : bestC * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const py = bestR * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            updatedGrid[bestR][bestC] = { x: px, y: py, color: projectile.color, row: bestR, col: bestC, type: 'normal' };

            const matches: {r: number, c: number}[] = [{ r: bestR, c: bestC }];
            const visited = new Set<string>(); visited.add(`${bestR},${bestC}`);
            let mi = 0;
            while (mi < matches.length) {
              const curr = matches[mi++];
              const neighbors = getNeighbors(curr.r, curr.c, updatedGrid);
              for (const n of neighbors) {
                const b = updatedGrid[n.r][n.c];
                if (b && b.color === projectile.color && b.type === 'normal' && !visited.has(`${n.r},${n.c}`)) {
                  visited.add(`${n.r},${n.c}`);
                  matches.push(n);
                }
              }
            }

            if (matches.length >= 3) {
              audio.playPop(420 + matches.length * 25);
              setShake(2 + matches.length * 0.5);
              matches.forEach(m => {
                const b = updatedGrid[m.r][m.c];
                if (b) explode(b.x, b.y, palette[b.color], 10, 1.2);
                updatedGrid[m.r][m.c] = null;
              });
              setScore(s => {
                const ns = s + matches.length * 15;
                onScoreChange(ns);
                return ns;
              });
            } else {
              audio.playShoot();
            }
          }

          // Anchor check for falling bubbles
          const anchored = new Set<string>();
          const q: {r: number, c: number}[] = [];
          for (let c = 0; c < GRID_COLS; c++) { if (updatedGrid[0][c]) { anchored.add(`0,${c}`); q.push({ r: 0, c }); } }
          let qi = 0;
          while (qi < q.length) {
            const curr = q[qi++];
            const neighbors = getNeighbors(curr.r, curr.c, updatedGrid);
            for (const n of neighbors) {
              if (updatedGrid[n.r][n.c] && !anchored.has(`${n.r},${n.c}`)) {
                anchored.add(`${n.r},${n.c}`); q.push(n);
              }
            }
          }
          let fallingCount = 0;
          for (let r = 0; r < GRID_ROWS; r++) {
            const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
            for (let c = 0; c < cols; c++) {
              if (updatedGrid[r][c] && !anchored.has(`${r},${c}`)) {
                const b = updatedGrid[r][c]!;
                explode(b.x, b.y, palette[b.color], 6, 1.0);
                updatedGrid[r][c] = null;
                fallingCount++;
                setScore(s => {
                  const ns = s + 25;
                  onScoreChange(ns);
                  return ns;
                });
              }
            }
          }
          if (fallingCount > 0) audio.playPop(350);

          setGrid(updatedGrid);
          setProjectile(null);
          if (shotsTaken > 0 && shotsTaken % SHOTS_TO_DROP === 0) {
            dropGrid();
            audio.playPop(220);
            setShake(4);
          }
          if (!updatedGrid.some(row => row.some(b => b !== null))) onWin();
          if (bestR >= GRID_ROWS - 2) onGameOver(score);
        }
      }
      render();
      animationFrameId = requestAnimationFrame(update);
    };

    const drawBubble = (b: Bubble, radius: number = BUBBLE_RADIUS, alpha: number = 1.0) => {
      const { x, y, color, type } = b;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.beginPath();
      ctx.arc(x, y, radius - 1, 0, Math.PI * 2);

      if (type === 'bomb') {
        ctx.fillStyle = '#1e293b';
        ctx.shadowBlur = 18;
        ctx.shadowColor = '#f97316';
      } else if (type === 'laser') {
        ctx.fillStyle = '#134e4a';
        ctx.shadowBlur = 18;
        ctx.shadowColor = '#22d3ee';
      } else {
        ctx.fillStyle = palette[color];
        ctx.shadowBlur = 12;
        ctx.shadowColor = palette[color];
      }
      ctx.fill();

      if (type === 'bomb') {
        ctx.fillStyle = '#fb923c';
        ctx.beginPath();
        ctx.arc(x, y, radius / 2.2, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(x - 2, y - 9, 4, 11);
      } else if (type === 'laser') {
        ctx.strokeStyle = '#22d3ee';
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.moveTo(x - radius/2, y);
        ctx.lineTo(x + radius/2, y);
        ctx.stroke();
      } else {
        ctx.beginPath();
        ctx.arc(x - radius/3, y - radius/3, radius/4, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255,255,255,0.45)';
        ctx.fill();
      }
      ctx.restore();
    };

    const render = () => {
      ctx.save();
      if (shake > 0) ctx.translate(Math.random() * shake - shake/2, Math.random() * shake - shake/2);
      ctx.clearRect(-20, -20, CANVAS_WIDTH + 40, CANVAS_HEIGHT + 40);

      // Draw Grid
      grid.forEach(row => row.forEach(b => b && drawBubble(b)));

      // Draw Aim Line
      const dx = mousePos.current.x - SHOOTER_X;
      const dy = mousePos.current.y - SHOOTER_Y;
      const angle = Math.atan2(dy, dx);
      ctx.beginPath();
      ctx.setLineDash([4, 6]);
      ctx.lineWidth = 2;
      ctx.moveTo(SHOOTER_X, SHOOTER_Y);
      ctx.lineTo(SHOOTER_X + Math.cos(angle) * 140, SHOOTER_Y + Math.sin(angle) * 140);
      ctx.strokeStyle = 'rgba(255,255,255,0.35)';
      ctx.stroke();
      ctx.setLineDash([]);

      // Draw Projectile
      if (projectile) {
        drawBubble({ x: projectile.x, y: projectile.y, color: projectile.color, row: 0, col: 0, type: 'normal' });
      }

      // Draw Particles
      particles.forEach(p => {
        if (p.type === 'beam') {
          ctx.save();
          ctx.beginPath();
          ctx.fillStyle = `rgba(0, 255, 255, ${p.life})`;
          ctx.fillRect(0, p.y - 12, CANVAS_WIDTH, 24);
          ctx.fillStyle = `rgba(255, 255, 255, ${p.life * 1.6})`;
          ctx.fillRect(0, p.y - 4, CANVAS_WIDTH, 8);
          ctx.restore();
        } else {
          ctx.save();
          ctx.globalAlpha = p.life;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
          ctx.fillStyle = p.color;
          ctx.fill();
          ctx.restore();
        }
      });

      // HUD
      const dropsIn = SHOTS_TO_DROP - (shotsTaken % SHOTS_TO_DROP);
      ctx.fillStyle = dropsIn <= 1 ? 'rgba(244, 63, 94, 0.9)' : 'rgba(255, 255, 255, 0.4)';
      ctx.font = 'black 12px Inter';
      ctx.textAlign = 'left';
      ctx.fillText(`THREAT IN: ${dropsIn}`, 20, CANVAS_HEIGHT - 20);

      // Shooter Preview
      drawBubble({ x: SHOOTER_X, y: SHOOTER_Y, color: activeColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS + 3);
      drawBubble({ x: SHOOTER_X + 70, y: SHOOTER_Y + 15, color: nextColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS * 0.75);

      ctx.fillStyle = 'rgba(255,255,255,0.6)';
      ctx.font = 'bold 11px Inter';
      ctx.textAlign = 'center';
      ctx.fillText('NEXT', SHOOTER_X + 70, SHOOTER_Y + 45);
      ctx.restore();
    };

    update();
    return () => cancelAnimationFrame(animationFrameId);
  }, [grid, projectile, activeColor, nextColor, particles, onGameOver, onScoreChange, onWin, score, palette, shotsTaken, dropGrid, triggerBomb, triggerLaser, shake, level]);

  const handlePointer = (e: React.PointerEvent) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    mousePos.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onPointerMove={handlePointer}
      onPointerDown={(e) => { handlePointer(e); handleShoot(); }}
      className="w-full h-full cursor-crosshair touch-none select-none"
    />
  );
};

export default GameBoard;

import { BubbleColor } from './types';

export const CANVAS_WIDTH = 400;
export const CANVAS_HEIGHT = 600;

export const BUBBLE_RADIUS = 20;
export const GRID_ROWS = 14; 
export const GRID_COLS = 8;

export const BUBBLE_COLORS: BubbleColor[] = ['rose', 'amber', 'lime', 'sky', 'violet', 'fuchsia'];

export const COLOR_PALETTES: Record<BubbleColor, string>[] = [
  { // Standard Neon
    rose: '#f43f5e',
    amber: '#f59e0b',
    lime: '#84cc16',
    sky: '#0ea5e9',
    violet: '#8b5cf6',
    fuchsia: '#d946ef'
  },
  { // Cyberpunk Night
    rose: '#ff0055',
    amber: '#ffcc00',
    lime: '#00ff66',
    sky: '#00ffff',
    violet: '#9900ff',
    fuchsia: '#ff00ff'
  },
  { // Retro Sunset
    rose: '#ef4444',
    amber: '#f97316',
    lime: '#fbbf24',
    sky: '#38bdf8',
    violet: '#818cf8',
    fuchsia: '#c084fc'
  },
  { // Arctic Pulse
    rose: '#fb7185',
    amber: '#fbbf24',
    lime: '#4ade80',
    sky: '#22d3ee',
    violet: '#a78bfa',
    fuchsia: '#f472b6'
  }
];

export const POWER_UP_CHANCE = 0.08; // 8% chance for a bubble to be a power-up
export const SHOOTER_Y = CANVAS_HEIGHT - 60;
export const SHOOTER_X = CANVAS_WIDTH / 2;
export const SHOTS_TO_DROP = 5; // Faster grid drops for higher tension
export const PROJECTILE_BASE_SPEED = 22; // High-velocity projectiles
export const COLLISION_THRESHOLD = 1.85; // Tighter collision detection

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { Bubble, BubbleColor, Projectile, Particle, BubbleType } from '../types';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, BUBBLE_RADIUS, GRID_ROWS, GRID_COLS, 
  COLOR_PALETTES, BUBBLE_COLORS, SHOOTER_X, SHOOTER_Y, SHOTS_TO_DROP, 
  POWER_UP_CHANCE, PROJECTILE_BASE_SPEED, COLLISION_THRESHOLD
} from '../constants';
import { audio } from '../services/audioService';

interface GameBoardProps {
  level: number;
  onScoreChange: (score: number) => void;
  onGameOver: (score: number) => void;
  onWin: () => void;
}

const GameBoard: React.FC<GameBoardProps> = ({ level, onScoreChange, onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [score, setScore] = useState(0);
  const [grid, setGrid] = useState<(Bubble | null)[][]>([]);
  const [projectile, setProjectile] = useState<Projectile | null>(null);
  const [nextColor, setNextColor] = useState<BubbleColor>(BUBBLE_COLORS[0]);
  const [activeColor, setActiveColor] = useState<BubbleColor>(BUBBLE_COLORS[1]);
  const [particles, setParticles] = useState<Particle[]>([]);
  const [shotsTaken, setShotsTaken] = useState(0);
  const [shake, setShake] = useState(0);

  const mousePos = useRef({ x: SHOOTER_X, y: 0 });
  const palette = COLOR_PALETTES[(level - 1) % COLOR_PALETTES.length];

  const generateBubble = (r: number, c: number): Bubble => {
    const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
    const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
    const isPowerUp = Math.random() < POWER_UP_CHANCE;
    const type: BubbleType = isPowerUp ? (Math.random() > 0.5 ? 'bomb' : 'laser') : 'normal';
    return { 
      x, y, 
      color: BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)],
      row: r,
      col: c,
      type
    };
  };

  useEffect(() => {
    const startRows = Math.min(GRID_ROWS - 2, 4 + Math.floor(level / 2));
    const newGrid: (Bubble | null)[][] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      newGrid[r] = [];
      const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < colsInRow; c++) {
        if (r < startRows) {
          newGrid[r][c] = generateBubble(r, c);
        } else {
          newGrid[r][c] = null;
        }
      }
    }
    setGrid(newGrid);
    setShotsTaken(0);
    setNextColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
    setActiveColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
  }, [level]);

  const getDistance = (x1: number, y1: number, x2: number, y2: number) => {
    return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);
  };

  const getNeighbors = (r: number, c: number) => {
    const neighbors: { r: number, c: number }[] = [];
    const offsets = r % 2 === 0 
      ? [{ dr: -1, dc: -1 }, { dr: -1, dc: 0 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: -1 }, { dr: 1, dc: 0 }]
      : [{ dr: -1, dc: 0 }, { dr: -1, dc: 1 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: 0 }, { dr: 1, dc: 1 }];

    for (const off of offsets) {
      const nr = r + off.dr;
      const nc = c + off.dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
        neighbors.push({ r: nr, c: nc });
      }
    }
    return neighbors;
  };

  const explode = (x: number, y: number, color: string, count: number = 8, velocityMult: number = 1.0) => {
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      newParticles.push({
        x, y,
        vx: (Math.random() - 0.5) * 16 * velocityMult,
        vy: (Math.random() - 0.5) * 16 * velocityMult,
        radius: Math.random() * 5 + 1.5,
        color,
        life: 1.0
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
  };

  const triggerLaser = useCallback((r: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
    let clearedCount = 0;

    audio.playLaser();
    setShake(10);

    setParticles(prev => [...prev, {
      x: CANVAS_WIDTH / 2,
      y: r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS,
      vx: 0, vy: 0, radius: 28, color: '#00ffff', life: 0.7, type: 'beam'
    }]);

    for (let c = 0; c < colsInRow; c++) {
      if (newGrid[r][c]) {
        const b = newGrid[r][c]!;
        explode(b.x, b.y, '#ffffff', 16, 1.4);
        newGrid[r][c] = null;
        clearedCount++;
      }
    }
    const bonus = clearedCount * 25;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });
    return newGrid;
  }, [onScoreChange]);

  const triggerBomb = useCallback((r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const center = newGrid[r][c];
    if (!center) return newGrid;

    audio.playBomb();
    setShake(30);
    explode(center.x, center.y, '#ff5500', 60, 1.8);

    let clearedCount = 0;
    const explosionRadius = BUBBLE_RADIUS * 6.5;

    for (let row = 0; row < GRID_ROWS; row++) {
      const cols = row % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let col = 0; col < cols; col++) {
        const b = newGrid[row][col];
        if (b) {
          const dist = getDistance(center.x, center.y, b.x, b.y);
          if (dist <= explosionRadius) {
            explode(b.x, b.y, palette[b.color] || '#ffffff', 12, 1.2);
            newGrid[row][col] = null;
            clearedCount++;
          }
        }
      }
    }

    newGrid[r][c] = null;
    const bonus = clearedCount * 20;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });

    return newGrid;
  }, [palette, onScoreChange]);

  const dropGrid = useCallback(() => {
    setGrid(oldGrid => {
      const newGrid: (Bubble | null)[][] = [];
      for (let r = 0; r < GRID_ROWS; r++) {
        newGrid[r] = [];
        const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
        if (r === 0) {
          for (let c = 0; c < colsInRow; c++) {
            newGrid[r][c] = generateBubble(r, c);
          }
        } else {
          const prevRow = oldGrid[r - 1];
          const prevCols = (r - 1) % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < colsInRow; c++) {
            const source = c < prevCols ? prevRow[c] : null;
            const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            if (source) {
              newGrid[r][c] = { ...source, x, y, row: r, col: c };
            } else {
              newGrid[r][c] = null;
            }
          }
        }
      }
      if (newGrid[GRID_ROWS - 2].some(b => b !== null)) onGameOver(score);
      return newGrid;
    });
  }, [score, onGameOver]);

  const handleShoot = useCallback(() => {
    if (projectile) return;
    const dx = mousePos.current.x - SHOOTER_X;
    const dy = mousePos.current.y - SHOOTER_Y;
    const angle = Math.atan2(dy, dx);
    const speed = PROJECTILE_BASE_SPEED + (level * 0.5);

    // Muzzle flash / Recoil effect
    explode(SHOOTER_X, SHOOTER_Y, palette[activeColor], 18, 0.9);
    setShake(5);

    setProjectile({
      x: SHOOTER_X, y: SHOOTER_Y, vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed, color: activeColor
    });
    audio.playShoot();
    setShotsTaken(prev => prev + 1);
    setActiveColor(nextColor);
    setNextColor(BUBBLE_COLORS[Math.floor(Math.random() * BUBBLE_COLORS.length)]);
  }, [projectile, activeColor, nextColor, level, palette]);

  useEffect(() => {
    let animationFrameId: number;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const update = () => {
      // High-octane particle updates
      setParticles(prev => prev.map(p => ({
        ...p, 
        x: p.x + p.vx, 
        y: p.y + p.vy, 
        life: p.life - (p.type === 'beam' ? 0.05 : 0.04)
      })).filter(p => p.life > 0));

      if (shake > 0) setShake(s => Math.max(0, s - 0.8));

      if (projectile) {
        // High-precision sub-stepping for fast projectiles
        const SUB_STEPS = 4;
        let collided = false;
        let hitBubble: Bubble | null = null;
        let bestR = -1;
        let bestC = -1;

        for (let i = 0; i < SUB_STEPS && !collided; i++) {
          projectile.x += projectile.vx / SUB_STEPS;
          projectile.y += projectile.vy / SUB_STEPS;

          // Wall bounce
          if (projectile.x - BUBBLE_RADIUS < 0) {
            projectile.x = BUBBLE_RADIUS;
            projectile.vx *= -1;
          } else if (projectile.x + BUBBLE_RADIUS > CANVAS_WIDTH) {
            projectile.x = CANVAS_WIDTH - BUBBLE_RADIUS;
            projectile.vx *= -1;
          }

          // Roof collision
          if (projectile.y - BUBBLE_RADIUS < 0) {
            collided = true;
            let minD = Infinity;
            for (let c = 0; c < GRID_COLS; c++) {
              const sx = c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS;
              const d = Math.abs(projectile.x - sx);
              if (d < minD) { minD = d; bestR = 0; bestC = c; }
            }
          } else {
            // Bubble collision
            for (let r = 0; r < GRID_ROWS; r++) {
              const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
              for (let c = 0; c < cols; c++) {
                const b = grid[r][c];
                if (b && getDistance(projectile.x, projectile.y, b.x, b.y) < BUBBLE_RADIUS * COLLISION_THRESHOLD) {
                  collided = true;
                  hitBubble = b;

                  // Snap to nearest empty slot
                  let minD = Infinity;
                  const neighbors = getNeighbors(r, c);
                  for (const n of neighbors) {
                    if (!grid[n.r][n.c]) {
                      const nx = (n.r % 2 === 0 ? n.c * BUBBLE_RADIUS * 2 : n.c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
                      const ny = n.r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
                      const d = getDistance(projectile.x, projectile.y, nx, ny);
                      if (d < minD) { minD = d; bestR = n.r; bestC = n.c; }
                    }
                  }
                }
              }
            }
          }
        }

        if (collided) {
          let updatedGrid = [...grid.map(row => [...row])];

          if (hitBubble?.type === 'bomb') {
            updatedGrid = triggerBomb(hitBubble.row, hitBubble.col, updatedGrid);
          } else if (hitBubble?.type === 'laser') {
            updatedGrid = triggerLaser(hitBubble.row, updatedGrid);
          } else if (bestR !== -1) {
            const px = (bestR % 2 === 0 ? bestC * BUBBLE_RADIUS * 2 : bestC * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const py = bestR * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            updatedGrid[bestR][bestC] = { x: px, y: py, color: projectile.color, row: bestR, col: bestC, type: 'normal' };

            const matches: {r: number, c: number}[] = [{ r: bestR, c: bestC }];
            const visited = new Set<string>(); visited.add(`${bestR},${bestC}`);
            let mi = 0;
            while (mi < matches.length) {
              const curr = matches[mi++];
              for (const n of getNeighbors(curr.r, curr.c)) {
                const b = updatedGrid[n.r][n.c];
                if (b && b.color === projectile.color && b.type === 'normal' && !visited.has(`${n.r},${n.c}`)) {
                  visited.add(`${n.r},${n.c}`);
                  matches.push(n);
                }
              }
            }

            if (matches.length >= 3) {
              audio.playPop(450 + matches.length * 30);
              setShake(4 + matches.length * 0.7);
              matches.forEach(m => {
                const b = updatedGrid[m.r][m.c];
                if (b) explode(b.x, b.y, palette[b.color], 12, 1.3);
                updatedGrid[m.r][m.c] = null;
              });
              setScore(s => {
                const ns = s + matches.length * 20;
                onScoreChange(ns);
                return ns;
              });
            } else {
              audio.playShoot();
            }
          }

          // Hanging bubble check
          const anchored = new Set<string>();
          const q: {r: number, c: number}[] = [];
          for (let c = 0; c < GRID_COLS; c++) { if (updatedGrid[0][c]) { anchored.add(`0,${c}`); q.push({ r: 0, c }); } }
          let qi = 0;
          while (qi < q.length) {
            const curr = q[qi++];
            for (const n of getNeighbors(curr.r, curr.c)) {
              if (updatedGrid[n.r][n.c] && !anchored.has(`${n.r},${n.c}`)) {
                anchored.add(`${n.r},${n.c}`); q.push(n);
              }
            }
          }
          let fallingCount = 0;
          for (let r = 0; r < GRID_ROWS; r++) {
            const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
            for (let c = 0; c < cols; c++) {
              if (updatedGrid[r][c] && !anchored.has(`${r},${c}`)) {
                const b = updatedGrid[r][c]!;
                explode(b.x, b.y, palette[b.color], 8, 1.1);
                updatedGrid[r][c] = null;
                fallingCount++;
                setScore(s => {
                  const ns = s + 30;
                  onScoreChange(ns);
                  return ns;
                });
              }
            }
          }
          if (fallingCount > 0) audio.playPop(380);

          setGrid(updatedGrid);
          setProjectile(null);
          if (shotsTaken > 0 && shotsTaken % SHOTS_TO_DROP === 0) {
            dropGrid();
            audio.playPop(250);
            setShake(6);
          }
          if (!updatedGrid.some(row => row.some(b => b !== null))) onWin();
          if (bestR >= GRID_ROWS - 2) onGameOver(score);
        }
      }
      render();
      animationFrameId = requestAnimationFrame(update);
    };

    const drawBubble = (b: Bubble, radius: number = BUBBLE_RADIUS, alpha: number = 1.0) => {
      const { x, y, color, type } = b;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.beginPath();
      ctx.arc(x, y, radius - 1, 0, Math.PI * 2);

      if (type === 'bomb') {
        ctx.fillStyle = '#1e1e2e';
        ctx.shadowBlur = 20;
        ctx.shadowColor = '#f97316';
      } else if (type === 'laser') {
        ctx.fillStyle = '#0f172a';
        ctx.shadowBlur = 20;
        ctx.shadowColor = '#38bdf8';
      } else {
        ctx.fillStyle = palette[color];
        ctx.shadowBlur = 14;
        ctx.shadowColor = palette[color];
      }
      ctx.fill();

      if (type === 'bomb') {
        ctx.fillStyle = '#f97316';
        ctx.beginPath();
        ctx.arc(x, y, radius / 2, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(x - 2, y - 10, 4, 12);
      } else if (type === 'laser') {
        ctx.strokeStyle = '#38bdf8';
        ctx.lineWidth = 5;
        ctx.beginPath();
        ctx.moveTo(x - radius/2, y);
        ctx.lineTo(x + radius/2, y);
        ctx.stroke();
      } else {
        ctx.beginPath();
        ctx.arc(x - radius/3, y - radius/3, radius/4, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255,255,255,0.5)';
        ctx.fill();
      }
      ctx.restore();
    };

    const render = () => {
      ctx.save();
      if (shake > 0) ctx.translate(Math.random() * shake - shake/2, Math.random() * shake - shake/2);
      ctx.clearRect(-40, -40, CANVAS_WIDTH + 80, CANVAS_HEIGHT + 80);

      // Grid Rendering
      grid.forEach(row => row.forEach(b => b && drawBubble(b)));

      // Precision Aim Line
      const dx = mousePos.current.x - SHOOTER_X;
      const dy = mousePos.current.y - SHOOTER_Y;
      const angle = Math.atan2(dy, dx);
      ctx.beginPath();
      ctx.setLineDash([6, 8]);
      ctx.lineWidth = 2.5;
      ctx.moveTo(SHOOTER_X, SHOOTER_Y);
      ctx.lineTo(SHOOTER_X + Math.cos(angle) * 160, SHOOTER_Y + Math.sin(angle) * 160);
      ctx.strokeStyle = 'rgba(255,255,255,0.4)';
      ctx.stroke();
      ctx.setLineDash([]);

      if (projectile) {
        drawBubble({ x: projectile.x, y: projectile.y, color: projectile.color, row: 0, col: 0, type: 'normal' });
      }

      particles.forEach(p => {
        if (p.type === 'beam') {
          ctx.save();
          ctx.beginPath();
          ctx.fillStyle = `rgba(0, 255, 255, ${p.life})`;
          ctx.fillRect(0, p.y - 15, CANVAS_WIDTH, 30);
          ctx.fillStyle = `rgba(255, 255, 255, ${p.life * 1.8})`;
          ctx.fillRect(0, p.y - 5, CANVAS_WIDTH, 10);
          ctx.restore();
        } else {
          ctx.save();
          ctx.globalAlpha = p.life;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
          ctx.fillStyle = p.color;
          ctx.fill();
          ctx.restore();
        }
      });

      // Threat Indicator
      const dropsIn = SHOTS_TO_DROP - (shotsTaken % SHOTS_TO_DROP);
      ctx.fillStyle = dropsIn <= 1 ? 'rgba(244, 63, 94, 1.0)' : 'rgba(255, 255, 255, 0.5)';
      ctx.font = '900 13px Inter';
      ctx.textAlign = 'left';
      ctx.fillText(`THREAT IN: ${dropsIn}`, 20, CANVAS_HEIGHT - 20);

      // Shooter Assembly
      drawBubble({ x: SHOOTER_X, y: SHOOTER_Y, color: activeColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS + 4);
      drawBubble({ x: SHOOTER_X + 80, y: SHOOTER_Y + 15, color: nextColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS * 0.8);

      ctx.fillStyle = 'rgba(255,255,255,0.7)';
      ctx.font = '900 12px Inter';
      ctx.textAlign = 'center';
      ctx.fillText('NEXT', SHOOTER_X + 80, SHOOTER_Y + 45);
      ctx.restore();
    };

    update();
    return () => cancelAnimationFrame(animationFrameId);
  }, [grid, projectile, activeColor, nextColor, particles, onGameOver, onScoreChange, onWin, score, palette, shotsTaken, dropGrid, triggerBomb, triggerLaser, shake, level]);

  const handlePointer = (e: React.PointerEvent) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    mousePos.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onPointerMove={handlePointer}
      onPointerDown={(e) => { handlePointer(e); handleShoot(); }}
      className="w-full h-full cursor-crosshair touch-none select-none"
    />
  );
};

export default GameBoard;

import { BubbleColor } from './types';

export const CANVAS_WIDTH = 400;
export const CANVAS_HEIGHT = 600;

export const BUBBLE_RADIUS = 20;
export const GRID_ROWS = 14; 
export const GRID_COLS = 8;

export const BUBBLE_COLORS: BubbleColor[] = ['rose', 'amber', 'lime', 'sky', 'violet', 'fuchsia'];

export const COLOR_PALETTES: Record<BubbleColor, string>[] = [
  { // Standard Neon
    rose: '#f43f5e',
    amber: '#f59e0b',
    lime: '#84cc16',
    sky: '#0ea5e9',
    violet: '#8b5cf6',
    fuchsia: '#d946ef'
  },
  { // Cyberpunk Night
    rose: '#ff0055',
    amber: '#ffcc00',
    lime: '#00ff66',
    sky: '#00ffff',
    violet: '#9900ff',
    fuchsia: '#ff00ff'
  },
  { // Retro Sunset
    rose: '#ef4444',
    amber: '#f97316',
    lime: '#fbbf24',
    sky: '#38bdf8',
    violet: '#818cf8',
    fuchsia: '#c084fc'
  },
  { // Arctic Pulse
    rose: '#fb7185',
    amber: '#fbbf24',
    lime: '#4ade80',
    sky: '#22d3ee',
    violet: '#a78bfa',
    fuchsia: '#f472b6'
  }
];

export const POWER_UP_CHANCE_BASE = 0.08;
export const SHOOTER_Y = CANVAS_HEIGHT - 60;
export const SHOOTER_X = CANVAS_WIDTH / 2;

// Difficulty Scaling Settings
export const MIN_SHOTS_TO_DROP = 3;
export const MAX_SHOTS_TO_DROP = 7;
export const PROJECTILE_BASE_SPEED = 22;
export const COLLISION_THRESHOLD = 1.85;

import React, { useRef, useEffect, useState, useCallback, useMemo } from 'react';
import { Bubble, BubbleColor, Projectile, Particle, BubbleType } from '../types';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, BUBBLE_RADIUS, GRID_ROWS, GRID_COLS, 
  COLOR_PALETTES, BUBBLE_COLORS, SHOOTER_X, SHOOTER_Y, 
  POWER_UP_CHANCE_BASE, PROJECTILE_BASE_SPEED, COLLISION_THRESHOLD,
  MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP
} from '../constants';
import { audio } from '../services/audioService';

interface GameBoardProps {
  level: number;
  onScoreChange: (score: number) => void;
  onGameOver: (score: number) => void;
  onWin: () => void;
}

const GameBoard: React.FC<GameBoardProps> = ({ level, onScoreChange, onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [score, setScore] = useState(0);
  const [grid, setGrid] = useState<(Bubble | null)[][]>([]);
  const [projectile, setProjectile] = useState<Projectile | null>(null);
  const [nextColor, setNextColor] = useState<BubbleColor>(BUBBLE_COLORS[0]);
  const [activeColor, setActiveColor] = useState<BubbleColor>(BUBBLE_COLORS[1]);
  const [particles, setParticles] = useState<Particle[]>([]);
  const [shotsTaken, setShotsTaken] = useState(0);
  const [shake, setShake] = useState(0);

  const mousePos = useRef({ x: SHOOTER_X, y: 0 });
  const palette = COLOR_PALETTES[(level - 1) % COLOR_PALETTES.length];

  // Dynamic Difficulty Calculations
  const currentLevelShotsToDrop = useMemo(() => 
    Math.max(MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP - Math.floor((level - 1) / 3)), 
  [level]);

  const activeColorCount = useMemo(() => 
    Math.min(6, 4 + Math.floor((level - 1) / 2)), 
  [level]);

  const availableColors = useMemo(() => 
    BUBBLE_COLORS.slice(0, activeColorCount), 
  [activeColorCount]);

  const generateBubble = useCallback((r: number, c: number): Bubble => {
    const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
    const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;

    // Power-up chance increases slightly with level to compensate for difficulty
    const powerUpChance = POWER_UP_CHANCE_BASE + (level * 0.005);
    const isPowerUp = Math.random() < powerUpChance;
    const type: BubbleType = isPowerUp ? (Math.random() > 0.5 ? 'bomb' : 'laser') : 'normal';

    return { 
      x, y, 
      color: availableColors[Math.floor(Math.random() * availableColors.length)],
      row: r,
      col: c,
      type
    };
  }, [availableColors, level]);

  useEffect(() => {
    const startRows = Math.min(GRID_ROWS - 4, 5 + Math.floor(level / 2));
    const newGrid: (Bubble | null)[][] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      newGrid[r] = [];
      const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < colsInRow; c++) {
        if (r < startRows) {
          newGrid[r][c] = generateBubble(r, c);
        } else {
          newGrid[r][c] = null;
        }
      }
    }
    setGrid(newGrid);
    setShotsTaken(0);
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
    setActiveColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [level, generateBubble, availableColors]);

  const getDistance = (x1: number, y1: number, x2: number, y2: number) => {
    return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);
  };

  const getNeighbors = (r: number, c: number) => {
    const neighbors: { r: number, c: number }[] = [];
    const offsets = r % 2 === 0 
      ? [{ dr: -1, dc: -1 }, { dr: -1, dc: 0 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: -1 }, { dr: 1, dc: 0 }]
      : [{ dr: -1, dc: 0 }, { dr: -1, dc: 1 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: 0 }, { dr: 1, dc: 1 }];

    for (const off of offsets) {
      const nr = r + off.dr;
      const nc = c + off.dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
        neighbors.push({ r: nr, c: nc });
      }
    }
    return neighbors;
  };

  const explode = (x: number, y: number, color: string, count: number = 8, velocityMult: number = 1.0) => {
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      newParticles.push({
        x, y,
        vx: (Math.random() - 0.5) * 16 * velocityMult,
        vy: (Math.random() - 0.5) * 16 * velocityMult,
        radius: Math.random() * 5 + 1.5,
        color,
        life: 1.0
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
  };

  const triggerLaser = useCallback((r: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
    let clearedCount = 0;

    audio.playLaser();
    setShake(10);

    setParticles(prev => [...prev, {
      x: CANVAS_WIDTH / 2,
      y: r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS,
      vx: 0, vy: 0, radius: 28, color: '#00ffff', life: 0.7, type: 'beam'
    }]);

    for (let c = 0; c < colsInRow; c++) {
      if (newGrid[r][c]) {
        const b = newGrid[r][c]!;
        explode(b.x, b.y, '#ffffff', 16, 1.4);
        newGrid[r][c] = null;
        clearedCount++;
      }
    }
    const bonus = clearedCount * 25;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });
    return newGrid;
  }, [onScoreChange]);

  const triggerBomb = useCallback((r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const center = newGrid[r][c];
    if (!center) return newGrid;

    audio.playBomb();
    setShake(30);
    explode(center.x, center.y, '#ff5500', 60, 1.8);

    let clearedCount = 0;
    const explosionRadius = BUBBLE_RADIUS * 6.5;

    for (let row = 0; row < GRID_ROWS; row++) {
      const cols = row % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let col = 0; col < cols; col++) {
        const b = newGrid[row][col];
        if (b) {
          const dist = getDistance(center.x, center.y, b.x, b.y);
          if (dist <= explosionRadius) {
            explode(b.x, b.y, palette[b.color] || '#ffffff', 12, 1.2);
            newGrid[row][col] = null;
            clearedCount++;
          }
        }
      }
    }

    newGrid[r][c] = null;
    const bonus = clearedCount * 20;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });

    return newGrid;
  }, [palette, onScoreChange]);

  const dropGrid = useCallback(() => {
    setGrid(oldGrid => {
      const newGrid: (Bubble | null)[][] = [];
      for (let r = 0; r < GRID_ROWS; r++) {
        newGrid[r] = [];
        const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
        if (r === 0) {
          for (let c = 0; c < colsInRow; c++) {
            newGrid[r][c] = generateBubble(r, c);
          }
        } else {
          const prevRow = oldGrid[r - 1];
          const prevCols = (r - 1) % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < colsInRow; c++) {
            const source = c < prevCols ? prevRow[c] : null;
            const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            if (source) {
              newGrid[r][c] = { ...source, x, y, row: r, col: c };
            } else {
              newGrid[r][c] = null;
            }
          }
        }
      }
      // Fail condition: bubble hits the danger zone
      if (newGrid[GRID_ROWS - 3].some(b => b !== null)) onGameOver(score);
      return newGrid;
    });
  }, [score, onGameOver, generateBubble]);

  const handleShoot = useCallback(() => {
    if (projectile) return;
    const dx = mousePos.current.x - SHOOTER_X;
    const dy = mousePos.current.y - SHOOTER_Y;
    const angle = Math.atan2(dy, dx);
    const speed = PROJECTILE_BASE_SPEED + (level * 0.5);

    explode(SHOOTER_X, SHOOTER_Y, palette[activeColor] || '#ffffff', 18, 0.9);
    setShake(5);

    setProjectile({
      x: SHOOTER_X, y: SHOOTER_Y, vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed, color: activeColor
    });
    audio.playShoot();
    setShotsTaken(prev => prev + 1);
    setActiveColor(nextColor);
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [projectile, activeColor, nextColor, level, palette, availableColors]);

  useEffect(() => {
    let animationFrameId: number;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const update = () => {
      setParticles(prev => prev.map(p => ({
        ...p, 
        x: p.x + p.vx, 
        y: p.y + p.vy, 
        life: p.life - (p.type === 'beam' ? 0.05 : 0.04)
      })).filter(p => p.life > 0));

      if (shake > 0) setShake(s => Math.max(0, s - 0.8));

      if (projectile) {
        const SUB_STEPS = 4;
        let collided = false;
        let hitBubble: Bubble | null = null;
        let bestR = -1;
        let bestC = -1;

        for (let i = 0; i < SUB_STEPS && !collided; i++) {
          projectile.x += projectile.vx / SUB_STEPS;
          projectile.y += projectile.vy / SUB_STEPS;

          if (projectile.x - BUBBLE_RADIUS < 0) {
            projectile.x = BUBBLE_RADIUS;
            projectile.vx *= -1;
          } else if (projectile.x + BUBBLE_RADIUS > CANVAS_WIDTH) {
            projectile.x = CANVAS_WIDTH - BUBBLE_RADIUS;
            projectile.vx *= -1;
          }

          if (projectile.y - BUBBLE_RADIUS < 0) {
            collided = true;
            let minD = Infinity;
            for (let c = 0; c < GRID_COLS; c++) {
              const sx = c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS;
              const d = Math.abs(projectile.x - sx);
              if (d < minD) { minD = d; bestR = 0; bestC = c; }
            }
          } else {
            for (let r = 0; r < GRID_ROWS; r++) {
              const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
              for (let c = 0; c < cols; c++) {
                const b = grid[r][c];
                if (b && getDistance(projectile.x, projectile.y, b.x, b.y) < BUBBLE_RADIUS * COLLISION_THRESHOLD) {
                  collided = true;
                  hitBubble = b;

                  let minD = Infinity;
                  const neighbors = getNeighbors(r, c);
                  for (const n of neighbors) {
                    if (!grid[n.r][n.c]) {
                      const nx = (n.r % 2 === 0 ? n.c * BUBBLE_RADIUS * 2 : n.c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
                      const ny = n.r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
                      const d = getDistance(projectile.x, projectile.y, nx, ny);
                      if (d < minD) { minD = d; bestR = n.r; bestC = n.c; }
                    }
                  }
                }
              }
            }
          }
        }

        if (collided) {
          let updatedGrid = [...grid.map(row => [...row])];

          if (hitBubble?.type === 'bomb') {
            updatedGrid = triggerBomb(hitBubble.row, hitBubble.col, updatedGrid);
          } else if (hitBubble?.type === 'laser') {
            updatedGrid = triggerLaser(hitBubble.row, updatedGrid);
          } else if (bestR !== -1) {
            const px = (bestR % 2 === 0 ? bestC * BUBBLE_RADIUS * 2 : bestC * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const py = bestR * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            updatedGrid[bestR][bestC] = { x: px, y: py, color: projectile.color, row: bestR, col: bestC, type: 'normal' };

            const matches: {r: number, c: number}[] = [{ r: bestR, c: bestC }];
            const visited = new Set<string>(); visited.add(`${bestR},${bestC}`);
            let mi = 0;
            while (mi < matches.length) {
              const curr = matches[mi++];
              for (const n of getNeighbors(curr.r, curr.c)) {
                const b = updatedGrid[n.r][n.c];
                if (b && b.color === projectile.color && b.type === 'normal' && !visited.has(`${n.r},${n.c}`)) {
                  visited.add(`${n.r},${n.c}`);
                  matches.push(n);
                }
              }
            }

            if (matches.length >= 3) {
              audio.playPop(450 + matches.length * 30);
              setShake(4 + matches.length * 0.7);
              matches.forEach(m => {
                const b = updatedGrid[m.r][m.c];
                if (b) explode(b.x, b.y, palette[b.color], 12, 1.3);
                updatedGrid[m.r][m.c] = null;
              });
              setScore(s => {
                const ns = s + matches.length * 20;
                onScoreChange(ns);
                return ns;
              });
            } else {
              audio.playShoot();
            }
          }

          const anchored = new Set<string>();
          const q: {r: number, c: number}[] = [];
          for (let c = 0; c < GRID_COLS; c++) { if (updatedGrid[0][c]) { anchored.add(`0,${c}`); q.push({ r: 0, c }); } }
          let qi = 0;
          while (qi < q.length) {
            const curr = q[qi++];
            for (const n of getNeighbors(curr.r, curr.c)) {
              if (updatedGrid[n.r][n.c] && !anchored.has(`${n.r},${n.c}`)) {
                anchored.add(`${n.r},${n.c}`); q.push(n);
              }
            }
          }
          let fallingCount = 0;
          for (let r = 0; r < GRID_ROWS; r++) {
            const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
            for (let c = 0; c < cols; c++) {
              if (updatedGrid[r][c] && !anchored.has(`${r},${c}`)) {
                const b = updatedGrid[r][c]!;
                explode(b.x, b.y, palette[b.color], 8, 1.1);
                updatedGrid[r][c] = null;
                fallingCount++;
                setScore(s => {
                  const ns = s + 30;
                  onScoreChange(ns);
                  return ns;
                });
              }
            }
          }
          if (fallingCount > 0) audio.playPop(380);

          setGrid(updatedGrid);
          setProjectile(null);

          if (shotsTaken > 0 && shotsTaken % currentLevelShotsToDrop === 0) {
            dropGrid();
            audio.playPop(250);
            setShake(6);
          }

          if (!updatedGrid.some(row => row.some(b => b !== null))) onWin();
          if (bestR >= GRID_ROWS - 3) onGameOver(score);
        }
      }
      render();
      animationFrameId = requestAnimationFrame(update);
    };

    const drawBubble = (b: Bubble, radius: number = BUBBLE_RADIUS, alpha: number = 1.0) => {
      const { x, y, color, type } = b;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.beginPath();
      ctx.arc(x, y, radius - 1, 0, Math.PI * 2);

      if (type === 'bomb') {
        ctx.fillStyle = '#1e1e2e';
        ctx.shadowBlur = 20;
        ctx.shadowColor = '#f97316';
      } else if (type === 'laser') {
        ctx.fillStyle = '#0f172a';
        ctx.shadowBlur = 20;
        ctx.shadowColor = '#38bdf8';
      } else {
        ctx.fillStyle = palette[color];
        ctx.shadowBlur = 14;
        ctx.shadowColor = palette[color];
      }
      ctx.fill();

      if (type === 'bomb') {
        ctx.fillStyle = '#f97316';
        ctx.beginPath();
        ctx.arc(x, y, radius / 2, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(x - 2, y - 10, 4, 12);
      } else if (type === 'laser') {
        ctx.strokeStyle = '#38bdf8';
        ctx.lineWidth = 5;
        ctx.beginPath();
        ctx.moveTo(x - radius/2, y);
        ctx.lineTo(x + radius/2, y);
        ctx.stroke();
      } else {
        ctx.beginPath();
        ctx.arc(x - radius/3, y - radius/3, radius/4, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255,255,255,0.5)';
        ctx.fill();
      }
      ctx.restore();
    };

    const render = () => {
      ctx.save();
      if (shake > 0) ctx.translate(Math.random() * shake - shake/2, Math.random() * shake - shake/2);
      ctx.clearRect(-40, -40, CANVAS_WIDTH + 80, CANVAS_HEIGHT + 80);

      // Danger Zone line
      ctx.beginPath();
      ctx.strokeStyle = 'rgba(244, 63, 94, 0.3)';
      ctx.setLineDash([5, 5]);
      const dangerY = (GRID_ROWS - 3) * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS * 2;
      ctx.moveTo(0, dangerY);
      ctx.lineTo(CANVAS_WIDTH, dangerY);
      ctx.stroke();
      ctx.setLineDash([]);

      grid.forEach(row => row.forEach(b => b && drawBubble(b)));

      const dx = mousePos.current.x - SHOOTER_X;
      const dy = mousePos.current.y - SHOOTER_Y;
      const angle = Math.atan2(dy, dx);
      ctx.beginPath();
      ctx.setLineDash([6, 8]);
      ctx.lineWidth = 2.5;
      ctx.moveTo(SHOOTER_X, SHOOTER_Y);
      ctx.lineTo(SHOOTER_X + Math.cos(angle) * 160, SHOOTER_Y + Math.sin(angle) * 160);
      ctx.strokeStyle = 'rgba(255,255,255,0.4)';
      ctx.stroke();
      ctx.setLineDash([]);

      if (projectile) {
        drawBubble({ x: projectile.x, y: projectile.y, color: projectile.color, row: 0, col: 0, type: 'normal' });
      }

      particles.forEach(p => {
        if (p.type === 'beam') {
          ctx.save();
          ctx.beginPath();
          ctx.fillStyle = `rgba(0, 255, 255, ${p.life})`;
          ctx.fillRect(0, p.y - 15, CANVAS_WIDTH, 30);
          ctx.fillStyle = `rgba(255, 255, 255, ${p.life * 1.8})`;
          ctx.fillRect(0, p.y - 5, CANVAS_WIDTH, 10);
          ctx.restore();
        } else {
          ctx.save();
          ctx.globalAlpha = p.life;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
          ctx.fillStyle = p.color;
          ctx.fill();
          ctx.restore();
        }
      });

      const dropsIn = currentLevelShotsToDrop - (shotsTaken % currentLevelShotsToDrop);
      ctx.fillStyle = dropsIn <= 1 ? 'rgba(244, 63, 94, 1.0)' : 'rgba(255, 255, 255, 0.5)';
      ctx.font = '900 13px Inter';
      ctx.textAlign = 'left';
      ctx.fillText(`THREAT IN: ${dropsIn}`, 20, CANVAS_HEIGHT - 20);

      drawBubble({ x: SHOOTER_X, y: SHOOTER_Y, color: activeColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS + 4);
      drawBubble({ x: SHOOTER_X + 80, y: SHOOTER_Y + 15, color: nextColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS * 0.8);

      ctx.fillStyle = 'rgba(255,255,255,0.7)';
      ctx.font = '900 12px Inter';
      ctx.textAlign = 'center';
      ctx.fillText('NEXT', SHOOTER_X + 80, SHOOTER_Y + 45);
      ctx.restore();
    };

    update();
    return () => cancelAnimationFrame(animationFrameId);
  }, [grid, projectile, activeColor, nextColor, particles, onGameOver, onScoreChange, onWin, score, palette, shotsTaken, dropGrid, triggerBomb, triggerLaser, shake, level, currentLevelShotsToDrop]);

  const handlePointer = (e: React.PointerEvent) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    mousePos.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onPointerMove={handlePointer}
      onPointerDown={(e) => { handlePointer(e); handleShoot(); }}
      className="w-full h-full cursor-crosshair touch-none select-none"
    />
  );
};

export default GameBoard;

import { BubbleColor } from './types';

export const CANVAS_WIDTH = 400;
export const CANVAS_HEIGHT = 600;

export const BUBBLE_RADIUS = 20;
export const GRID_ROWS = 14; 
export const GRID_COLS = 8;

export const BUBBLE_COLORS: BubbleColor[] = ['rose', 'amber', 'lime', 'sky', 'violet', 'fuchsia'];

export const COLOR_PALETTES: Record<BubbleColor, string>[] = [
  { // Standard Neon
    rose: '#f43f5e',
    amber: '#f59e0b',
    lime: '#84cc16',
    sky: '#0ea5e9',
    violet: '#8b5cf6',
    fuchsia: '#d946ef'
  },
  { // Cyberpunk Night
    rose: '#ff0055',
    amber: '#ffcc00',
    lime: '#00ff66',
    sky: '#00ffff',
    violet: '#9900ff',
    fuchsia: '#ff00ff'
  },
  { // Retro Sunset
    rose: '#ef4444',
    amber: '#f97316',
    lime: '#fbbf24',
    sky: '#38bdf8',
    violet: '#818cf8',
    fuchsia: '#c084fc'
  },
  { // Arctic Pulse
    rose: '#fb7185',
    amber: '#fbbf24',
    lime: '#4ade80',
    sky: '#22d3ee',
    violet: '#a78bfa',
    fuchsia: '#f472b6'
  }
];

export const POWER_UP_CHANCE_BASE = 0.08;
export const SHOOTER_Y = CANVAS_HEIGHT - 60;
export const SHOOTER_X = CANVAS_WIDTH / 2;

// Difficulty Scaling Settings
export const MIN_SHOTS_TO_DROP = 3;
export const MAX_SHOTS_TO_DROP = 7;
export const PROJECTILE_BASE_SPEED = 13; // Balanced for visibility
export const COLLISION_THRESHOLD = 1.85;

import React, { useRef, useEffect, useState, useCallback, useMemo } from 'react';
import { Bubble, BubbleColor, Projectile, Particle, BubbleType } from '../types';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, BUBBLE_RADIUS, GRID_ROWS, GRID_COLS, 
  COLOR_PALETTES, BUBBLE_COLORS, SHOOTER_X, SHOOTER_Y, 
  POWER_UP_CHANCE_BASE, PROJECTILE_BASE_SPEED, COLLISION_THRESHOLD,
  MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP
} from '../constants';
import { audio } from '../services/audioService';

interface GameBoardProps {
  level: number;
  onScoreChange: (score: number) => void;
  onGameOver: (score: number) => void;
  onWin: () => void;
}

const GameBoard: React.FC<GameBoardProps> = ({ level, onScoreChange, onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [score, setScore] = useState(0);
  const [grid, setGrid] = useState<(Bubble | null)[][]>([]);
  const [projectile, setProjectile] = useState<Projectile | null>(null);
  const [nextColor, setNextColor] = useState<BubbleColor>(BUBBLE_COLORS[0]);
  const [activeColor, setActiveColor] = useState<BubbleColor>(BUBBLE_COLORS[1]);
  const [particles, setParticles] = useState<Particle[]>([]);
  const [shotsTaken, setShotsTaken] = useState(0);
  const [shake, setShake] = useState(0);

  const mousePos = useRef({ x: SHOOTER_X, y: 0 });
  const palette = COLOR_PALETTES[(level - 1) % COLOR_PALETTES.length];

  // Dynamic Difficulty Calculations
  const currentLevelShotsToDrop = useMemo(() => 
    Math.max(MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP - Math.floor((level - 1) / 3)), 
  [level]);

  const activeColorCount = useMemo(() => 
    Math.min(6, 4 + Math.floor((level - 1) / 2)), 
  [level]);

  const availableColors = useMemo(() => 
    BUBBLE_COLORS.slice(0, activeColorCount), 
  [activeColorCount]);

  const generateBubble = useCallback((r: number, c: number): Bubble => {
    const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
    const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;

    // Power-up chance increases slightly with level to compensate for difficulty
    const powerUpChance = POWER_UP_CHANCE_BASE + (level * 0.005);
    const isPowerUp = Math.random() < powerUpChance;
    const type: BubbleType = isPowerUp ? (Math.random() > 0.5 ? 'bomb' : 'laser') : 'normal';

    return { 
      x, y, 
      color: availableColors[Math.floor(Math.random() * availableColors.length)],
      row: r,
      col: c,
      type
    };
  }, [availableColors, level]);

  useEffect(() => {
    const startRows = Math.min(GRID_ROWS - 4, 5 + Math.floor(level / 2));
    const newGrid: (Bubble | null)[][] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      newGrid[r] = [];
      const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < colsInRow; c++) {
        if (r < startRows) {
          newGrid[r][c] = generateBubble(r, c);
        } else {
          newGrid[r][c] = null;
        }
      }
    }
    setGrid(newGrid);
    setShotsTaken(0);
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
    setActiveColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [level, generateBubble, availableColors]);

  const getDistance = (x1: number, y1: number, x2: number, y2: number) => {
    return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);
  };

  const getNeighbors = (r: number, c: number) => {
    const neighbors: { r: number, c: number }[] = [];
    const offsets = r % 2 === 0 
      ? [{ dr: -1, dc: -1 }, { dr: -1, dc: 0 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: -1 }, { dr: 1, dc: 0 }]
      : [{ dr: -1, dc: 0 }, { dr: -1, dc: 1 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: 0 }, { dr: 1, dc: 1 }];

    for (const off of offsets) {
      const nr = r + off.dr;
      const nc = c + off.dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
        neighbors.push({ r: nr, c: nc });
      }
    }
    return neighbors;
  };

  const explode = (x: number, y: number, color: string, count: number = 8, velocityMult: number = 1.0) => {
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      newParticles.push({
        x, y,
        vx: (Math.random() - 0.5) * 16 * velocityMult,
        vy: (Math.random() - 0.5) * 16 * velocityMult,
        radius: Math.random() * 5 + 1.5,
        color,
        life: 1.0
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
  };

  const triggerLaser = useCallback((r: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
    let clearedCount = 0;

    audio.playLaser();
    setShake(10);

    setParticles(prev => [...prev, {
      x: CANVAS_WIDTH / 2,
      y: r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS,
      vx: 0, vy: 0, radius: 28, color: '#00ffff', life: 0.7, type: 'beam'
    }]);

    for (let c = 0; c < colsInRow; c++) {
      if (newGrid[r][c]) {
        const b = newGrid[r][c]!;
        explode(b.x, b.y, '#ffffff', 16, 1.4);
        newGrid[r][c] = null;
        clearedCount++;
      }
    }
    const bonus = clearedCount * 25;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });
    return newGrid;
  }, [onScoreChange]);

  const triggerBomb = useCallback((r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const center = newGrid[r][c];
    if (!center) return newGrid;

    audio.playBomb();
    setShake(30);
    explode(center.x, center.y, '#ff5500', 60, 1.8);

    let clearedCount = 0;
    const explosionRadius = BUBBLE_RADIUS * 6.5;

    for (let row = 0; row < GRID_ROWS; row++) {
      const cols = row % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let col = 0; col < cols; col++) {
        const b = newGrid[row][col];
        if (b) {
          const dist = getDistance(center.x, center.y, b.x, b.y);
          if (dist <= explosionRadius) {
            explode(b.x, b.y, palette[b.color] || '#ffffff', 12, 1.2);
            newGrid[row][col] = null;
            clearedCount++;
          }
        }
      }
    }

    newGrid[r][c] = null;
    const bonus = clearedCount * 20;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });

    return newGrid;
  }, [palette, onScoreChange]);

  const dropGrid = useCallback(() => {
    setGrid(oldGrid => {
      const newGrid: (Bubble | null)[][] = [];
      for (let r = 0; r < GRID_ROWS; r++) {
        newGrid[r] = [];
        const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
        if (r === 0) {
          for (let c = 0; c < colsInRow; c++) {
            newGrid[r][c] = generateBubble(r, c);
          }
        } else {
          const prevRow = oldGrid[r - 1];
          const prevCols = (r - 1) % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < colsInRow; c++) {
            const source = c < prevCols ? prevRow[c] : null;
            const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            if (source) {
              newGrid[r][c] = { ...source, x, y, row: r, col: c };
            } else {
              newGrid[r][c] = null;
            }
          }
        }
      }
      // Fail condition: bubble hits the danger zone
      if (newGrid[GRID_ROWS - 3].some(b => b !== null)) onGameOver(score);
      return newGrid;
    });
  }, [score, onGameOver, generateBubble]);

  const handleShoot = useCallback(() => {
    if (projectile) return;
    const dx = mousePos.current.x - SHOOTER_X;
    const dy = mousePos.current.y - SHOOTER_Y;
    const angle = Math.atan2(dy, dx);
    const speed = PROJECTILE_BASE_SPEED + (level * 0.3); // Slower scaling for readability

    explode(SHOOTER_X, SHOOTER_Y, palette[activeColor] || '#ffffff', 18, 0.9);
    setShake(5);

    setProjectile({
      x: SHOOTER_X, y: SHOOTER_Y, vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed, color: activeColor
    });
    audio.playShoot();
    setShotsTaken(prev => prev + 1);
    setActiveColor(nextColor);
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [projectile, activeColor, nextColor, level, palette, availableColors]);

  useEffect(() => {
    let animationFrameId: number;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const update = () => {
      setParticles(prev => prev.map(p => ({
        ...p, 
        x: p.x + p.vx, 
        y: p.y + p.vy, 
        life: p.life - (p.type === 'beam' ? 0.05 : 0.04)
      })).filter(p => p.life > 0));

      if (shake > 0) setShake(s => Math.max(0, s - 0.8));

      if (projectile) {
        // High-precision sub-stepping for fast projectiles
        const SUB_STEPS = 4;
        let collided = false;
        let hitBubble: Bubble | null = null;
        let bestR = -1;
        let bestC = -1;

        for (let i = 0; i < SUB_STEPS && !collided; i++) {
          projectile.x += projectile.vx / SUB_STEPS;
          projectile.y += projectile.vy / SUB_STEPS;

          if (projectile.x - BUBBLE_RADIUS < 0) {
            projectile.x = BUBBLE_RADIUS;
            projectile.vx *= -1;
          } else if (projectile.x + BUBBLE_RADIUS > CANVAS_WIDTH) {
            projectile.x = CANVAS_WIDTH - BUBBLE_RADIUS;
            projectile.vx *= -1;
          }

          if (projectile.y - BUBBLE_RADIUS < 0) {
            collided = true;
            let minD = Infinity;
            for (let c = 0; c < GRID_COLS; c++) {
              const sx = c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS;
              const d = Math.abs(projectile.x - sx);
              if (d < minD) { minD = d; bestR = 0; bestC = c; }
            }
          } else {
            for (let r = 0; r < GRID_ROWS; r++) {
              const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
              for (let c = 0; c < cols; c++) {
                const b = grid[r][c];
                if (b && getDistance(projectile.x, projectile.y, b.x, b.y) < BUBBLE_RADIUS * COLLISION_THRESHOLD) {
                  collided = true;
                  hitBubble = b;

                  let minD = Infinity;
                  const neighbors = getNeighbors(r, c);
                  for (const n of neighbors) {
                    if (!grid[n.r][n.c]) {
                      const nx = (n.r % 2 === 0 ? n.c * BUBBLE_RADIUS * 2 : n.c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
                      const ny = n.r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
                      const d = getDistance(projectile.x, projectile.y, nx, ny);
                      if (d < minD) { minD = d; bestR = n.r; bestC = n.c; }
                    }
                  }
                }
              }
            }
          }
        }

        if (collided) {
          let updatedGrid = [...grid.map(row => [...row])];

          if (hitBubble?.type === 'bomb') {
            updatedGrid = triggerBomb(hitBubble.row, hitBubble.col, updatedGrid);
          } else if (hitBubble?.type === 'laser') {
            updatedGrid = triggerLaser(hitBubble.row, updatedGrid);
          } else if (bestR !== -1) {
            const px = (bestR % 2 === 0 ? bestC * BUBBLE_RADIUS * 2 : bestC * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const py = bestR * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            updatedGrid[bestR][bestC] = { x: px, y: py, color: projectile.color, row: bestR, col: bestC, type: 'normal' };

            const matches: {r: number, c: number}[] = [{ r: bestR, c: bestC }];
            const visited = new Set<string>(); visited.add(`${bestR},${bestC}`);
            let mi = 0;
            while (mi < matches.length) {
              const curr = matches[mi++];
              for (const n of getNeighbors(curr.r, curr.c)) {
                const b = updatedGrid[n.r][n.c];
                if (b && b.color === projectile.color && b.type === 'normal' && !visited.has(`${n.r},${n.c}`)) {
                  visited.add(`${n.r},${n.c}`);
                  matches.push(n);
                }
              }
            }

            if (matches.length >= 3) {
              audio.playPop(450 + matches.length * 30);
              setShake(4 + matches.length * 0.7);
              matches.forEach(m => {
                const b = updatedGrid[m.r][m.c];
                if (b) explode(b.x, b.y, palette[b.color], 12, 1.3);
                updatedGrid[m.r][m.c] = null;
              });
              setScore(s => {
                const ns = s + matches.length * 20;
                onScoreChange(ns);
                return ns;
              });
            } else {
              audio.playShoot();
            }
          }

          const anchored = new Set<string>();
          const q: {r: number, c: number}[] = [];
          for (let c = 0; c < GRID_COLS; c++) { if (updatedGrid[0][c]) { anchored.add(`0,${c}`); q.push({ r: 0, c }); } }
          let qi = 0;
          while (qi < q.length) {
            const curr = q[qi++];
            for (const n of getNeighbors(curr.r, curr.c)) {
              if (updatedGrid[n.r][n.c] && !anchored.has(`${n.r},${n.c}`)) {
                anchored.add(`${n.r},${n.c}`); q.push(n);
              }
            }
          }
          let fallingCount = 0;
          for (let r = 0; r < GRID_ROWS; r++) {
            const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
            for (let c = 0; c < cols; c++) {
              if (updatedGrid[r][c] && !anchored.has(`${r},${c}`)) {
                const b = updatedGrid[r][c]!;
                explode(b.x, b.y, palette[b.color], 8, 1.1);
                updatedGrid[r][c] = null;
                fallingCount++;
                setScore(s => {
                  const ns = s + 30;
                  onScoreChange(ns);
                  return ns;
                });
              }
            }
          }
          if (fallingCount > 0) audio.playPop(380);

          setGrid(updatedGrid);
          setProjectile(null);

          if (shotsTaken > 0 && shotsTaken % currentLevelShotsToDrop === 0) {
            dropGrid();
            audio.playPop(250);
            setShake(6);
          }

          if (!updatedGrid.some(row => row.some(b => b !== null))) onWin();
          if (bestR >= GRID_ROWS - 3) onGameOver(score);
        }
      }
      render();
      animationFrameId = requestAnimationFrame(update);
    };

    const drawBubble = (b: Bubble, radius: number = BUBBLE_RADIUS, alpha: number = 1.0) => {
      const { x, y, color, type } = b;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.beginPath();
      ctx.arc(x, y, radius - 1, 0, Math.PI * 2);

      if (type === 'bomb') {
        ctx.fillStyle = '#1e1e2e';
        ctx.shadowBlur = 20;
        ctx.shadowColor = '#f97316';
      } else if (type === 'laser') {
        ctx.fillStyle = '#0f172a';
        ctx.shadowBlur = 20;
        ctx.shadowColor = '#38bdf8';
      } else {
        ctx.fillStyle = palette[color];
        ctx.shadowBlur = 14;
        ctx.shadowColor = palette[color];
      }
      ctx.fill();

      if (type === 'bomb') {
        ctx.fillStyle = '#f97316';
        ctx.beginPath();
        ctx.arc(x, y, radius / 2, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(x - 2, y - 10, 4, 12);
      } else if (type === 'laser') {
        ctx.strokeStyle = '#38bdf8';
        ctx.lineWidth = 5;
        ctx.beginPath();
        ctx.moveTo(x - radius/2, y);
        ctx.lineTo(x + radius/2, y);
        ctx.stroke();
      } else {
        ctx.beginPath();
        ctx.arc(x - radius/3, y - radius/3, radius/4, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255,255,255,0.5)';
        ctx.fill();
      }
      ctx.restore();
    };

    const render = () => {
      ctx.save();
      if (shake > 0) ctx.translate(Math.random() * shake - shake/2, Math.random() * shake - shake/2);
      ctx.clearRect(-40, -40, CANVAS_WIDTH + 80, CANVAS_HEIGHT + 80);

      // Danger Zone line
      ctx.beginPath();
      ctx.strokeStyle = 'rgba(244, 63, 94, 0.3)';
      ctx.setLineDash([5, 5]);
      const dangerY = (GRID_ROWS - 3) * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS * 2;
      ctx.moveTo(0, dangerY);
      ctx.lineTo(CANVAS_WIDTH, dangerY);
      ctx.stroke();
      ctx.setLineDash([]);

      grid.forEach(row => row.forEach(b => b && drawBubble(b)));

      const dx = mousePos.current.x - SHOOTER_X;
      const dy = mousePos.current.y - SHOOTER_Y;
      const angle = Math.atan2(dy, dx);
      ctx.beginPath();
      ctx.setLineDash([6, 8]);
      ctx.lineWidth = 2.5;
      ctx.moveTo(SHOOTER_X, SHOOTER_Y);
      ctx.lineTo(SHOOTER_X + Math.cos(angle) * 160, SHOOTER_Y + Math.sin(angle) * 160);
      ctx.strokeStyle = 'rgba(255,255,255,0.4)';
      ctx.stroke();
      ctx.setLineDash([]);

      if (projectile) {
        drawBubble({ x: projectile.x, y: projectile.y, color: projectile.color, row: 0, col: 0, type: 'normal' });
      }

      particles.forEach(p => {
        if (p.type === 'beam') {
          ctx.save();
          ctx.beginPath();
          ctx.fillStyle = `rgba(0, 255, 255, ${p.life})`;
          ctx.fillRect(0, p.y - 15, CANVAS_WIDTH, 30);
          ctx.fillStyle = `rgba(255, 255, 255, ${p.life * 1.8})`;
          ctx.fillRect(0, p.y - 5, CANVAS_WIDTH, 10);
          ctx.restore();
        } else {
          ctx.save();
          ctx.globalAlpha = p.life;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
          ctx.fillStyle = p.color;
          ctx.fill();
          ctx.restore();
        }
      });

      const dropsIn = currentLevelShotsToDrop - (shotsTaken % currentLevelShotsToDrop);
      ctx.fillStyle = dropsIn <= 1 ? 'rgba(244, 63, 94, 1.0)' : 'rgba(255, 255, 255, 0.5)';
      ctx.font = '900 13px Inter';
      ctx.textAlign = 'left';
      ctx.fillText(`THREAT IN: ${dropsIn}`, 20, CANVAS_HEIGHT - 20);

      drawBubble({ x: SHOOTER_X, y: SHOOTER_Y, color: activeColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS + 4);
      drawBubble({ x: SHOOTER_X + 80, y: SHOOTER_Y + 15, color: nextColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS * 0.8);

      ctx.fillStyle = 'rgba(255,255,255,0.7)';
      ctx.font = '900 12px Inter';
      ctx.textAlign = 'center';
      ctx.fillText('NEXT', SHOOTER_X + 80, SHOOTER_Y + 45);
      ctx.restore();
    };

    update();
    return () => cancelAnimationFrame(animationFrameId);
  }, [grid, projectile, activeColor, nextColor, particles, onGameOver, onScoreChange, onWin, score, palette, shotsTaken, dropGrid, triggerBomb, triggerLaser, shake, level, currentLevelShotsToDrop]);

  const handlePointer = (e: React.PointerEvent) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    mousePos.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onPointerMove={handlePointer}
      onPointerDown={(e) => { handlePointer(e); handleShoot(); }}
      className="w-full h-full cursor-crosshair touch-none select-none"
    />
  );
};

export default GameBoard;

import { BubbleColor } from './types';

export const CANVAS_WIDTH = 400;
export const CANVAS_HEIGHT = 600;

export const BUBBLE_RADIUS = 20;
export const GRID_ROWS = 14; 
export const GRID_COLS = 8;

export const BUBBLE_COLORS: BubbleColor[] = ['rose', 'amber', 'lime', 'sky', 'violet', 'fuchsia'];

export const COLOR_PALETTES: Record<BubbleColor, string>[] = [
  { // Standard Neon
    rose: '#f43f5e',
    amber: '#f59e0b',
    lime: '#84cc16',
    sky: '#0ea5e9',
    violet: '#8b5cf6',
    fuchsia: '#d946ef'
  },
  { // Cyberpunk Night
    rose: '#ff0055',
    amber: '#ffcc00',
    lime: '#00ff66',
    sky: '#00ffff',
    violet: '#9900ff',
    fuchsia: '#ff00ff'
  },
  { // Retro Sunset
    rose: '#ef4444',
    amber: '#f97316',
    lime: '#fbbf24',
    sky: '#38bdf8',
    violet: '#818cf8',
    fuchsia: '#c084fc'
  },
  { // Arctic Pulse
    rose: '#fb7185',
    amber: '#fbbf24',
    lime: '#4ade80',
    sky: '#22d3ee',
    violet: '#a78bfa',
    fuchsia: '#f472b6'
  }
];

export const POWER_UP_CHANCE_BASE = 0.08;
export const SHOOTER_Y = CANVAS_HEIGHT - 60;
export const SHOOTER_X = CANVAS_WIDTH / 2;

// Difficulty Scaling Settings
export const MIN_SHOTS_TO_DROP = 3;
export const MAX_SHOTS_TO_DROP = 7;
export const PROJECTILE_BASE_SPEED = 8; // Further reduced for clarity
export const COLLISION_THRESHOLD = 1.85;

import React, { useRef, useEffect, useState, useCallback, useMemo } from 'react';
import { Bubble, BubbleColor, Projectile, Particle, BubbleType } from '../types';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, BUBBLE_RADIUS, GRID_ROWS, GRID_COLS, 
  COLOR_PALETTES, BUBBLE_COLORS, SHOOTER_X, SHOOTER_Y, 
  POWER_UP_CHANCE_BASE, PROJECTILE_BASE_SPEED, COLLISION_THRESHOLD,
  MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP
} from '../constants';
import { audio } from '../services/audioService';

interface GameBoardProps {
  level: number;
  onScoreChange: (score: number) => void;
  onGameOver: (score: number) => void;
  onWin: () => void;
}

const GameBoard: React.FC<GameBoardProps> = ({ level, onScoreChange, onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [score, setScore] = useState(0);
  const [grid, setGrid] = useState<(Bubble | null)[][]>([]);
  const [projectile, setProjectile] = useState<Projectile | null>(null);
  const [nextColor, setNextColor] = useState<BubbleColor>(BUBBLE_COLORS[0]);
  const [activeColor, setActiveColor] = useState<BubbleColor>(BUBBLE_COLORS[1]);
  const [particles, setParticles] = useState<Particle[]>([]);
  const [shotsTaken, setShotsTaken] = useState(0);
  const [shake, setShake] = useState(0);

  const mousePos = useRef({ x: SHOOTER_X, y: 0 });
  const palette = COLOR_PALETTES[(level - 1) % COLOR_PALETTES.length];

  // Dynamic Difficulty Calculations
  const currentLevelShotsToDrop = useMemo(() => 
    Math.max(MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP - Math.floor((level - 1) / 3)), 
  [level]);

  const activeColorCount = useMemo(() => 
    Math.min(6, 4 + Math.floor((level - 1) / 2)), 
  [level]);

  const availableColors = useMemo(() => 
    BUBBLE_COLORS.slice(0, activeColorCount), 
  [activeColorCount]);

  const generateBubble = useCallback((r: number, c: number): Bubble => {
    const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
    const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;

    // Power-up chance increases slightly with level to compensate for difficulty
    const powerUpChance = POWER_UP_CHANCE_BASE + (level * 0.005);
    const isPowerUp = Math.random() < powerUpChance;
    const type: BubbleType = isPowerUp ? (Math.random() > 0.5 ? 'bomb' : 'laser') : 'normal';

    return { 
      x, y, 
      color: availableColors[Math.floor(Math.random() * availableColors.length)],
      row: r,
      col: c,
      type
    };
  }, [availableColors, level]);

  useEffect(() => {
    const startRows = Math.min(GRID_ROWS - 4, 5 + Math.floor(level / 2));
    const newGrid: (Bubble | null)[][] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      newGrid[r] = [];
      const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < colsInRow; c++) {
        if (r < startRows) {
          newGrid[r][c] = generateBubble(r, c);
        } else {
          newGrid[r][c] = null;
        }
      }
    }
    setGrid(newGrid);
    setShotsTaken(0);
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
    setActiveColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [level, generateBubble, availableColors]);

  const getDistance = (x1: number, y1: number, x2: number, y2: number) => {
    return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);
  };

  const getNeighbors = (r: number, c: number) => {
    const neighbors: { r: number, c: number }[] = [];
    const offsets = r % 2 === 0 
      ? [{ dr: -1, dc: -1 }, { dr: -1, dc: 0 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: -1 }, { dr: 1, dc: 0 }]
      : [{ dr: -1, dc: 0 }, { dr: -1, dc: 1 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: 0 }, { dr: 1, dc: 1 }];

    for (const off of offsets) {
      const nr = r + off.dr;
      const nc = c + off.dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
        neighbors.push({ r: nr, c: nc });
      }
    }
    return neighbors;
  };

  const explode = (x: number, y: number, color: string, count: number = 8, velocityMult: number = 1.0) => {
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      newParticles.push({
        x, y,
        vx: (Math.random() - 0.5) * 16 * velocityMult,
        vy: (Math.random() - 0.5) * 16 * velocityMult,
        radius: Math.random() * 5 + 1.5,
        color,
        life: 1.0
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
  };

  const triggerLaser = useCallback((r: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
    let clearedCount = 0;

    audio.playLaser();
    setShake(10);

    setParticles(prev => [...prev, {
      x: CANVAS_WIDTH / 2,
      y: r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS,
      vx: 0, vy: 0, radius: 28, color: '#00ffff', life: 0.7, type: 'beam'
    }]);

    for (let c = 0; c < colsInRow; c++) {
      if (newGrid[r][c]) {
        const b = newGrid[r][c]!;
        explode(b.x, b.y, '#ffffff', 16, 1.4);
        newGrid[r][c] = null;
        clearedCount++;
      }
    }
    const bonus = clearedCount * 25;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });
    return newGrid;
  }, [onScoreChange]);

  const triggerBomb = useCallback((r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const center = newGrid[r][c];
    if (!center) return newGrid;

    audio.playBomb();
    setShake(30);
    explode(center.x, center.y, '#ff5500', 60, 1.8);

    let clearedCount = 0;
    const explosionRadius = BUBBLE_RADIUS * 6.5;

    for (let row = 0; row < GRID_ROWS; row++) {
      const cols = row % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let col = 0; col < cols; col++) {
        const b = newGrid[row][col];
        if (b) {
          const dist = getDistance(center.x, center.y, b.x, b.y);
          if (dist <= explosionRadius) {
            explode(b.x, b.y, palette[b.color] || '#ffffff', 12, 1.2);
            newGrid[row][col] = null;
            clearedCount++;
          }
        }
      }
    }

    newGrid[r][c] = null;
    const bonus = clearedCount * 20;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });

    return newGrid;
  }, [palette, onScoreChange]);

  const dropGrid = useCallback(() => {
    setGrid(oldGrid => {
      const newGrid: (Bubble | null)[][] = [];
      for (let r = 0; r < GRID_ROWS; r++) {
        newGrid[r] = [];
        const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
        if (r === 0) {
          for (let c = 0; c < colsInRow; c++) {
            newGrid[r][c] = generateBubble(r, c);
          }
        } else {
          const prevRow = oldGrid[r - 1];
          const prevCols = (r - 1) % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < colsInRow; c++) {
            const source = c < prevCols ? prevRow[c] : null;
            const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            if (source) {
              newGrid[r][c] = { ...source, x, y, row: r, col: c };
            } else {
              newGrid[r][c] = null;
            }
          }
        }
      }
      // Fail condition: bubble hits the danger zone
      if (newGrid[GRID_ROWS - 3].some(b => b !== null)) onGameOver(score);
      return newGrid;
    });
  }, [score, onGameOver, generateBubble]);

  const handleShoot = useCallback(() => {
    if (projectile) return;
    const dx = mousePos.current.x - SHOOTER_X;
    const dy = mousePos.current.y - SHOOTER_Y;
    const angle = Math.atan2(dy, dx);
    const speed = PROJECTILE_BASE_SPEED + (level * 0.15); // Gentler scaling for a smooth feel

    explode(SHOOTER_X, SHOOTER_Y, palette[activeColor] || '#ffffff', 18, 0.9);
    setShake(5);

    setProjectile({
      x: SHOOTER_X, y: SHOOTER_Y, vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed, color: activeColor
    });
    audio.playShoot();
    setShotsTaken(prev => prev + 1);
    setActiveColor(nextColor);
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [projectile, activeColor, nextColor, level, palette, availableColors]);

  useEffect(() => {
    let animationFrameId: number;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const update = () => {
      setParticles(prev => prev.map(p => ({
        ...p, 
        x: p.x + p.vx, 
        y: p.y + p.vy, 
        life: p.life - (p.type === 'beam' ? 0.05 : 0.04)
      })).filter(p => p.life > 0));

      if (shake > 0) setShake(s => Math.max(0, s - 0.8));

      if (projectile) {
        // High-precision sub-stepping for reliable collisions even at lower speeds
        const SUB_STEPS = 4;
        let collided = false;
        let hitBubble: Bubble | null = null;
        let bestR = -1;
        let bestC = -1;

        for (let i = 0; i < SUB_STEPS && !collided; i++) {
          projectile.x += projectile.vx / SUB_STEPS;
          projectile.y += projectile.vy / SUB_STEPS;

          if (projectile.x - BUBBLE_RADIUS < 0) {
            projectile.x = BUBBLE_RADIUS;
            projectile.vx *= -1;
          } else if (projectile.x + BUBBLE_RADIUS > CANVAS_WIDTH) {
            projectile.x = CANVAS_WIDTH - BUBBLE_RADIUS;
            projectile.vx *= -1;
          }

          if (projectile.y - BUBBLE_RADIUS < 0) {
            collided = true;
            let minD = Infinity;
            for (let c = 0; c < GRID_COLS; c++) {
              const sx = c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS;
              const d = Math.abs(projectile.x - sx);
              if (d < minD) { minD = d; bestR = 0; bestC = c; }
            }
          } else {
            for (let r = 0; r < GRID_ROWS; r++) {
              const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
              for (let c = 0; c < cols; c++) {
                const b = grid[r][c];
                if (b && getDistance(projectile.x, projectile.y, b.x, b.y) < BUBBLE_RADIUS * COLLISION_THRESHOLD) {
                  collided = true;
                  hitBubble = b;

                  let minD = Infinity;
                  const neighbors = getNeighbors(r, c);
                  for (const n of neighbors) {
                    if (!grid[n.r][n.c]) {
                      const nx = (n.r % 2 === 0 ? n.c * BUBBLE_RADIUS * 2 : n.c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
                      const ny = n.r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
                      const d = getDistance(projectile.x, projectile.y, nx, ny);
                      if (d < minD) { minD = d; bestR = n.r; bestC = n.c; }
                    }
                  }
                }
              }
            }
          }
        }

        if (collided) {
          let updatedGrid = [...grid.map(row => [...row])];

          if (hitBubble?.type === 'bomb') {
            updatedGrid = triggerBomb(hitBubble.row, hitBubble.col, updatedGrid);
          } else if (hitBubble?.type === 'laser') {
            updatedGrid = triggerLaser(hitBubble.row, updatedGrid);
          } else if (bestR !== -1) {
            const px = (bestR % 2 === 0 ? bestC * BUBBLE_RADIUS * 2 : bestC * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const py = bestR * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            updatedGrid[bestR][bestC] = { x: px, y: py, color: projectile.color, row: bestR, col: bestC, type: 'normal' };

            const matches: {r: number, c: number}[] = [{ r: bestR, c: bestC }];
            const visited = new Set<string>(); visited.add(`${bestR},${bestC}`);
            let mi = 0;
            while (mi < matches.length) {
              const curr = matches[mi++];
              for (const n of getNeighbors(curr.r, curr.c)) {
                const b = updatedGrid[n.r][n.c];
                if (b && b.color === projectile.color && b.type === 'normal' && !visited.has(`${n.r},${n.c}`)) {
                  visited.add(`${n.r},${n.c}`);
                  matches.push(n);
                }
              }
            }

            if (matches.length >= 3) {
              audio.playPop(450 + matches.length * 30);
              setShake(4 + matches.length * 0.7);
              matches.forEach(m => {
                const b = updatedGrid[m.r][m.c];
                if (b) explode(b.x, b.y, palette[b.color], 12, 1.3);
                updatedGrid[m.r][m.c] = null;
              });
              setScore(s => {
                const ns = s + matches.length * 20;
                onScoreChange(ns);
                return ns;
              });
            } else {
              audio.playShoot();
            }
          }

          const anchored = new Set<string>();
          const q: {r: number, c: number}[] = [];
          for (let c = 0; c < GRID_COLS; c++) { if (updatedGrid[0][c]) { anchored.add(`0,${c}`); q.push({ r: 0, c }); } }
          let qi = 0;
          while (qi < q.length) {
            const curr = q[qi++];
            for (const n of getNeighbors(curr.r, curr.c)) {
              if (updatedGrid[n.r][n.c] && !anchored.has(`${n.r},${n.c}`)) {
                anchored.add(`${n.r},${n.c}`); q.push(n);
              }
            }
          }
          let fallingCount = 0;
          for (let r = 0; r < GRID_ROWS; r++) {
            const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
            for (let c = 0; c < cols; c++) {
              if (updatedGrid[r][c] && !anchored.has(`${r},${c}`)) {
                const b = updatedGrid[r][c]!;
                explode(b.x, b.y, palette[b.color], 8, 1.1);
                updatedGrid[r][c] = null;
                fallingCount++;
                setScore(s => {
                  const ns = s + 30;
                  onScoreChange(ns);
                  return ns;
                });
              }
            }
          }
          if (fallingCount > 0) audio.playPop(380);

          setGrid(updatedGrid);
          setProjectile(null);

          if (shotsTaken > 0 && shotsTaken % currentLevelShotsToDrop === 0) {
            dropGrid();
            audio.playPop(250);
            setShake(6);
          }

          if (!updatedGrid.some(row => row.some(b => b !== null))) onWin();
          if (bestR >= GRID_ROWS - 3) onGameOver(score);
        }
      }
      render();
      animationFrameId = requestAnimationFrame(update);
    };

    const drawBubble = (b: Bubble, radius: number = BUBBLE_RADIUS, alpha: number = 1.0) => {
      const { x, y, color, type } = b;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.beginPath();
      ctx.arc(x, y, radius - 1, 0, Math.PI * 2);

      if (type === 'bomb') {
        ctx.fillStyle = '#1e1e2e';
        ctx.shadowBlur = 20;
        ctx.shadowColor = '#f97316';
      } else if (type === 'laser') {
        ctx.fillStyle = '#0f172a';
        ctx.shadowBlur = 20;
        ctx.shadowColor = '#38bdf8';
      } else {
        ctx.fillStyle = palette[color];
        ctx.shadowBlur = 14;
        ctx.shadowColor = palette[color];
      }
      ctx.fill();

      if (type === 'bomb') {
        ctx.fillStyle = '#f97316';
        ctx.beginPath();
        ctx.arc(x, y, radius / 2, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(x - 2, y - 10, 4, 12);
      } else if (type === 'laser') {
        ctx.strokeStyle = '#38bdf8';
        ctx.lineWidth = 5;
        ctx.beginPath();
        ctx.moveTo(x - radius/2, y);
        ctx.lineTo(x + radius/2, y);
        ctx.stroke();
      } else {
        ctx.beginPath();
        ctx.arc(x - radius/3, y - radius/3, radius/4, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255,255,255,0.5)';
        ctx.fill();
      }
      ctx.restore();
    };

    const render = () => {
      ctx.save();
      if (shake > 0) ctx.translate(Math.random() * shake - shake/2, Math.random() * shake - shake/2);
      ctx.clearRect(-40, -40, CANVAS_WIDTH + 80, CANVAS_HEIGHT + 80);

      // Danger Zone line
      ctx.beginPath();
      ctx.strokeStyle = 'rgba(244, 63, 94, 0.3)';
      ctx.setLineDash([5, 5]);
      const dangerY = (GRID_ROWS - 3) * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS * 2;
      ctx.moveTo(0, dangerY);
      ctx.lineTo(CANVAS_WIDTH, dangerY);
      ctx.stroke();
      ctx.setLineDash([]);

      grid.forEach(row => row.forEach(b => b && drawBubble(b)));

      const dx = mousePos.current.x - SHOOTER_X;
      const dy = mousePos.current.y - SHOOTER_Y;
      const angle = Math.atan2(dy, dx);
      ctx.beginPath();
      ctx.setLineDash([6, 8]);
      ctx.lineWidth = 2.5;
      ctx.moveTo(SHOOTER_X, SHOOTER_Y);
      ctx.lineTo(SHOOTER_X + Math.cos(angle) * 160, SHOOTER_Y + Math.sin(angle) * 160);
      ctx.strokeStyle = 'rgba(255,255,255,0.4)';
      ctx.stroke();
      ctx.setLineDash([]);

      if (projectile) {
        drawBubble({ x: projectile.x, y: projectile.y, color: projectile.color, row: 0, col: 0, type: 'normal' });
      }

      particles.forEach(p => {
        if (p.type === 'beam') {
          ctx.save();
          ctx.beginPath();
          ctx.fillStyle = `rgba(0, 255, 255, ${p.life})`;
          ctx.fillRect(0, p.y - 15, CANVAS_WIDTH, 30);
          ctx.fillStyle = `rgba(255, 255, 255, ${p.life * 1.8})`;
          ctx.fillRect(0, p.y - 5, CANVAS_WIDTH, 10);
          ctx.restore();
        } else {
          ctx.save();
          ctx.globalAlpha = p.life;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
          ctx.fillStyle = p.color;
          ctx.fill();
          ctx.restore();
        }
      });

      const dropsIn = currentLevelShotsToDrop - (shotsTaken % currentLevelShotsToDrop);
      ctx.fillStyle = dropsIn <= 1 ? 'rgba(244, 63, 94, 1.0)' : 'rgba(255, 255, 255, 0.5)';
      ctx.font = '900 13px Inter';
      ctx.textAlign = 'left';
      ctx.fillText(`THREAT IN: ${dropsIn}`, 20, CANVAS_HEIGHT - 20);

      drawBubble({ x: SHOOTER_X, y: SHOOTER_Y, color: activeColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS + 4);
      drawBubble({ x: SHOOTER_X + 80, y: SHOOTER_Y + 15, color: nextColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS * 0.8);

      ctx.fillStyle = 'rgba(255,255,255,0.7)';
      ctx.font = '900 12px Inter';
      ctx.textAlign = 'center';
      ctx.fillText('NEXT', SHOOTER_X + 80, SHOOTER_Y + 45);
      ctx.restore();
    };

    update();
    return () => cancelAnimationFrame(animationFrameId);
  }, [grid, projectile, activeColor, nextColor, particles, onGameOver, onScoreChange, onWin, score, palette, shotsTaken, dropGrid, triggerBomb, triggerLaser, shake, level, currentLevelShotsToDrop]);

  const handlePointer = (e: React.PointerEvent) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    mousePos.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onPointerMove={handlePointer}
      onPointerDown={(e) => { handlePointer(e); handleShoot(); }}
      className="w-full h-full cursor-crosshair touch-none select-none"
    />
  );
};

export default GameBoard;

import React, { useRef, useEffect, useState, useCallback, useMemo } from 'react';
import { Bubble, BubbleColor, Projectile, Particle, BubbleType } from '../types';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, BUBBLE_RADIUS, GRID_ROWS, GRID_COLS, 
  COLOR_PALETTES, BUBBLE_COLORS, SHOOTER_X, SHOOTER_Y, 
  POWER_UP_CHANCE_BASE, PROJECTILE_BASE_SPEED, COLLISION_THRESHOLD,
  MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP
} from '../constants';
import { audio } from '../services/audioService';

interface GameBoardProps {
  level: number;
  onScoreChange: (score: number) => void;
  onGameOver: (score: number) => void;
  onWin: () => void;
}

const GameBoard: React.FC<GameBoardProps> = ({ level, onScoreChange, onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [score, setScore] = useState(0);
  const [grid, setGrid] = useState<(Bubble | null)[][]>([]);
  const [projectile, setProjectile] = useState<Projectile | null>(null);
  const [nextColor, setNextColor] = useState<BubbleColor>(BUBBLE_COLORS[0]);
  const [activeColor, setActiveColor] = useState<BubbleColor>(BUBBLE_COLORS[1]);
  const [particles, setParticles] = useState<Particle[]>([]);
  const [shotsTaken, setShotsTaken] = useState(0);
  const [shake, setShake] = useState(0);

  const mousePos = useRef({ x: SHOOTER_X, y: 0 });
  const palette = COLOR_PALETTES[(level - 1) % COLOR_PALETTES.length];

  // Dynamic Difficulty Calculations
  const currentLevelShotsToDrop = useMemo(() => 
    Math.max(MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP - Math.floor((level - 1) / 3)), 
  [level]);

  const activeColorCount = useMemo(() => 
    Math.min(6, 4 + Math.floor((level - 1) / 2)), 
  [level]);

  const availableColors = useMemo(() => 
    BUBBLE_COLORS.slice(0, activeColorCount), 
  [activeColorCount]);

  const generateBubble = useCallback((r: number, c: number): Bubble => {
    const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
    const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;

    // Power-up chance increases slightly with level to compensate for difficulty
    const powerUpChance = POWER_UP_CHANCE_BASE + (level * 0.005);
    const isPowerUp = Math.random() < powerUpChance;
    const type: BubbleType = isPowerUp ? (Math.random() > 0.5 ? 'bomb' : 'laser') : 'normal';

    return { 
      x, y, 
      color: availableColors[Math.floor(Math.random() * availableColors.length)],
      row: r,
      col: c,
      type
    };
  }, [availableColors, level]);

  useEffect(() => {
    const startRows = Math.min(GRID_ROWS - 4, 5 + Math.floor(level / 2));
    const newGrid: (Bubble | null)[][] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      newGrid[r] = [];
      const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < colsInRow; c++) {
        if (r < startRows) {
          newGrid[r][c] = generateBubble(r, c);
        } else {
          newGrid[r][c] = null;
        }
      }
    }
    setGrid(newGrid);
    setShotsTaken(0);
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
    setActiveColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [level, generateBubble, availableColors]);

  const getDistance = (x1: number, y1: number, x2: number, y2: number) => {
    return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);
  };

  const getNeighbors = (r: number, c: number) => {
    const neighbors: { r: number, c: number }[] = [];
    const offsets = r % 2 === 0 
      ? [{ dr: -1, dc: -1 }, { dr: -1, dc: 0 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: -1 }, { dr: 1, dc: 0 }]
      : [{ dr: -1, dc: 0 }, { dr: -1, dc: 1 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: 0 }, { dr: 1, dc: 1 }];

    for (const off of offsets) {
      const nr = r + off.dr;
      const nc = c + off.dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
        neighbors.push({ r: nr, c: nc });
      }
    }
    return neighbors;
  };

  const explode = (x: number, y: number, color: string, count: number = 12, velocityMult: number = 1.0) => {
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      newParticles.push({
        x, y,
        vx: (Math.random() - 0.5) * 12 * velocityMult,
        vy: (Math.random() - 0.5) * 12 * velocityMult,
        radius: Math.random() * 5 + 1.5,
        color,
        life: 1.0
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
  };

  const triggerLaser = useCallback((r: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
    let clearedCount = 0;

    audio.playLaser();
    setShake(10);

    setParticles(prev => [...prev, {
      x: CANVAS_WIDTH / 2,
      y: r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS,
      vx: 0, vy: 0, radius: 28, color: '#00ffff', life: 1.0, type: 'beam'
    }]);

    for (let c = 0; c < colsInRow; c++) {
      if (newGrid[r][c]) {
        const b = newGrid[r][c]!;
        explode(b.x, b.y, '#ffffff', 16, 1.4);
        newGrid[r][c] = null;
        clearedCount++;
      }
    }
    const bonus = clearedCount * 25;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });
    return newGrid;
  }, [onScoreChange]);

  const triggerBomb = useCallback((r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const center = newGrid[r][c];
    if (!center) return newGrid;

    audio.playBomb();
    setShake(30);
    explode(center.x, center.y, '#ff5500', 60, 1.8);

    let clearedCount = 0;
    const explosionRadius = BUBBLE_RADIUS * 6.5;

    for (let row = 0; row < GRID_ROWS; row++) {
      const cols = row % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let col = 0; col < cols; col++) {
        const b = newGrid[row][col];
        if (b) {
          const dist = getDistance(center.x, center.y, b.x, b.y);
          if (dist <= explosionRadius) {
            explode(b.x, b.y, palette[b.color] || '#ffffff', 12, 1.2);
            newGrid[row][col] = null;
            clearedCount++;
          }
        }
      }
    }

    newGrid[r][c] = null;
    const bonus = clearedCount * 20;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });

    return newGrid;
  }, [palette, onScoreChange]);

  const dropGrid = useCallback(() => {
    setGrid(oldGrid => {
      const newGrid: (Bubble | null)[][] = [];
      for (let r = 0; r < GRID_ROWS; r++) {
        newGrid[r] = [];
        const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
        if (r === 0) {
          for (let c = 0; c < colsInRow; c++) {
            newGrid[r][c] = generateBubble(r, c);
          }
        } else {
          const prevRow = oldGrid[r - 1];
          const prevCols = (r - 1) % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < colsInRow; c++) {
            const source = c < prevCols ? prevRow[c] : null;
            const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            if (source) {
              newGrid[r][c] = { ...source, x, y, row: r, col: c };
            } else {
              newGrid[r][c] = null;
            }
          }
        }
      }
      // Fail condition: bubble hits the danger zone
      if (newGrid[GRID_ROWS - 3].some(b => b !== null)) onGameOver(score);
      return newGrid;
    });
  }, [score, onGameOver, generateBubble]);

  const handleShoot = useCallback(() => {
    if (projectile) return;
    const dx = mousePos.current.x - SHOOTER_X;
    const dy = mousePos.current.y - SHOOTER_Y;
    const angle = Math.atan2(dy, dx);
    const speed = PROJECTILE_BASE_SPEED + (level * 0.15); // Gentler scaling for a smooth feel

    explode(SHOOTER_X, SHOOTER_Y, palette[activeColor] || '#ffffff', 18, 0.9);
    setShake(5);

    setProjectile({
      x: SHOOTER_X, y: SHOOTER_Y, vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed, color: activeColor
    });
    audio.playShoot();
    setShotsTaken(prev => prev + 1);
    setActiveColor(nextColor);
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [projectile, activeColor, nextColor, level, palette, availableColors]);

  useEffect(() => {
    let animationFrameId: number;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const update = () => {
      // Particles updated with friction and slower life decay for better visual tracking
      setParticles(prev => prev.map(p => ({
        ...p, 
        x: p.x + p.vx, 
        y: p.y + p.vy, 
        vx: p.vx * 0.97, // Friction slows down particles over time
        vy: p.vy * 0.97, 
        life: p.life - (p.type === 'beam' ? 0.02 : 0.015) // Much slower decay
      })).filter(p => p.life > 0));

      // Slower shake decay for a more impactful feeling
      if (shake > 0) setShake(s => Math.max(0, s - 0.4));

      if (projectile) {
        // High-precision sub-stepping for reliable collisions even at lower speeds
        const SUB_STEPS = 4;
        let collided = false;
        let hitBubble: Bubble | null = null;
        let bestR = -1;
        let bestC = -1;

        for (let i = 0; i < SUB_STEPS && !collided; i++) {
          projectile.x += projectile.vx / SUB_STEPS;
          projectile.y += projectile.vy / SUB_STEPS;

          if (projectile.x - BUBBLE_RADIUS < 0) {
            projectile.x = BUBBLE_RADIUS;
            projectile.vx *= -1;
          } else if (projectile.x + BUBBLE_RADIUS > CANVAS_WIDTH) {
            projectile.x = CANVAS_WIDTH - BUBBLE_RADIUS;
            projectile.vx *= -1;
          }

          if (projectile.y - BUBBLE_RADIUS < 0) {
            collided = true;
            let minD = Infinity;
            for (let c = 0; c < GRID_COLS; c++) {
              const sx = c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS;
              const d = Math.abs(projectile.x - sx);
              if (d < minD) { minD = d; bestR = 0; bestC = c; }
            }
          } else {
            for (let r = 0; r < GRID_ROWS; r++) {
              const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
              for (let c = 0; c < cols; c++) {
                const b = grid[r][c];
                if (b && getDistance(projectile.x, projectile.y, b.x, b.y) < BUBBLE_RADIUS * COLLISION_THRESHOLD) {
                  collided = true;
                  hitBubble = b;

                  let minD = Infinity;
                  const neighbors = getNeighbors(r, c);
                  for (const n of neighbors) {
                    if (!grid[n.r][n.c]) {
                      const nx = (n.r % 2 === 0 ? n.c * BUBBLE_RADIUS * 2 : n.c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
                      const ny = n.r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
                      const d = getDistance(projectile.x, projectile.y, nx, ny);
                      if (d < minD) { minD = d; bestR = n.r; bestC = n.c; }
                    }
                  }
                }
              }
            }
          }
        }

        if (collided) {
          let updatedGrid = [...grid.map(row => [...row])];

          if (hitBubble?.type === 'bomb') {
            updatedGrid = triggerBomb(hitBubble.row, hitBubble.col, updatedGrid);
          } else if (hitBubble?.type === 'laser') {
            updatedGrid = triggerLaser(hitBubble.row, updatedGrid);
          } else if (bestR !== -1) {
            const px = (bestR % 2 === 0 ? bestC * BUBBLE_RADIUS * 2 : bestC * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const py = bestR * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            updatedGrid[bestR][bestC] = { x: px, y: py, color: projectile.color, row: bestR, col: bestC, type: 'normal' };

            const matches: {r: number, c: number}[] = [{ r: bestR, c: bestC }];
            const visited = new Set<string>(); visited.add(`${bestR},${bestC}`);
            let mi = 0;
            while (mi < matches.length) {
              const curr = matches[mi++];
              for (const n of getNeighbors(curr.r, curr.c)) {
                const b = updatedGrid[n.r][n.c];
                if (b && b.color === projectile.color && b.type === 'normal' && !visited.has(`${n.r},${n.c}`)) {
                  visited.add(`${n.r},${n.c}`);
                  matches.push(n);
                }
              }
            }

            if (matches.length >= 3) {
              audio.playPop(450 + matches.length * 30);
              setShake(4 + matches.length * 0.7);
              matches.forEach(m => {
                const b = updatedGrid[m.r][m.c];
                if (b) explode(b.x, b.y, palette[b.color], 16, 1.1); // More particles per pop
                updatedGrid[m.r][m.c] = null;
              });
              setScore(s => {
                const ns = s + matches.length * 20;
                onScoreChange(ns);
                return ns;
              });
            } else {
              audio.playShoot();
            }
          }

          const anchored = new Set<string>();
          const q: {r: number, c: number}[] = [];
          for (let c = 0; c < GRID_COLS; c++) { if (updatedGrid[0][c]) { anchored.add(`0,${c}`); q.push({ r: 0, c }); } }
          let qi = 0;
          while (qi < q.length) {
            const curr = q[qi++];
            for (const n of getNeighbors(curr.r, curr.c)) {
              if (updatedGrid[n.r][n.c] && !anchored.has(`${n.r},${n.c}`)) {
                anchored.add(`${n.r},${n.c}`); q.push(n);
              }
            }
          }
          let fallingCount = 0;
          for (let r = 0; r < GRID_ROWS; r++) {
            const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
            for (let c = 0; c < cols; c++) {
              if (updatedGrid[r][c] && !anchored.has(`${r},${c}`)) {
                const b = updatedGrid[r][c]!;
                explode(b.x, b.y, palette[b.color], 10, 0.9);
                updatedGrid[r][c] = null;
                fallingCount++;
                setScore(s => {
                  const ns = s + 30;
                  onScoreChange(ns);
                  return ns;
                });
              }
            }
          }
          if (fallingCount > 0) audio.playPop(380);

          setGrid(updatedGrid);
          setProjectile(null);

          if (shotsTaken > 0 && shotsTaken % currentLevelShotsToDrop === 0) {
            dropGrid();
            audio.playPop(250);
            setShake(6);
          }

          if (!updatedGrid.some(row => row.some(b => b !== null))) onWin();
          if (bestR >= GRID_ROWS - 3) onGameOver(score);
        }
      }
      render();
      animationFrameId = requestAnimationFrame(update);
    };

    const drawBubble = (b: Bubble, radius: number = BUBBLE_RADIUS, alpha: number = 1.0) => {
      const { x, y, color, type } = b;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.beginPath();
      ctx.arc(x, y, radius - 1, 0, Math.PI * 2);

      if (type === 'bomb') {
        ctx.fillStyle = '#1e1e2e';
        ctx.shadowBlur = 20;
        ctx.shadowColor = '#f97316';
      } else if (type === 'laser') {
        ctx.fillStyle = '#0f172a';
        ctx.shadowBlur = 20;
        ctx.shadowColor = '#38bdf8';
      } else {
        ctx.fillStyle = palette[color];
        ctx.shadowBlur = 14;
        ctx.shadowColor = palette[color];
      }
      ctx.fill();

      if (type === 'bomb') {
        ctx.fillStyle = '#f97316';
        ctx.beginPath();
        ctx.arc(x, y, radius / 2, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(x - 2, y - 10, 4, 12);
      } else if (type === 'laser') {
        ctx.strokeStyle = '#38bdf8';
        ctx.lineWidth = 5;
        ctx.beginPath();
        ctx.moveTo(x - radius/2, y);
        ctx.lineTo(x + radius/2, y);
        ctx.stroke();
      } else {
        ctx.beginPath();
        ctx.arc(x - radius/3, y - radius/3, radius/4, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255,255,255,0.5)';
        ctx.fill();
      }
      ctx.restore();
    };

    const render = () => {
      ctx.save();
      if (shake > 0) ctx.translate(Math.random() * shake - shake/2, Math.random() * shake - shake/2);
      ctx.clearRect(-40, -40, CANVAS_WIDTH + 80, CANVAS_HEIGHT + 80);

      // Danger Zone line
      ctx.beginPath();
      ctx.strokeStyle = 'rgba(244, 63, 94, 0.3)';
      ctx.setLineDash([5, 5]);
      const dangerY = (GRID_ROWS - 3) * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS * 2;
      ctx.moveTo(0, dangerY);
      ctx.lineTo(CANVAS_WIDTH, dangerY);
      ctx.stroke();
      ctx.setLineDash([]);

      grid.forEach(row => row.forEach(b => b && drawBubble(b)));

      const dx = mousePos.current.x - SHOOTER_X;
      const dy = mousePos.current.y - SHOOTER_Y;
      const angle = Math.atan2(dy, dx);
      ctx.beginPath();
      ctx.setLineDash([6, 8]);
      ctx.lineWidth = 2.5;
      ctx.moveTo(SHOOTER_X, SHOOTER_Y);
      ctx.lineTo(SHOOTER_X + Math.cos(angle) * 160, SHOOTER_Y + Math.sin(angle) * 160);
      ctx.strokeStyle = 'rgba(255,255,255,0.4)';
      ctx.stroke();
      ctx.setLineDash([]);

      if (projectile) {
        drawBubble({ x: projectile.x, y: projectile.y, color: projectile.color, row: 0, col: 0, type: 'normal' });
      }

      particles.forEach(p => {
        if (p.type === 'beam') {
          ctx.save();
          ctx.beginPath();
          ctx.fillStyle = `rgba(0, 255, 255, ${p.life})`;
          ctx.fillRect(0, p.y - 15, CANVAS_WIDTH, 30);
          ctx.fillStyle = `rgba(255, 255, 255, ${p.life * 1.8})`;
          ctx.fillRect(0, p.y - 5, CANVAS_WIDTH, 10);
          ctx.restore();
        } else {
          ctx.save();
          ctx.globalAlpha = p.life;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
          ctx.fillStyle = p.color;
          ctx.fill();
          ctx.restore();
        }
      });

      const dropsIn = currentLevelShotsToDrop - (shotsTaken % currentLevelShotsToDrop);
      ctx.fillStyle = dropsIn <= 1 ? 'rgba(244, 63, 94, 1.0)' : 'rgba(255, 255, 255, 0.5)';
      ctx.font = '900 13px Inter';
      ctx.textAlign = 'left';
      ctx.fillText(`THREAT IN: ${dropsIn}`, 20, CANVAS_HEIGHT - 20);

      drawBubble({ x: SHOOTER_X, y: SHOOTER_Y, color: activeColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS + 4);
      drawBubble({ x: SHOOTER_X + 80, y: SHOOTER_Y + 15, color: nextColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS * 0.8);

      ctx.fillStyle = 'rgba(255,255,255,0.7)';
      ctx.font = '900 12px Inter';
      ctx.textAlign = 'center';
      ctx.fillText('NEXT', SHOOTER_X + 80, SHOOTER_Y + 45);
      ctx.restore();
    };

    update();
    return () => cancelAnimationFrame(animationFrameId);
  }, [grid, projectile, activeColor, nextColor, particles, onGameOver, onScoreChange, onWin, score, palette, shotsTaken, dropGrid, triggerBomb, triggerLaser, shake, level, currentLevelShotsToDrop]);

  const handlePointer = (e: React.PointerEvent) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    mousePos.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onPointerMove={handlePointer}
      onPointerDown={(e) => { handlePointer(e); handleShoot(); }}
      className="w-full h-full cursor-crosshair touch-none select-none"
    />
  );
};

export default GameBoard;

import React, { useState, useEffect, useCallback } from 'react';
import GameBoard from './components/GameBoard';
import { getAITip } from './services/geminiService';
import { audio } from './services/audioService';

const App: React.FC = () => {
  const [score, setScore] = useState(0);
  const [level, setLevel] = useState(1);
  const [aiTip, setAiTip] = useState("Welcome to BallBop!");
  const [gameState, setGameState] = useState<'start' | 'playing' | 'gameover' | 'next_level'>('start');
  const [isMuted, setIsMuted] = useState(false);

  const toggleMute = () => {
    const nextMuted = !isMuted;
    setIsMuted(nextMuted);
    audio.setMuted(nextMuted);
  };

  const updateTip = useCallback(async (s: number, l: number) => {
    const tip = await getAITip(s, l);
    setAiTip(tip);
  }, []);

  useEffect(() => {
    if (gameState === 'playing' && score > 0 && score % 1000 === 0) {
      updateTip(score, level);
    }
  }, [score, level, gameState, updateTip]);

  const handleStart = () => {
    setScore(0);
    setLevel(1);
    setGameState('playing');
    audio.playWin(); // Quick happy sound to start
  };

  const handleGameOver = (finalScore: number) => {
    setScore(finalScore);
    setGameState('gameover');
    audio.playGameOver();
  };

  const handleLevelClear = () => {
    setGameState('next_level');
    audio.playWin();
  };

  const startNextLevel = () => {
    setLevel(prev => prev + 1);
    setGameState('playing');
    audio.playPop(800);
  };

  return (
    <div className="fixed inset-0 bg-slate-900 flex flex-col items-center justify-center p-4">
      {/* Header Branding */}
      <div className="w-full max-w-[400px] flex justify-between items-center mb-4 px-2">
        <div className="flex flex-col">
          <div className="flex items-center gap-2">
            <h1 className="text-3xl font-game text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-fuchsia-500 tracking-normal">
              BallBop
            </h1>
            <button 
              onClick={toggleMute}
              className="p-2 bg-slate-800 rounded-full hover:bg-slate-700 transition-colors"
              aria-label={isMuted ? "Unmute" : "Mute"}
            >
              {isMuted ? (
                <svg className="w-4 h-4 text-rose-500" fill="currentColor" viewBox="0 0 24 24"><path d="M16.5 12c0-1.77-1.02-3.29-2.5-4.03v2.21l2.45 2.45c.03-.2.05-.41.05-.63zm2.5 0c0 .94-.2 1.82-.54 2.64l1.51 1.51C20.63 14.91 21 13.5 21 12c0-4.28-2.99-7.86-7-8.77v2.06c2.89.86 5 3.54 5 6.71zM4.27 3L3 4.27 7.73 9H3v6h4l5 5v-6.73l4.25 4.25c-.67.52-1.42.93-2.25 1.18v2.06c1.38-.31 2.63-.95 3.69-1.81L19.73 21 21 19.73l-9-9L4.27 3zM12 4L9.91 6.09 12 8.18V4z"/></svg>
              ) : (
                <svg className="w-4 h-4 text-cyan-400" fill="currentColor" viewBox="0 0 24 24"><path d="M3 9v6h4l5 5V4L7 9H3zm13.5 3c0-1.77-1.02-3.29-2.5-4.03v8.05c1.48-.73 2.5-2.25 2.5-4.02zM14 3.23v2.06c2.89.86 5 3.54 5 6.71s-2.11 5.85-5 6.71v2.06c4.01-.91 7-4.49 7-8.77z"/></svg>
              )}
            </button>
          </div>
          <span className="text-[10px] text-cyan-500/80 font-bold tracking-[0.2em] uppercase">by 939PRO Elite</span>
        </div>
        <div className="flex flex-col items-end">
          <div className="text-white font-bold text-lg">Score: <span className="text-cyan-400 font-game">{score}</span></div>
          <div className="text-xs text-slate-400 uppercase tracking-widest font-semibold">Level {level}</div>
        </div>
      </div>

      {/* Main Game Container */}
      <div className="relative w-full max-w-[400px] aspect-[2/3] bg-slate-800 rounded-3xl overflow-hidden border-4 border-slate-700 shadow-2xl shadow-cyan-500/20">
        {gameState === 'playing' ? (
          <GameBoard 
            level={level}
            onScoreChange={setScore} 
            onGameOver={handleGameOver} 
            onWin={handleLevelClear}
          />
        ) : (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/90 backdrop-blur-sm z-50 p-8 text-center">
            {gameState === 'start' && (
              <>
                <div className="w-24 h-24 mb-6 rounded-full bg-gradient-to-tr from-cyan-500 to-fuchsia-500 flex items-center justify-center animate-pulse">
                  <div className="w-16 h-16 rounded-full bg-slate-900 flex items-center justify-center">
                    <span className="text-3xl font-game text-white">BOP</span>
                  </div>
                </div>
                <h2 className="text-3xl font-game text-white mb-2">Ready to Pop?</h2>
                <p className="text-slate-400 mb-8 font-medium">Master the physics of BallBop and clear the board.</p>
                <button 
                  onClick={handleStart}
                  className="w-full py-4 bg-gradient-to-r from-cyan-500 to-fuchsia-500 rounded-2xl text-white font-game text-2xl hover:scale-105 active:scale-95 transition-all shadow-lg shadow-cyan-500/40"
                >
                  START GAME
                </button>
              </>
            )}

            {gameState === 'next_level' && (
              <>
                <h2 className="text-4xl font-game mb-2 text-cyan-400">
                  LEVEL {level} CLEAR!
                </h2>
                <div className="text-slate-300 mb-8">
                  <p className="text-lg font-bold">Bonus points awarded!</p>
                  <p className="text-sm text-slate-500 mt-2 font-medium">Level {level + 1} will be harder.</p>
                </div>
                <button 
                  onClick={startNextLevel}
                  className="w-full py-4 bg-gradient-to-r from-emerald-500 to-cyan-500 rounded-2xl text-white font-game text-2xl hover:scale-105 active:scale-95 transition-all shadow-lg"
                >
                  NEXT LEVEL
                </button>
              </>
            )}

            {gameState === 'gameover' && (
              <>
                <h2 className="text-4xl font-game mb-2 text-rose-500">
                  GAME OVER
                </h2>
                <div className="text-slate-300 mb-8 font-medium">
                  <p className="text-xl">Final Score: <span className="font-game text-white">{score}</span></p>
                  <p className="text-sm mt-4 text-slate-500 italic">"939PRO: Perfection is just a pop away."</p>
                </div>
                <button 
                  onClick={handleStart}
                  className="w-full py-4 bg-slate-100 rounded-2xl text-slate-900 font-game text-2xl hover:bg-white active:scale-95 transition-all"
                >
                  RESTART
                </button>
              </>
            )}
          </div>
        )}
      </div>

      {/* AI Tip / Footer */}
      <div className="w-full max-w-[400px] mt-4 p-4 bg-slate-800/50 rounded-2xl border border-slate-700/50">
        <p className="text-sm text-slate-400 text-center leading-relaxed font-medium">
          <span className="text-fuchsia-500 font-bold mr-2 uppercase tracking-wide">AI Insight:</span>
          {aiTip}
        </p>
      </div>

      {/* Navigation Simulation for iOS look */}
      <div className="mt-auto pb-4">
        <div className="w-32 h-1.5 bg-slate-700 rounded-full"></div>
      </div>
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState, useCallback, useMemo } from 'react';
import { Bubble, BubbleColor, Projectile, Particle, BubbleType } from '../types';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, BUBBLE_RADIUS, GRID_ROWS, GRID_COLS, 
  COLOR_PALETTES, BUBBLE_COLORS, SHOOTER_X, SHOOTER_Y, 
  POWER_UP_CHANCE_BASE, PROJECTILE_BASE_SPEED, COLLISION_THRESHOLD,
  MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP
} from '../constants';
import { audio } from '../services/audioService';

interface GameBoardProps {
  level: number;
  onScoreChange: (score: number) => void;
  onGameOver: (score: number) => void;
  onWin: () => void;
}

const GameBoard: React.FC<GameBoardProps> = ({ level, onScoreChange, onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [score, setScore] = useState(0);
  const [grid, setGrid] = useState<(Bubble | null)[][]>([]);
  const [projectile, setProjectile] = useState<Projectile | null>(null);
  const [nextColor, setNextColor] = useState<BubbleColor>(BUBBLE_COLORS[0]);
  const [activeColor, setActiveColor] = useState<BubbleColor>(BUBBLE_COLORS[1]);
  const [particles, setParticles] = useState<Particle[]>([]);
  const [shotsTaken, setShotsTaken] = useState(0);
  const [shake, setShake] = useState(0);

  const mousePos = useRef({ x: SHOOTER_X, y: 0 });
  const palette = COLOR_PALETTES[(level - 1) % COLOR_PALETTES.length];

  // Dynamic Difficulty Calculations
  const currentLevelShotsToDrop = useMemo(() => 
    Math.max(MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP - Math.floor((level - 1) / 3)), 
  [level]);

  const activeColorCount = useMemo(() => 
    Math.min(6, 4 + Math.floor((level - 1) / 2)), 
  [level]);

  const availableColors = useMemo(() => 
    BUBBLE_COLORS.slice(0, activeColorCount), 
[activeColorCount]);

  const generateBubble = useCallback((r: number, c: number): Bubble => {
    const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
    const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;

    // Power-up chance increases slightly with level to compensate for difficulty
    const powerUpChance = POWER_UP_CHANCE_BASE + (level * 0.005);
    const isPowerUp = Math.random() < powerUpChance;
    const type: BubbleType = isPowerUp ? (Math.random() > 0.5 ? 'bomb' : 'laser') : 'normal';

    return { 
      x, y, 
      color: availableColors[Math.floor(Math.random() * availableColors.length)],
      row: r,
      col: c,
      type
    };
  }, [availableColors, level]);

  useEffect(() => {
    const startRows = Math.min(GRID_ROWS - 4, 5 + Math.floor(level / 2));
    const newGrid: (Bubble | null)[][] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      newGrid[r] = [];
      const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < colsInRow; c++) {
        if (r < startRows) {
          newGrid[r][c] = generateBubble(r, c);
        } else {
          newGrid[r][c] = null;
        }
      }
    }
    setGrid(newGrid);
    setShotsTaken(0);
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
    setActiveColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [level, generateBubble, availableColors]);

  const getDistance = (x1: number, y1: number, x2: number, y2: number) => {
    return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);
  };

  const getNeighbors = (r: number, c: number) => {
    const neighbors: { r: number, c: number }[] = [];
    const offsets = r % 2 === 0 
      ? [{ dr: -1, dc: -1 }, { dr: -1, dc: 0 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: -1 }, { dr: 1, dc: 0 }]
      : [{ dr: -1, dc: 0 }, { dr: -1, dc: 1 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: 0 }, { dr: 1, dc: 1 }];

    for (const off of offsets) {
      const nr = r + off.dr;
      const nc = c + off.dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
        neighbors.push({ r: nr, c: nc });
      }
    }
    return neighbors;
  };

  const explode = (x: number, y: number, color: string, count: number = 12, velocityMult: number = 1.0) => {
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      newParticles.push({
        x, y,
        vx: (Math.random() - 0.5) * 12 * velocityMult,
        vy: (Math.random() - 0.5) * 12 * velocityMult,
        radius: Math.random() * 5 + 1.5,
        color,
        life: 1.0
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
  };

  const triggerLaser = useCallback((r: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
    let clearedCount = 0;

    audio.playLaser();
    setShake(10);

    setParticles(prev => [...prev, {
      x: CANVAS_WIDTH / 2,
      y: r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS,
      vx: 0, vy: 0, radius: 28, color: '#00ffff', life: 1.0, type: 'beam'
    }]);

    for (let c = 0; c < colsInRow; c++) {
      if (newGrid[r][c]) {
        const b = newGrid[r][c]!;
        explode(b.x, b.y, '#ffffff', 16, 1.4);
        newGrid[r][c] = null;
        clearedCount++;
      }
    }
    const bonus = clearedCount * 25;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });
    return newGrid;
  }, [onScoreChange]);

  const triggerBomb = useCallback((r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const center = newGrid[r][c];
    if (!center) return newGrid;

    audio.playBomb();
    setShake(30);
    explode(center.x, center.y, '#ff5500', 60, 1.8);

    let clearedCount = 0;
    const explosionRadius = BUBBLE_RADIUS * 6.5;

    for (let row = 0; row < GRID_ROWS; row++) {
      const cols = row % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let col = 0; col < cols; col++) {
        const b = newGrid[row][col];
        if (b) {
          const dist = getDistance(center.x, center.y, b.x, b.y);
          if (dist <= explosionRadius) {
            explode(b.x, b.y, palette[b.color] || '#ffffff', 12, 1.2);
            newGrid[row][col] = null;
            clearedCount++;
          }
        }
      }
    }

    newGrid[r][c] = null;
    const bonus = clearedCount * 20;
    setScore(s => {
      onScoreChange(s + bonus);
      return s + bonus;
    });

    return newGrid;
  }, [palette, onScoreChange]);

  const dropGrid = useCallback(() => {
    setGrid(oldGrid => {
      const newGrid: (Bubble | null)[][] = [];
      for (let r = 0; r < GRID_ROWS; r++) {
        newGrid[r] = [];
        const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
        if (r === 0) {
          for (let c = 0; c < colsInRow; c++) {
            newGrid[r][c] = generateBubble(r, c);
          }
        } else {
          const prevRow = oldGrid[r - 1];
          const prevCols = (r - 1) % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < colsInRow; c++) {
            const source = c < prevCols ? prevRow[c] : null;
            const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            if (source) {
              newGrid[r][c] = { ...source, x, y, row: r, col: c };
            } else {
              newGrid[r][c] = null;
            }
          }
        }
      }
      // Fail condition: bubble hits the danger zone
      if (newGrid[GRID_ROWS - 3].some(b => b !== null)) onGameOver(score);
      return newGrid;
    });
  }, [score, onGameOver, generateBubble]);

  const handleShoot = useCallback(() => {
    if (projectile) return;
    const dx = mousePos.current.x - SHOOTER_X;
    const dy = mousePos.current.y - SHOOTER_Y;
    const angle = Math.atan2(dy, dx);
    const speed = PROJECTILE_BASE_SPEED + (level * 0.15); // Gentler scaling for a smooth feel

    explode(SHOOTER_X, SHOOTER_Y, palette[activeColor] || '#ffffff', 18, 0.9);
    setShake(5);

    setProjectile({
      x: SHOOTER_X, y: SHOOTER_Y, vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed, color: activeColor
    });
    audio.playShoot();
    setShotsTaken(prev => prev + 1);
    setActiveColor(nextColor);
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [projectile, activeColor, nextColor, level, palette, availableColors]);

  useEffect(() => {
    let animationFrameId: number;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const update = () => {
      // Particles updated with friction and slower life decay for better visual tracking
      setParticles(prev => prev.map(p => ({
        ...p, 
        x: p.x + p.vx, 
        y: p.y + p.vy, 
        vx: p.vx * 0.97, // Friction slows down particles over time
        vy: p.vy * 0.97, 
        life: p.life - (p.type === 'beam' ? 0.02 : 0.015) // Much slower decay
      })).filter(p => p.life > 0));

      // Slower shake decay for a more impactful feeling
      if (shake > 0) setShake(s => Math.max(0, s - 0.4));

      if (projectile) {
        // High-precision sub-stepping for reliable collisions even at lower speeds
        const SUB_STEPS = 4;
        let collided = false;
        let hitBubble: Bubble | null = null;
        let bestR = -1;
        let bestC = -1;

        for (let i = 0; i < SUB_STEPS && !collided; i++) {
          projectile.x += projectile.vx / SUB_STEPS;
          projectile.y += projectile.vy / SUB_STEPS;

          if (projectile.x - BUBBLE_RADIUS < 0) {
            projectile.x = BUBBLE_RADIUS;
            projectile.vx *= -1;
          } else if (projectile.x + BUBBLE_RADIUS > CANVAS_WIDTH) {
            projectile.x = CANVAS_WIDTH - BUBBLE_RADIUS;
            projectile.vx *= -1;
          }

          if (projectile.y - BUBBLE_RADIUS < 0) {
            collided = true;
            let minD = Infinity;
            for (let c = 0; c < GRID_COLS; c++) {
              const sx = c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS;
              const d = Math.abs(projectile.x - sx);
              if (d < minD) { minD = d; bestR = 0; bestC = c; }
            }
          } else {
            for (let r = 0; r < GRID_ROWS; r++) {
              const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
              for (let c = 0; c < cols; c++) {
                const b = grid[r][c];
                if (b && getDistance(projectile.x, projectile.y, b.x, b.y) < BUBBLE_RADIUS * COLLISION_THRESHOLD) {
                  collided = true;
                  hitBubble = b;

                  let minD = Infinity;
                  const neighbors = getNeighbors(r, c);
                  for (const n of neighbors) {
                    if (!grid[n.r][n.c]) {
                      const nx = (n.r % 2 === 0 ? n.c * BUBBLE_RADIUS * 2 : n.c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
                      const ny = n.r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
                      const d = getDistance(projectile.x, projectile.y, nx, ny);
                      if (d < minD) { minD = d; bestR = n.r; bestC = n.c; }
                    }
                  }
                }
              }
            }
          }
        }

        if (collided) {
          let updatedGrid = [...grid.map(row => [...row])];

          if (hitBubble?.type === 'bomb') {
            updatedGrid = triggerBomb(hitBubble.row, hitBubble.col, updatedGrid);
          } else if (hitBubble?.type === 'laser') {
            updatedGrid = triggerLaser(hitBubble.row, updatedGrid);
          } else if (bestR !== -1) {
            const px = (bestR % 2 === 0 ? bestC * BUBBLE_RADIUS * 2 : bestC * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
            const py = bestR * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
            updatedGrid[bestR][bestC] = { x: px, y: py, color: projectile.color, row: bestR, col: bestC, type: 'normal' };

            const matches: {r: number, c: number}[] = [{ r: bestR, c: bestC }];
            const visited = new Set<string>(); visited.add(`${bestR},${bestC}`);
            let mi = 0;
            while (mi < matches.length) {
              const curr = matches[mi++];
              for (const n of getNeighbors(curr.r, curr.c)) {
                const b = updatedGrid[n.r][n.c];
                if (b && b.color === projectile.color && b.type === 'normal' && !visited.has(`${n.r},${n.c}`)) {
                  visited.add(`${n.r},${n.c}`);
                  matches.push(n);
                }
              }
            }

            if (matches.length >= 3) {
              audio.playPop(450 + matches.length * 30);
              setShake(4 + matches.length * 0.7);
              matches.forEach(m => {
                const b = updatedGrid[m.r][m.c];
                if (b) explode(b.x, b.y, palette[b.color], 16, 1.1); // More particles per pop
                updatedGrid[m.r][m.c] = null;
              });
              setScore(s => {
                const ns = s + matches.length * 20;
                onScoreChange(ns);
                return ns;
              });
            } else {
              audio.playShoot();
            }
          }

          const anchored = new Set<string>();
          const q: {r: number, c: number}[] = [];
          for (let c = 0; c < GRID_COLS; c++) { if (updatedGrid[0][c]) { anchored.add(`0,${c}`); q.push({ r: 0, c }); } }
          let qi = 0;
          while (qi < q.length) {
            const curr = q[qi++];
            for (const n of getNeighbors(curr.r, curr.c)) {
              if (updatedGrid[n.r][n.c] && !anchored.has(`${n.r},${n.c}`)) {
                anchored.add(`${n.r},${n.c}`); q.push(n);
              }
            }
          }
          let fallingCount = 0;
          for (let r = 0; r < GRID_ROWS; r++) {
            const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
            for (let c = 0; c < cols; c++) {
              if (updatedGrid[r][c] && !anchored.has(`${r},${c}`)) {
                const b = updatedGrid[r][c]!;
                explode(b.x, b.y, palette[b.color], 10, 0.9);
                updatedGrid[r][c] = null;
                fallingCount++;
                setScore(s => {
                  const ns = s + 30;
                  onScoreChange(ns);
                  return ns;
                });
              }
            }
          }
          if (fallingCount > 0) audio.playPop(380);

          setGrid(updatedGrid);
          setProjectile(null);

          if (shotsTaken > 0 && shotsTaken % currentLevelShotsToDrop === 0) {
            dropGrid();
            audio.playPop(250);
            setShake(6);
          }

          if (!updatedGrid.some(row => row.some(b => b !== null))) onWin();
          if (bestR >= GRID_ROWS - 3) onGameOver(score);
        }
      }
      render();
      animationFrameId = requestAnimationFrame(update);
    };

    const drawBubble = (b: Bubble, radius: number = BUBBLE_RADIUS, alpha: number = 1.0) => {
      const { x, y, color, type } = b;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.beginPath();
      ctx.arc(x, y, radius - 1, 0, Math.PI * 2);

      if (type === 'bomb') {
        ctx.fillStyle = '#1e1e2e';
        ctx.shadowBlur = 20;
        ctx.shadowColor = '#f97316';
      } else if (type === 'laser') {
        ctx.fillStyle = '#0f172a';
        ctx.shadowBlur = 20;
        ctx.shadowColor = '#38bdf8';
      } else {
        ctx.fillStyle = palette[color];
        ctx.shadowBlur = 14;
        ctx.shadowColor = palette[color];
      }
      ctx.fill();

      if (type === 'bomb') {
        ctx.fillStyle = '#f97316';
        ctx.beginPath();
        ctx.arc(x, y, radius / 2, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(x - 2, y - 10, 4, 12);
      } else if (type === 'laser') {
        ctx.strokeStyle = '#38bdf8';
        ctx.lineWidth = 5;
        ctx.beginPath();
        ctx.moveTo(x - radius/2, y);
        ctx.lineTo(x + radius/2, y);
        ctx.stroke();
      } else {
        ctx.beginPath();
        ctx.arc(x - radius/3, y - radius/3, radius/4, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255,255,255,0.5)';
        ctx.fill();
      }
      ctx.restore();
    };

    const render = () => {
      ctx.save();
      if (shake > 0) ctx.translate(Math.random() * shake - shake/2, Math.random() * shake - shake/2);
      ctx.clearRect(-40, -40, CANVAS_WIDTH + 80, CANVAS_HEIGHT + 80);

      // Danger Zone line
      ctx.beginPath();
      ctx.strokeStyle = 'rgba(244, 63, 94, 0.3)';
      ctx.setLineDash([5, 5]);
      const dangerY = (GRID_ROWS - 3) * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS * 2;
      ctx.moveTo(0, dangerY);
      ctx.lineTo(CANVAS_WIDTH, dangerY);
      ctx.stroke();
      ctx.setLineDash([]);

      grid.forEach(row => row.forEach(b => b && drawBubble(b)));

      const dx = mousePos.current.x - SHOOTER_X;
      const dy = mousePos.current.y - SHOOTER_Y;
      const angle = Math.atan2(dy, dx);
      ctx.beginPath();
      ctx.setLineDash([6, 8]);
      ctx.lineWidth = 2.5;
      ctx.moveTo(SHOOTER_X, SHOOTER_Y);
      ctx.lineTo(SHOOTER_X + Math.cos(angle) * 160, SHOOTER_Y + Math.sin(angle) * 160);
      ctx.strokeStyle = 'rgba(255,255,255,0.4)';
      ctx.stroke();
      ctx.setLineDash([]);

      if (projectile) {
        drawBubble({ x: projectile.x, y: projectile.y, color: projectile.color, row: 0, col: 0, type: 'normal' });
      }

      particles.forEach(p => {
        if (p.type === 'beam') {
          ctx.save();
          ctx.beginPath();
          ctx.fillStyle = `rgba(0, 255, 255, ${p.life})`;
          ctx.fillRect(0, p.y - 15, CANVAS_WIDTH, 30);
          ctx.fillStyle = `rgba(255, 255, 255, ${p.life * 1.8})`;
          ctx.fillRect(0, p.y - 5, CANVAS_WIDTH, 10);
          ctx.restore();
        } else {
          ctx.save();
          ctx.globalAlpha = p.life;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
          ctx.fillStyle = p.color;
          ctx.fill();
          ctx.restore();
        }
      });

      const dropsIn = currentLevelShotsToDrop - (shotsTaken % currentLevelShotsToDrop);
      ctx.fillStyle = dropsIn <= 1 ? 'rgba(244, 63, 94, 1.0)' : 'rgba(255, 255, 255, 0.5)';
      ctx.font = '700 16px Luckiest Guy'; // Use the punchy game font for threat warning
      ctx.textAlign = 'left';
      ctx.fillText(`THREAT IN: ${dropsIn}`, 20, CANVAS_HEIGHT - 20);

      drawBubble({ x: SHOOTER_X, y: SHOOTER_Y, color: activeColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS + 4);
      drawBubble({ x: SHOOTER_X + 80, y: SHOOTER_Y + 15, color: nextColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS * 0.8);

      ctx.fillStyle = 'rgba(255,255,255,0.7)';
      ctx.font = '600 12px Fredoka'; // Friendly rounded font for labels
      ctx.textAlign = 'center';
      ctx.fillText('NEXT', SHOOTER_X + 80, SHOOTER_Y + 45);
      ctx.restore();
    };

    update();
    return () => cancelAnimationFrame(animationFrameId);
  }, [grid, projectile, activeColor, nextColor, particles, onGameOver, onScoreChange, onWin, score, palette, shotsTaken, dropGrid, triggerBomb, triggerLaser, shake, level, currentLevelShotsToDrop]);

  const handlePointer = (e: React.PointerEvent) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    mousePos.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onPointerMove={handlePointer}
      onPointerDown={(e) => { handlePointer(e); handleShoot(); }}
      className="w-full h-full cursor-crosshair touch-none select-none"
    />
  );
};

export default GameBoard;

import React, { useRef, useEffect, useState, useCallback, useMemo } from 'react';
import { Bubble, BubbleColor, Projectile, Particle, BubbleType } from '../types';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, BUBBLE_RADIUS, GRID_ROWS, GRID_COLS, 
  COLOR_PALETTES, BUBBLE_COLORS, SHOOTER_X, SHOOTER_Y, 
  POWER_UP_CHANCE_BASE, PROJECTILE_BASE_SPEED, COLLISION_THRESHOLD,
  MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP
} from '../constants';
import { audio } from '../services/audioService';

interface GameBoardProps {
  level: number;
  onScoreChange: (score: number) => void;
  onGameOver: (score: number) => void;
  onWin: () => void;
}

const GameBoard: React.FC<GameBoardProps> = ({ level, onScoreChange, onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [score, setScore] = useState(0);
  const [grid, setGrid] = useState<(Bubble | null)[][]>([]);
  const [projectile, setProjectile] = useState<Projectile | null>(null);
  const [nextColor, setNextColor] = useState<BubbleColor>(BUBBLE_COLORS[0]);
  const [activeColor, setActiveColor] = useState<BubbleColor>(BUBBLE_COLORS[1]);
  const [particles, setParticles] = useState<Particle[]>([]);
  const [shotsTaken, setShotsTaken] = useState(0);
  const [shake, setShake] = useState(0);

  const mousePos = useRef({ x: SHOOTER_X, y: 0 });
  const palette = COLOR_PALETTES[(level - 1) % COLOR_PALETTES.length];

  const currentLevelShotsToDrop = useMemo(() => 
    Math.max(MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP - Math.floor((level - 1) / 3)), 
  [level]);

  const activeColorCount = useMemo(() => 
    Math.min(6, 4 + Math.floor((level - 1) / 2)), 
  [level]);

  const availableColors = useMemo(() => 
    BUBBLE_COLORS.slice(0, activeColorCount), 
  [activeColorCount]);

  const getBubbleCoords = (r: number, c: number) => {
    const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
    const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
    return { x, y };
  };

  const generateBubble = useCallback((r: number, c: number): Bubble => {
    const { x, y } = getBubbleCoords(r, c);
    const powerUpChance = POWER_UP_CHANCE_BASE + (level * 0.005);
    const isPowerUp = Math.random() < powerUpChance;
    const type: BubbleType = isPowerUp ? (Math.random() > 0.5 ? 'bomb' : 'laser') : 'normal';

    return { 
      x, y, 
      color: availableColors[Math.floor(Math.random() * availableColors.length)],
      row: r,
      col: c,
      type
    };
  }, [availableColors, level]);

  useEffect(() => {
    const startRows = Math.min(GRID_ROWS - 4, 5 + Math.floor(level / 2));
    const newGrid: (Bubble | null)[][] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      newGrid[r] = [];
      const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < colsInRow; c++) {
        if (r < startRows) {
          newGrid[r][c] = generateBubble(r, c);
        } else {
          newGrid[r][c] = null;
        }
      }
    }
    setGrid(newGrid);
    setShotsTaken(0);
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
    setActiveColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [level, generateBubble, availableColors]);

  const getDistance = (x1: number, y1: number, x2: number, y2: number) => {
    return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);
  };

  const getNeighbors = (r: number, c: number) => {
    const neighbors: { r: number, c: number }[] = [];
    const offsets = r % 2 === 0 
      ? [{ dr: -1, dc: -1 }, { dr: -1, dc: 0 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: -1 }, { dr: 1, dc: 0 }]
      : [{ dr: -1, dc: 0 }, { dr: -1, dc: 1 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: 0 }, { dr: 1, dc: 1 }];

    for (const off of offsets) {
      const nr = r + off.dr;
      const nc = c + off.dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
        neighbors.push({ r: nr, c: nc });
      }
    }
    return neighbors;
  };

  const findClosestEmptySlot = (targetX: number, targetY: number, currentGrid: (Bubble | null)[][]) => {
    let bestR = -1;
    let bestC = -1;
    let minD = Infinity;

    // We scan nearby rows to find the most accurate hex-grid snapping point
    const startR = Math.max(0, Math.floor(targetY / (BUBBLE_RADIUS * 1.732)) - 1);
    const endR = Math.min(GRID_ROWS - 1, startR + 3);

    for (let r = startR; r <= endR; r++) {
      const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < cols; c++) {
        if (!currentGrid[r][c]) {
          const { x, y } = getBubbleCoords(r, c);
          const d = getDistance(targetX, targetY, x, y);
          if (d < minD) {
            minD = d;
            bestR = r;
            bestC = c;
          }
        }
      }
    }
    return { bestR, bestC };
  };

  const explode = (x: number, y: number, color: string, count: number = 12, velocityMult: number = 1.0) => {
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      newParticles.push({
        x, y,
        vx: (Math.random() - 0.5) * 12 * velocityMult,
        vy: (Math.random() - 0.5) * 12 * velocityMult,
        radius: Math.random() * 5 + 1.5,
        color,
        life: 1.0
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
  };

  const triggerLaser = useCallback((r: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
    let clearedCount = 0;
    audio.playLaser();
    setShake(10);
    setParticles(prev => [...prev, {
      x: CANVAS_WIDTH / 2, y: r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS,
      vx: 0, vy: 0, radius: 28, color: '#00ffff', life: 1.0, type: 'beam'
    }]);
    for (let c = 0; c < colsInRow; c++) {
      if (newGrid[r][c]) {
        const b = newGrid[r][c]!;
        explode(b.x, b.y, '#ffffff', 16, 1.4);
        newGrid[r][c] = null;
        clearedCount++;
      }
    }
    const bonus = clearedCount * 25;
    setScore(s => { onScoreChange(s + bonus); return s + bonus; });
    return newGrid;
  }, [onScoreChange]);

  const triggerBomb = useCallback((r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const center = newGrid[r][c];
    if (!center) return newGrid;
    audio.playBomb();
    setShake(30);
    explode(center.x, center.y, '#ff5500', 60, 1.8);
    let clearedCount = 0;
    const explosionRadius = BUBBLE_RADIUS * 6.5;
    for (let row = 0; row < GRID_ROWS; row++) {
      const cols = row % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let col = 0; col < cols; col++) {
        const b = newGrid[row][col];
        if (b) {
          const dist = getDistance(center.x, center.y, b.x, b.y);
          if (dist <= explosionRadius) {
            explode(b.x, b.y, palette[b.color] || '#ffffff', 12, 1.2);
            newGrid[row][col] = null;
            clearedCount++;
          }
        }
      }
    }
    newGrid[r][c] = null;
    const bonus = clearedCount * 20;
    setScore(s => { onScoreChange(s + bonus); return s + bonus; });
    return newGrid;
  }, [palette, onScoreChange]);

  const dropGrid = useCallback(() => {
    setGrid(oldGrid => {
      const newGrid: (Bubble | null)[][] = [];
      for (let r = 0; r < GRID_ROWS; r++) {
        newGrid[r] = [];
        const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
        if (r === 0) {
          for (let c = 0; c < colsInRow; c++) {
            newGrid[r][c] = generateBubble(r, c);
          }
        } else {
          const prevRow = oldGrid[r - 1];
          const prevCols = (r - 1) % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < colsInRow; c++) {
            const source = c < prevCols ? prevRow[c] : null;
            const { x, y } = getBubbleCoords(r, c);
            if (source) {
              newGrid[r][c] = { ...source, x, y, row: r, col: c };
            } else {
              newGrid[r][c] = null;
            }
          }
        }
      }
      if (newGrid[GRID_ROWS - 3].some(b => b !== null)) onGameOver(score);
      return newGrid;
    });
  }, [score, onGameOver, generateBubble]);

  const handleShoot = useCallback(() => {
    if (projectile) return;
    const dx = mousePos.current.x - SHOOTER_X;
    const dy = mousePos.current.y - SHOOTER_Y;
    const angle = Math.atan2(dy, dx);
    const speed = PROJECTILE_BASE_SPEED + (level * 0.15);
    explode(SHOOTER_X, SHOOTER_Y, palette[activeColor] || '#ffffff', 18, 0.9);
    setShake(5);
    setProjectile({
      x: SHOOTER_X, y: SHOOTER_Y, vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed, color: activeColor
    });
    audio.playShoot();
    setShotsTaken(prev => prev + 1);
    setActiveColor(nextColor);
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [projectile, activeColor, nextColor, level, palette, availableColors]);

  useEffect(() => {
    let animationFrameId: number;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const update = () => {
      setParticles(prev => prev.map(p => ({
        ...p, x: p.x + p.vx, y: p.y + p.vy, vx: p.vx * 0.97, vy: p.vy * 0.97, life: p.life - (p.type === 'beam' ? 0.02 : 0.015)
      })).filter(p => p.life > 0));

      if (shake > 0) setShake(s => Math.max(0, s - 0.4));

      if (projectile) {
        const SUB_STEPS = 5;
        let collided = false;
        let hitBubble: Bubble | null = null;
        let bestR = -1, bestC = -1;

        for (let i = 0; i < SUB_STEPS && !collided; i++) {
          projectile.x += projectile.vx / SUB_STEPS;
          projectile.y += projectile.vy / SUB_STEPS;

          // Banking off the sides with safety offsets to prevent "wall tunneling"
          if (projectile.x - BUBBLE_RADIUS < 0) {
            projectile.x = BUBBLE_RADIUS;
            projectile.vx *= -1;
          } else if (projectile.x + BUBBLE_RADIUS > CANVAS_WIDTH) {
            projectile.x = CANVAS_WIDTH - BUBBLE_RADIUS;
            projectile.vx *= -1;
          }

          // Top wall collision - uses robust slot finding for corner cases
          if (projectile.y - BUBBLE_RADIUS < 0) {
            collided = true;
            const slot = findClosestEmptySlot(projectile.x, projectile.y, grid);
            bestR = slot.bestR;
            bestC = slot.bestC;
          } else {
            // Scan nearby grid for bubble collisions
            for (let r = 0; r < GRID_ROWS; r++) {
              const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
              for (let c = 0; c < cols; c++) {
                const b = grid[r][c];
                if (b && getDistance(projectile.x, projectile.y, b.x, b.y) < BUBBLE_RADIUS * COLLISION_THRESHOLD) {
                  collided = true;
                  hitBubble = b;
                  // Use global search for the nearest empty hex-grid slot relative to impact
                  const slot = findClosestEmptySlot(projectile.x, projectile.y, grid);
                  bestR = slot.bestR;
                  bestC = slot.bestC;
                }
              }
            }
          }
        }

        if (collided) {
          let updatedGrid = [...grid.map(row => [...row])];
          if (hitBubble?.type === 'bomb') {
            updatedGrid = triggerBomb(hitBubble.row, hitBubble.col, updatedGrid);
          } else if (hitBubble?.type === 'laser') {
            updatedGrid = triggerLaser(hitBubble.row, updatedGrid);
          } else if (bestR !== -1) {
            const { x: px, y: py } = getBubbleCoords(bestR, bestC);
            updatedGrid[bestR][bestC] = { x: px, y: py, color: projectile.color, row: bestR, col: bestC, type: 'normal' };
            const matches: {r: number, c: number}[] = [{ r: bestR, c: bestC }];
            const visited = new Set<string>(); visited.add(`${bestR},${bestC}`);
            let mi = 0;
            while (mi < matches.length) {
              const curr = matches[mi++];
              for (const n of getNeighbors(curr.r, curr.c)) {
                const b = updatedGrid[n.r][n.c];
                if (b && b.color === projectile.color && b.type === 'normal' && !visited.has(`${n.r},${n.c}`)) {
                  visited.add(`${n.r},${n.c}`); matches.push(n);
                }
              }
            }
            if (matches.length >= 3) {
              audio.playPop(450 + matches.length * 30);
              setShake(4 + matches.length * 0.7);
              matches.forEach(m => {
                const b = updatedGrid[m.r][m.c];
                if (b) explode(b.x, b.y, palette[b.color], 16, 1.1);
                updatedGrid[m.r][m.c] = null;
              });
              setScore(s => { onScoreChange(s + matches.length * 20); return s + matches.length * 20; });
            } else {
              audio.playShoot();
            }
          }

          const anchored = new Set<string>();
          const q: {r: number, c: number}[] = [];
          for (let c = 0; c < GRID_COLS; c++) { if (updatedGrid[0][c]) { anchored.add(`0,${c}`); q.push({ r: 0, c }); } }
          let qi = 0;
          while (qi < q.length) {
            const curr = q[qi++];
            for (const n of getNeighbors(curr.r, curr.c)) {
              if (updatedGrid[n.r][n.c] && !anchored.has(`${n.r},${n.c}`)) {
                anchored.add(`${n.r},${n.c}`); q.push(n);
              }
            }
          }
          let fallingCount = 0;
          for (let r = 0; r < GRID_ROWS; r++) {
            const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
            for (let c = 0; c < cols; c++) {
              if (updatedGrid[r][c] && !anchored.has(`${r},${c}`)) {
                const b = updatedGrid[r][c]!;
                explode(b.x, b.y, palette[b.color], 10, 0.9);
                updatedGrid[r][c] = null;
                fallingCount++;
                setScore(s => { onScoreChange(s + 30); return s + 30; });
              }
            }
          }
          if (fallingCount > 0) audio.playPop(380);
          setGrid(updatedGrid);
          setProjectile(null);
          if (shotsTaken > 0 && shotsTaken % currentLevelShotsToDrop === 0) { dropGrid(); audio.playPop(250); setShake(6); }
          if (!updatedGrid.some(row => row.some(b => b !== null))) onWin();
          if (bestR >= GRID_ROWS - 3) onGameOver(score);
        }
      }
      render();
      animationFrameId = requestAnimationFrame(update);
    };

    const drawBubble = (b: Bubble, radius: number = BUBBLE_RADIUS, alpha: number = 1.0) => {
      const { x, y, color, type } = b;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.beginPath();
      ctx.arc(x, y, radius - 1, 0, Math.PI * 2);
      if (type === 'bomb') { ctx.fillStyle = '#1e1e2e'; ctx.shadowBlur = 20; ctx.shadowColor = '#f97316'; } 
      else if (type === 'laser') { ctx.fillStyle = '#0f172a'; ctx.shadowBlur = 20; ctx.shadowColor = '#38bdf8'; } 
      else { ctx.fillStyle = palette[color]; ctx.shadowBlur = 14; ctx.shadowColor = palette[color]; }
      ctx.fill();
      if (type === 'bomb') { ctx.fillStyle = '#f97316'; ctx.beginPath(); ctx.arc(x, y, radius / 2, 0, Math.PI * 2); ctx.fill(); ctx.fillStyle = '#ffffff'; ctx.fillRect(x - 2, y - 10, 4, 12); } 
      else if (type === 'laser') { ctx.strokeStyle = '#38bdf8'; ctx.lineWidth = 5; ctx.beginPath(); ctx.moveTo(x - radius/2, y); ctx.lineTo(x + radius/2, y); ctx.stroke(); } 
      else { ctx.beginPath(); ctx.arc(x - radius/3, y - radius/3, radius/4, 0, Math.PI * 2); ctx.fillStyle = 'rgba(255,255,255,0.5)'; ctx.fill(); }
      ctx.restore();
    };

    const render = () => {
      ctx.save();
      if (shake > 0) ctx.translate(Math.random() * shake - shake/2, Math.random() * shake - shake/2);
      ctx.clearRect(-40, -40, CANVAS_WIDTH + 80, CANVAS_HEIGHT + 80);
      ctx.beginPath();
      ctx.strokeStyle = 'rgba(244, 63, 94, 0.3)';
      ctx.setLineDash([5, 5]);
      const dangerY = (GRID_ROWS - 3) * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS * 2;
      ctx.moveTo(0, dangerY); ctx.lineTo(CANVAS_WIDTH, dangerY); ctx.stroke(); ctx.setLineDash([]);
      grid.forEach(row => row.forEach(b => b && drawBubble(b)));
      const dx = mousePos.current.x - SHOOTER_X, dy = mousePos.current.y - SHOOTER_Y;
      const angle = Math.atan2(dy, dx);
      ctx.beginPath(); ctx.setLineDash([6, 8]); ctx.lineWidth = 2.5; ctx.moveTo(SHOOTER_X, SHOOTER_Y); ctx.lineTo(SHOOTER_X + Math.cos(angle) * 160, SHOOTER_Y + Math.sin(angle) * 160); ctx.strokeStyle = 'rgba(255,255,255,0.4)'; ctx.stroke(); ctx.setLineDash([]);
      if (projectile) drawBubble({ x: projectile.x, y: projectile.y, color: projectile.color, row: 0, col: 0, type: 'normal' });
      particles.forEach(p => {
        if (p.type === 'beam') { ctx.save(); ctx.beginPath(); ctx.fillStyle = `rgba(0, 255, 255, ${p.life})`; ctx.fillRect(0, p.y - 15, CANVAS_WIDTH, 30); ctx.fillStyle = `rgba(255, 255, 255, ${p.life * 1.8})`; ctx.fillRect(0, p.y - 5, CANVAS_WIDTH, 10); ctx.restore(); } 
        else { ctx.save(); ctx.globalAlpha = p.life; ctx.beginPath(); ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2); ctx.fillStyle = p.color; ctx.fill(); ctx.restore(); }
      });
      const dropsIn = currentLevelShotsToDrop - (shotsTaken % currentLevelShotsToDrop);
      ctx.fillStyle = dropsIn <= 1 ? 'rgba(244, 63, 94, 1.0)' : 'rgba(255, 255, 255, 0.5)';
      ctx.font = '700 16px Luckiest Guy'; ctx.textAlign = 'left'; ctx.fillText(`THREAT IN: ${dropsIn}`, 20, CANVAS_HEIGHT - 20);
      drawBubble({ x: SHOOTER_X, y: SHOOTER_Y, color: activeColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS + 4);
      drawBubble({ x: SHOOTER_X + 80, y: SHOOTER_Y + 15, color: nextColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS * 0.8);
      ctx.fillStyle = 'rgba(255,255,255,0.7)'; ctx.font = '600 12px Fredoka'; ctx.textAlign = 'center'; ctx.fillText('NEXT', SHOOTER_X + 80, SHOOTER_Y + 45);
      ctx.restore();
    };
    update();
    return () => cancelAnimationFrame(animationFrameId);
  }, [grid, projectile, activeColor, nextColor, particles, onGameOver, onScoreChange, onWin, score, palette, shotsTaken, dropGrid, triggerBomb, triggerLaser, shake, level, currentLevelShotsToDrop]);

  const handlePointer = (e: React.PointerEvent) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    mousePos.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onPointerMove={handlePointer}
      onPointerDown={(e) => { handlePointer(e); handleShoot(); }}
      className="w-full h-full cursor-crosshair touch-none select-none"
    />
  );
};

