                {isMuted ? (
                  <svg className="w-4 h-4 text-rose-500" fill="currentColor" viewBox="0 0 24 24"><path d="M16.5 12c0-1.77-1.02-3.29-2.5-4.03v2.21l2.45 2.45c.03-.2.05-.41.05-.63zm2.5 0c0 .94-.2 1.82-.54 2.64l1.51 1.51C20.63 14.91 21 13.5 21 12c0-4.28-2.99-7.86-7-8.77v2.06c2.89.86 5 3.54 5 6.71zM4.27 3L3 4.27 7.73 9H3v6h4l5 5v-6.73l4.25 4.25c-.67.52-1.42.93-2.25 1.18v2.06c1.38-.31 2.63-.95 3.69-1.81L19.73 21 21 19.73l-9-9L4.27 3zM12 4L9.91 6.09 12 8.18V4z"/></svg>
                ) : (
                  <svg className="w-4 h-4 text-cyan-400" fill="currentColor" viewBox="0 0 24 24"><path d="M3 9v6h4l5 5V4L7 9H3zm13.5 3c0-1.77-1.02-3.29-2.5-4.03v8.05c1.48-.73 2.5-2.25 2.5-4.02zM14 3.23v2.06c2.89.86 5 3.54 5 6.71s-2.11 5.85-5 6.71v2.06c4.01-.91 7-4.49 7-8.77z"/></svg>
                )}
              </button>
            </div>
          </div>
          <span className="text-[10px] text-cyan-500/80 font-bold tracking-[0.2em] uppercase">by 939PRO Elite</span>
        </div>
        <div className="flex flex-col items-end">
          <div className="text-white font-bold text-lg">Score: <span className="text-cyan-400 font-game">{score}</span></div>
          <div className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Best: <span className="text-fuchsia-400 font-game">{highScore}</span></div>
        </div>
      </div>

      {/* Main Game Container */}
      <div className="relative w-full max-w-[400px] aspect-[2/3] bg-slate-800 rounded-3xl overflow-hidden border-4 border-slate-700 shadow-2xl shadow-cyan-500/20">
        {gameState === 'playing' ? (
          <>
            <GameBoard 
              level={level}
              isPaused={isPaused}
              onScoreChange={setScore} 
              onGameOver={handleGameOver} 
              onWin={handleLevelClear}
            />
            {isPaused && (
              <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md flex flex-col items-center justify-center z-[100]">
                <h2 className="text-4xl font-game text-white mb-6">PAUSED</h2>
                <button 
                  onClick={togglePause}
                  className="px-8 py-3 bg-cyan-500 rounded-2xl text-white font-game text-xl shadow-lg hover:scale-105 transition-transform"
                >
                  RESUME
                </button>
              </div>
            )}
          </>
        ) : (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/90 backdrop-blur-sm z-50 p-8 text-center">
            {gameState === 'start' && (
              <>
                <div className="w-24 h-24 mb-6 rounded-full bg-gradient-to-tr from-cyan-500 to-fuchsia-500 flex items-center justify-center animate-pulse">
                  <div className="w-16 h-16 rounded-full bg-slate-900 flex items-center justify-center">
                    <span className="text-3xl font-game text-white">BOP</span>
                  </div>
                </div>
                <h2 className="text-3xl font-game text-white mb-2">Ready to Pop?</h2>
                <div className="mb-6 px-4 py-2 bg-slate-800 rounded-xl border border-slate-700">
                  <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mb-1">Personal Best</p>
                  <p className="text-2xl font-game text-fuchsia-400">{highScore}</p>
                </div>
                <p className="text-slate-400 mb-8 font-medium">Master the physics of BallBop and clear the board.</p>
                <button 
                  onClick={handleStart}
                  className="w-full py-4 bg-gradient-to-r from-cyan-500 to-fuchsia-500 rounded-2xl text-white font-game text-2xl hover:scale-105 active:scale-95 transition-all shadow-lg shadow-cyan-500/40"
                >
                  START GAME
                </button>
              </>
            )}

            {gameState === 'next_level' && (
              <>
                <h2 className="text-4xl font-game mb-2 text-cyan-400">
                  LEVEL {level} CLEAR!
                </h2>
                <div className="text-slate-300 mb-8">
                  <p className="text-lg font-bold">Bonus points awarded!</p>
                  <p className="text-sm text-slate-500 mt-2 font-medium">Level {level + 1} will be harder.</p>
                </div>
                <button 
                  onClick={startNextLevel}
                  className="w-full py-4 bg-gradient-to-r from-emerald-500 to-cyan-500 rounded-2xl text-white font-game text-2xl hover:scale-105 active:scale-95 transition-all shadow-lg"
                >
                  NEXT LEVEL
                </button>
              </>
            )}

            {gameState === 'gameover' && (
              <>
                {isNewHighScore ? (
                  <div className="mb-2 animate-bounce">
                    <span className="bg-fuchsia-500 text-white text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-tighter shadow-lg shadow-fuchsia-500/50">NEW HIGH SCORE!</span>
                  </div>
                ) : null}
                <h2 className="text-4xl font-game mb-2 text-rose-500">
                  GAME OVER
                </h2>
                <div className="text-slate-300 mb-8 font-medium">
                  <p className="text-xl">Final Score: <span className="font-game text-white">{score}</span></p>
                  <p className="text-sm mt-2 text-slate-400">Current Best: <span className="text-fuchsia-400 font-game">{highScore}</span></p>
                  <p className="text-xs mt-6 text-slate-500 italic">"939PRO: Perfection is just a pop away."</p>
                </div>
                <button 
                  onClick={handleStart}
                  className="w-full py-4 bg-slate-100 rounded-2xl text-slate-900 font-game text-2xl hover:bg-white active:scale-95 transition-all"
                >
                  RETRY
                </button>
              </>
            )}
          </div>
        )}
      </div>

      {/* AI Tip / Footer */}
      <div className="w-full max-w-[400px] mt-4 p-4 bg-slate-800/50 rounded-2xl border border-slate-700/50">
        <p className="text-sm text-slate-400 text-center leading-relaxed font-medium">
          <span className="text-fuchsia-500 font-bold mr-2 uppercase tracking-wide">AI Insight:</span>
          {aiTip}
        </p>
      </div>

      {/* Navigation Simulation for iOS look */}
      <div className="mt-auto pb-4">
        <div className="w-32 h-1.5 bg-slate-700 rounded-full"></div>
      </div>
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState, useCallback, useMemo } from 'react';
import { Bubble, BubbleColor, Projectile, Particle, BubbleType } from '../types';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, BUBBLE_RADIUS, GRID_ROWS, GRID_COLS, 
  COLOR_PALETTES, BUBBLE_COLORS, SHOOTER_X, SHOOTER_Y, 
  POWER_UP_CHANCE_BASE, PROJECTILE_BASE_SPEED, COLLISION_THRESHOLD,
  MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP
} from '../constants';
import { audio } from '../services/audioService';

interface GameBoardProps {
  level: number;
  isPaused: boolean;
  onScoreChange: (score: number) => void;
  onGameOver: (score: number) => void;
  onWin: () => void;
}

const GameBoard: React.FC<GameBoardProps> = ({ level, isPaused, onScoreChange, onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [score, setScore] = useState(0);
  const [grid, setGrid] = useState<(Bubble | null)[][]>([]);
  const [projectile, setProjectile] = useState<Projectile | null>(null);
  const [nextColor, setNextColor] = useState<BubbleColor>(BUBBLE_COLORS[0]);
  const [activeColor, setActiveColor] = useState<BubbleColor>(BUBBLE_COLORS[1]);
  const [particles, setParticles] = useState<Particle[]>([]);
  const [shotsTaken, setShotsTaken] = useState(0);
  const [shake, setShake] = useState(0);

  const mousePos = useRef({ x: SHOOTER_X, y: 0 });
  const palette = COLOR_PALETTES[(level - 1) % COLOR_PALETTES.length];

  const currentLevelShotsToDrop = useMemo(() => 
    Math.max(MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP - Math.floor((level - 1) / 3)), 
  [level]);

  const activeColorCount = useMemo(() => 
    Math.min(6, 4 + Math.floor((level - 1) / 2)), 
  [level]);

  const availableColors = useMemo(() => 
    BUBBLE_COLORS.slice(0, activeColorCount), 
  [activeColorCount]);

  const getBubbleCoords = (r: number, c: number) => {
    const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
    const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
    return { x, y };
  };

  const generateBubble = useCallback((r: number, c: number): Bubble => {
    const { x, y } = getBubbleCoords(r, c);
    const powerUpChance = POWER_UP_CHANCE_BASE + (level * 0.005);
    const isPowerUp = Math.random() < powerUpChance;
    const type: BubbleType = isPowerUp ? (Math.random() > 0.5 ? 'bomb' : 'laser') : 'normal';

    return { 
      x, y, 
      color: availableColors[Math.floor(Math.random() * availableColors.length)],
      row: r,
      col: c,
      type
    };
  }, [availableColors, level]);

  useEffect(() => {
    const startRows = Math.min(GRID_ROWS - 4, 5 + Math.floor(level / 2));
    const newGrid: (Bubble | null)[][] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      newGrid[r] = [];
      const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < colsInRow; c++) {
        if (r < startRows) {
          newGrid[r][c] = generateBubble(r, c);
        } else {
          newGrid[r][c] = null;
        }
      }
    }
    setGrid(newGrid);
    setShotsTaken(0);
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
    setActiveColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [level, generateBubble, availableColors]);

  const getDistance = (x1: number, y1: number, x2: number, y2: number) => {
    return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);
  };

  const getNeighbors = (r: number, c: number) => {
    const neighbors: { r: number, c: number }[] = [];
    const offsets = r % 2 === 0 
      ? [{ dr: -1, dc: -1 }, { dr: -1, dc: 0 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: -1 }, { dr: 1, dc: 0 }]
      : [{ dr: -1, dc: 0 }, { dr: -1, dc: 1 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: 0 }, { dr: 1, dc: 1 }];

    for (const off of offsets) {
      const nr = r + off.dr;
      const nc = c + off.dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
        neighbors.push({ r: nr, c: nc });
      }
    }
    return neighbors;
  };

  /**
   * High-precision snapping logic:
   * Uses hex-grid math to narrow search to the immediate vicinity of the impact, 
   * ensuring bubbles always snap to the most logical grid slot.
   */
  const findClosestEmptySlot = (targetX: number, targetY: number, currentGrid: (Bubble | null)[][]) => {
    let bestR = -1;
    let bestC = -1;
    let minD = Infinity;

    // Localized search based on approximate hex coordinates
    const approxR = Math.round((targetY - BUBBLE_RADIUS) / (BUBBLE_RADIUS * 1.732));
    const startR = Math.max(0, approxR - 1);
    const endR = Math.min(GRID_ROWS - 1, approxR + 2);

    for (let r = startR; r <= endR; r++) {
      const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      // Estimate column based on staggering
      const offsetX = r % 2 === 0 ? BUBBLE_RADIUS : BUBBLE_RADIUS * 2;
      const approxC = Math.round((targetX - offsetX) / (BUBBLE_RADIUS * 2));
      const startC = Math.max(0, approxC - 1);
      const endC = Math.min(cols - 1, approxC + 1);

      for (let c = startC; c <= endC; c++) {
        if (!currentGrid[r][c]) {
          const { x, y } = getBubbleCoords(r, c);
          const d = getDistance(targetX, targetY, x, y);
          if (d < minD) {
            minD = d;
            bestR = r;
            bestC = c;
          }
        }
      }
    }

    // Safety fallback for edge cases
    if (bestR === -1) {
       for (let r = 0; r < GRID_ROWS; r++) {
          const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < cols; c++) {
            if (!currentGrid[r][c]) return { bestR: r, bestC: c };
          }
       }
    }

    return { bestR, bestC };
  };

  const explode = (x: number, y: number, color: string, count: number = 12, velocityMult: number = 1.0) => {
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      newParticles.push({
        x, y,
        vx: (Math.random() - 0.5) * 12 * velocityMult,
        vy: (Math.random() - 0.5) * 12 * velocityMult,
        radius: Math.random() * 5 + 1.5,
        color,
        life: 1.0
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
  };

  const triggerLaser = useCallback((r: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
    let clearedCount = 0;
    audio.playLaser();
    setShake(10);
    setParticles(prev => [...prev, {
      x: CANVAS_WIDTH / 2, y: r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS,
      vx: 0, vy: 0, radius: 28, color: '#00ffff', life: 1.0, type: 'beam'
    }]);
    for (let c = 0; c < colsInRow; c++) {
      if (newGrid[r][c]) {
        const b = newGrid[r][c]!;
        explode(b.x, b.y, '#ffffff', 16, 1.4);
        newGrid[r][c] = null;
        clearedCount++;
      }
    }
    const bonus = clearedCount * 25;
    setScore(s => { onScoreChange(s + bonus); return s + bonus; });
    return newGrid;
  }, [onScoreChange]);

  const triggerBomb = useCallback((r: number, c: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const center = newGrid[r][c];
    if (!center) return newGrid;
    audio.playBomb();
    setShake(30);
    explode(center.x, center.y, '#ff5500', 60, 1.8);
    let clearedCount = 0;
    const explosionRadius = BUBBLE_RADIUS * 6.5;
    for (let row = 0; row < GRID_ROWS; row++) {
      const cols = row % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let col = 0; col < cols; col++) {
        const b = newGrid[row][col];
        if (b) {
          const dist = getDistance(center.x, center.y, b.x, b.y);
          if (dist <= explosionRadius) {
            explode(b.x, b.y, palette[b.color] || '#ffffff', 12, 1.2);
            newGrid[row][col] = null;
            clearedCount++;
          }
        }
      }
    }
    newGrid[r][c] = null;
    const bonus = clearedCount * 20;
    setScore(s => { onScoreChange(s + bonus); return s + bonus; });
    return newGrid;
  }, [palette, onScoreChange]);

  const dropGrid = useCallback(() => {
    setGrid(oldGrid => {
      const newGrid: (Bubble | null)[][] = [];
      for (let r = 0; r < GRID_ROWS; r++) {
        newGrid[r] = [];
        const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
        if (r === 0) {
          for (let c = 0; c < colsInRow; c++) {
            newGrid[r][c] = generateBubble(r, c);
          }
        } else {
          const prevRow = oldGrid[r - 1];
          const prevCols = (r - 1) % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < colsInRow; c++) {
            const source = c < prevCols ? prevRow[c] : null;
            const { x, y } = getBubbleCoords(r, c);
            if (source) {
              newGrid[r][c] = { ...source, x, y, row: r, col: c };
            } else {
              newGrid[r][c] = null;
            }
          }
        }
      }
      if (newGrid[GRID_ROWS - 3].some(b => b !== null)) onGameOver(score);
      return newGrid;
    });
  }, [score, onGameOver, generateBubble]);

  const handleShoot = useCallback(() => {
    if (projectile || isPaused) return;
    const dx = mousePos.current.x - SHOOTER_X;
    const dy = mousePos.current.y - SHOOTER_Y;
    const angle = Math.atan2(dy, dx);
    const speed = PROJECTILE_BASE_SPEED + (level * 0.15);
    explode(SHOOTER_X, SHOOTER_Y, palette[activeColor] || '#ffffff', 18, 0.9);
    setShake(5);
    setProjectile({
      x: SHOOTER_X, y: SHOOTER_Y, vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed, color: activeColor
    });
    audio.playShoot();
    setShotsTaken(prev => prev + 1);
    setActiveColor(nextColor);
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [projectile, activeColor, nextColor, level, palette, availableColors, isPaused]);

  useEffect(() => {
    let animationFrameId: number;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const update = () => {
      if (!isPaused) {
        setParticles(prev => prev.map(p => ({
          ...p, x: p.x + p.vx, y: p.y + p.vy, vx: p.vx * 0.97, vy: p.vy * 0.97, life: p.life - (p.type === 'beam' ? 0.02 : 0.015)
        })).filter(p => p.life > 0));

        if (shake > 0) setShake(s => Math.max(0, s - 0.4));

        if (projectile) {
          // SUB_STEPS increased to 10 for ultra-high precision path tracing
          const SUB_STEPS = 10;
          let collided = false;
          let hitBubble: Bubble | null = null;
          let bestR = -1, bestC = -1;

          for (let i = 0; i < SUB_STEPS && !collided; i++) {
            projectile.x += projectile.vx / SUB_STEPS;
            projectile.y += projectile.vy / SUB_STEPS;

            // Bouncy walls 
            if (projectile.x - BUBBLE_RADIUS < 0) {
              projectile.x = BUBBLE_RADIUS;
              projectile.vx *= -1;
            } else if (projectile.x + BUBBLE_RADIUS > CANVAS_WIDTH) {
              projectile.x = CANVAS_WIDTH - BUBBLE_RADIUS;
              projectile.vx *= -1;
            }

            // Impact logic
            if (projectile.y - BUBBLE_RADIUS < 0) {
              collided = true;
              // Ceiling hit: Use a tiny back-step for more accurate row-0 slot finding
              const slot = findClosestEmptySlot(projectile.x, projectile.y + 1, grid);
              bestR = slot.bestR;
              bestC = slot.bestC;
            } else {
              for (let r = 0; r < GRID_ROWS; r++) {
                const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
                for (let c = 0; c < cols; c++) {
                  const b = grid[r][c];
                  if (b && getDistance(projectile.x, projectile.y, b.x, b.y) < BUBBLE_RADIUS * COLLISION_THRESHOLD) {
                    collided = true;
                    hitBubble = b;

                    /**
                     * Direction-Aware Snapping:
                     * Calculate slot based on the position just BEFORE deep penetration.
                     * This ensures that hitting a cluster from below doesn't snap to a slot above it.
                     */
                    const backX = projectile.x - (projectile.vx / SUB_STEPS) * 1.5;
                    const backY = projectile.y - (projectile.vy / SUB_STEPS) * 1.5;

                    const slot = findClosestEmptySlot(backX, backY, grid);
                    bestR = slot.bestR;
                    bestC = slot.bestC;
                  }
                }
              }
            }
          }

          if (collided) {
            let updatedGrid = [...grid.map(row => [...row])];
            if (hitBubble?.type === 'bomb') {
              updatedGrid = triggerBomb(hitBubble.row, hitBubble.col, updatedGrid);
            } else if (hitBubble?.type === 'laser') {
              updatedGrid = triggerLaser(hitBubble.row, updatedGrid);
            } else if (bestR !== -1) {
              const { x: px, y: py } = getBubbleCoords(bestR, bestC);
              updatedGrid[bestR][bestC] = { x: px, y: py, color: projectile.color, row: bestR, col: bestC, type: 'normal' };
              const matches: {r: number, c: number}[] = [{ r: bestR, c: bestC }];
              const visited = new Set<string>(); visited.add(`${bestR},${bestC}`);
              let mi = 0;
              while (mi < matches.length) {
                const curr = matches[mi++];
                for (const n of getNeighbors(curr.r, curr.c)) {
                  const b = updatedGrid[n.r][n.c];
                  if (b && b.color === projectile.color && b.type === 'normal' && !visited.has(`${n.r},${n.c}`)) {
                    visited.add(`${n.r},${n.c}`); matches.push(n);
                  }
                }
              }
              if (matches.length >= 3) {
                audio.playPop(450 + matches.length * 30);
                setShake(4 + matches.length * 0.7);
                matches.forEach(m => {
                  const b = updatedGrid[m.r][m.c];
                  if (b) explode(b.x, b.y, palette[b.color], 16, 1.1);
                  updatedGrid[m.r][m.c] = null;
                });
                setScore(s => { onScoreChange(s + matches.length * 20); return s + matches.length * 20; });
              } else {
                audio.playShoot();
              }
            }

            // Orphan pruning logic (anchoring)
            const anchored = new Set<string>();
            const q: {r: number, c: number}[] = [];
            for (let c = 0; c < GRID_COLS; c++) { if (updatedGrid[0][c]) { anchored.add(`0,${c}`); q.push({ r: 0, c }); } }
            let qi = 0;
            while (qi < q.length) {
              const curr = q[qi++];
              for (const n of getNeighbors(curr.r, curr.c)) {
                if (updatedGrid[n.r][n.c] && !anchored.has(`${n.r},${n.c}`)) {
                  anchored.add(`${n.r},${n.c}`); q.push(n);
                }
              }
            }
            let fallingCount = 0;
            for (let r = 0; r < GRID_ROWS; r++) {
              const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
              for (let c = 0; c < cols; c++) {
                if (updatedGrid[r][c] && !anchored.has(`${r},${c}`)) {
                  const b = updatedGrid[r][c]!;
                  explode(b.x, b.y, palette[b.color], 10, 0.9);
                  updatedGrid[r][c] = null;
                  fallingCount++;
                  setScore(s => { onScoreChange(s + 30); return s + 30; });
                }
              }
            }
            if (fallingCount > 0) audio.playPop(380);
            setGrid(updatedGrid);
            setProjectile(null);
            if (shotsTaken > 0 && shotsTaken % currentLevelShotsToDrop === 0) { dropGrid(); audio.playPop(250); setShake(6); }
            if (!updatedGrid.some(row => row.some(b => b !== null))) onWin();
            if (bestR >= GRID_ROWS - 3) onGameOver(score);
          }
        }
      }
      render();
      animationFrameId = requestAnimationFrame(update);
    };

    const drawBubble = (b: Bubble, radius: number = BUBBLE_RADIUS, alpha: number = 1.0) => {
      const { x, y, color, type } = b;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.beginPath();
      ctx.arc(x, y, radius - 1, 0, Math.PI * 2);
      if (type === 'bomb') { ctx.fillStyle = '#1e1e2e'; ctx.shadowBlur = 20; ctx.shadowColor = '#f97316'; } 
      else if (type === 'laser') { ctx.fillStyle = '#0f172a'; ctx.shadowBlur = 20; ctx.shadowColor = '#38bdf8'; } 
      else { ctx.fillStyle = palette[color]; ctx.shadowBlur = 14; ctx.shadowColor = palette[color]; }
      ctx.fill();
      if (type === 'bomb') { ctx.fillStyle = '#f97316'; ctx.beginPath(); ctx.arc(x, y, radius / 2, 0, Math.PI * 2); ctx.fill(); ctx.fillStyle = '#ffffff'; ctx.fillRect(x - 2, y - 10, 4, 12); } 
      else if (type === 'laser') { ctx.strokeStyle = '#38bdf8'; ctx.lineWidth = 5; ctx.beginPath(); ctx.moveTo(x - radius/2, y); ctx.lineTo(x + radius/2, y); ctx.stroke(); } 
      else { ctx.beginPath(); ctx.arc(x - radius/3, y - radius/3, radius/4, 0, Math.PI * 2); ctx.fillStyle = 'rgba(255,255,255,0.5)'; ctx.fill(); }
      ctx.restore();
    };

    const render = () => {
      ctx.save();
      if (shake > 0) ctx.translate(Math.random() * shake - shake/2, Math.random() * shake - shake/2);
      ctx.clearRect(-40, -40, CANVAS_WIDTH + 80, CANVAS_HEIGHT + 80);
      ctx.beginPath();
      ctx.strokeStyle = 'rgba(244, 63, 94, 0.3)';
      ctx.setLineDash([5, 5]);
      const dangerY = (GRID_ROWS - 3) * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS * 2;
      ctx.moveTo(0, dangerY); ctx.lineTo(CANVAS_WIDTH, dangerY); ctx.stroke(); ctx.setLineDash([]);
      grid.forEach(row => row.forEach(b => b && drawBubble(b)));

      const dx = mousePos.current.x - SHOOTER_X, dy = mousePos.current.y - SHOOTER_Y;
      const angle = Math.atan2(dy, dx);

      if (!isPaused) {
        ctx.beginPath(); 
        ctx.setLineDash([6, 8]); 
        ctx.lineWidth = 2.5; 
        ctx.moveTo(SHOOTER_X, SHOOTER_Y); 
        ctx.lineTo(SHOOTER_X + Math.cos(angle) * 160, SHOOTER_Y + Math.sin(angle) * 160); 
        ctx.strokeStyle = 'rgba(255,255,255,0.4)'; 
        ctx.stroke(); 
        ctx.setLineDash([]);
      }

      if (projectile) drawBubble({ x: projectile.x, y: projectile.y, color: projectile.color, row: 0, col: 0, type: 'normal' });

      particles.forEach(p => {
        if (p.type === 'beam') { ctx.save(); ctx.beginPath(); ctx.fillStyle = `rgba(0, 255, 255, ${p.life})`; ctx.fillRect(0, p.y - 15, CANVAS_WIDTH, 30); ctx.fillStyle = `rgba(255, 255, 255, ${p.life * 1.8})`; ctx.fillRect(0, p.y - 5, CANVAS_WIDTH, 10); ctx.restore(); } 
        else { ctx.save(); ctx.globalAlpha = p.life; ctx.beginPath(); ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2); ctx.fillStyle = p.color; ctx.fill(); ctx.restore(); }
      });

      const dropsIn = currentLevelShotsToDrop - (shotsTaken % currentLevelShotsToDrop);
      ctx.fillStyle = dropsIn <= 1 ? 'rgba(244, 63, 94, 1.0)' : 'rgba(255, 255, 255, 0.5)';
      ctx.font = '700 16px Luckiest Guy'; ctx.textAlign = 'left'; ctx.fillText(`THREAT IN: ${dropsIn}`, 20, CANVAS_HEIGHT - 20);

      drawBubble({ x: SHOOTER_X, y: SHOOTER_Y, color: activeColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS + 4);
      drawBubble({ x: SHOOTER_X + 80, y: SHOOTER_Y + 15, color: nextColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS * 0.8);

      ctx.fillStyle = 'rgba(255,255,255,0.7)'; ctx.font = '600 12px Fredoka'; ctx.textAlign = 'center'; ctx.fillText('NEXT', SHOOTER_X + 80, SHOOTER_Y + 45);
      ctx.restore();
    };
    update();
    return () => cancelAnimationFrame(animationFrameId);
  }, [grid, projectile, activeColor, nextColor, particles, onGameOver, onScoreChange, onWin, score, palette, shotsTaken, dropGrid, triggerBomb, triggerLaser, shake, level, currentLevelShotsToDrop, isPaused]);

  const handlePointer = (e: React.PointerEvent) => {
    if (isPaused) return;
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    mousePos.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onPointerMove={handlePointer}
      onPointerDown={(e) => { handlePointer(e); handleShoot(); }}
      className={`w-full h-full cursor-crosshair touch-none select-none transition-opacity ${isPaused ? 'opacity-50' : 'opacity-100'}`}
    />
  );
};

export default GameBoard;

export type BubbleColor = 'rose' | 'amber' | 'lime' | 'sky' | 'violet' | 'fuchsia';
export type BubbleType = 'normal' | 'bomb' | 'laser';

export interface Bubble {
  x: number;
  y: number;
  color: BubbleColor;
  row: number;
  col: number;
  type?: BubbleType;
}

export interface Projectile {
  x: number;
  y: number;
  vx: number;
  vy: number;
  color: BubbleColor;
  type: BubbleType;
}

export interface GameState {
  score: number;
  level: number;
  grid: (Bubble | null)[][];
  currentBubble: BubbleColor;
  nextBubble: BubbleColor;
  isGameOver: boolean;
  isWon: boolean;
}

export interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  radius: number;
  color: string;
  life: number;
  type?: 'sparkle' | 'smoke' | 'beam' | 'collection';
  targetX?: number;
  targetY?: number;
}

import React, { useRef, useEffect, useState, useCallback, useMemo } from 'react';
import { Bubble, BubbleColor, Projectile, Particle, BubbleType } from '../types';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, BUBBLE_RADIUS, GRID_ROWS, GRID_COLS, 
  COLOR_PALETTES, BUBBLE_COLORS, SHOOTER_X, SHOOTER_Y, 
  POWER_UP_CHANCE_BASE, PROJECTILE_BASE_SPEED, COLLISION_THRESHOLD,
  MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP
} from '../constants';
import { audio } from '../services/audioService';

interface GameBoardProps {
  level: number;
  isPaused: boolean;
  onScoreChange: (score: number) => void;
  onGameOver: (score: number) => void;
  onWin: () => void;
}

const GameBoard: React.FC<GameBoardProps> = ({ level, isPaused, onScoreChange, onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [score, setScore] = useState(0);
  const [grid, setGrid] = useState<(Bubble | null)[][]>([]);
  const [projectile, setProjectile] = useState<Projectile | null>(null);
  const [nextColor, setNextColor] = useState<BubbleColor>(BUBBLE_COLORS[0]);
  const [activeColor, setActiveColor] = useState<BubbleColor>(BUBBLE_COLORS[1]);
  const [storedPowerUp, setStoredPowerUp] = useState<BubbleType>('normal');
  const [particles, setParticles] = useState<Particle[]>([]);
  const [shotsTaken, setShotsTaken] = useState(0);
  const [shake, setShake] = useState(0);

  const mousePos = useRef({ x: SHOOTER_X, y: 0 });
  const pulseRef = useRef(0);
  const palette = COLOR_PALETTES[(level - 1) % COLOR_PALETTES.length];

  const currentLevelShotsToDrop = useMemo(() => 
    Math.max(MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP - Math.floor((level - 1) / 3)), 
  [level]);

  const activeColorCount = useMemo(() => 
    Math.min(6, 4 + Math.floor((level - 1) / 2)), 
  [level]);

  const availableColors = useMemo(() => 
    BUBBLE_COLORS.slice(0, activeColorCount), 
  [activeColorCount]);

  const getBubbleCoords = (r: number, c: number) => {
    const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
    const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
    return { x, y };
  };

  const generateBubble = useCallback((r: number, c: number): Bubble => {
    const { x, y } = getBubbleCoords(r, c);
    const powerUpChance = POWER_UP_CHANCE_BASE + (level * 0.005);
    const isPowerUp = Math.random() < powerUpChance;
    const type: BubbleType = isPowerUp ? (Math.random() > 0.5 ? 'bomb' : 'laser') : 'normal';

    return { 
      x, y, 
      color: availableColors[Math.floor(Math.random() * availableColors.length)],
      row: r,
      col: c,
      type
    };
  }, [availableColors, level]);

  useEffect(() => {
    const startRows = Math.min(GRID_ROWS - 4, 5 + Math.floor(level / 2));
    const newGrid: (Bubble | null)[][] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      newGrid[r] = [];
      const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < colsInRow; c++) {
        if (r < startRows) {
          newGrid[r][c] = generateBubble(r, c);
        } else {
          newGrid[r][c] = null;
        }
      }
    }
    setGrid(newGrid);
    setShotsTaken(0);
    setStoredPowerUp('normal');
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
    setActiveColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [level, generateBubble, availableColors]);

  const getDistance = (x1: number, y1: number, x2: number, y2: number) => {
    return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);
  };

  const getNeighbors = (r: number, c: number) => {
    const neighbors: { r: number, c: number }[] = [];
    const offsets = r % 2 === 0 
      ? [{ dr: -1, dc: -1 }, { dr: -1, dc: 0 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: -1 }, { dr: 1, dc: 0 }]
      : [{ dr: -1, dc: 0 }, { dr: -1, dc: 1 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: 0 }, { dr: 1, dc: 1 }];

    for (const off of offsets) {
      const nr = r + off.dr;
      const nc = c + off.dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
        neighbors.push({ r: nr, c: nc });
      }
    }
    return neighbors;
  };

  const findClosestEmptySlot = (targetX: number, targetY: number, currentGrid: (Bubble | null)[][]) => {
    let bestR = -1;
    let bestC = -1;
    let minD = Infinity;

    const approxR = Math.round((targetY - BUBBLE_RADIUS) / (BUBBLE_RADIUS * 1.732));
    const startR = Math.max(0, approxR - 1);
    const endR = Math.min(GRID_ROWS - 1, approxR + 2);

    for (let r = startR; r <= endR; r++) {
      const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      const offsetX = r % 2 === 0 ? BUBBLE_RADIUS : BUBBLE_RADIUS * 2;
      const approxC = Math.round((targetX - offsetX) / (BUBBLE_RADIUS * 2));
      const startC = Math.max(0, approxC - 1);
      const endC = Math.min(cols - 1, approxC + 1);

      for (let c = startC; c <= endC; c++) {
        if (!currentGrid[r][c]) {
          const { x, y } = getBubbleCoords(r, c);
          const d = getDistance(targetX, targetY, x, y);
          if (d < minD) {
            minD = d;
            bestR = r;
            bestC = c;
          }
        }
      }
    }

    if (bestR === -1) {
       for (let r = 0; r < GRID_ROWS; r++) {
          const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < cols; c++) {
            if (!currentGrid[r][c]) return { bestR: r, bestC: c };
          }
       }
    }

    return { bestR, bestC };
  };

  const explode = (x: number, y: number, color: string, count: number = 12, velocityMult: number = 1.0) => {
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      newParticles.push({
        x, y,
        vx: (Math.random() - 0.5) * 12 * velocityMult,
        vy: (Math.random() - 0.5) * 12 * velocityMult,
        radius: Math.random() * 5 + 1.5,
        color,
        life: 1.0
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
  };

  const triggerLaser = useCallback((r: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
    let clearedCount = 0;
    audio.playLaser();
    setShake(10);
    setParticles(prev => [...prev, {
      x: CANVAS_WIDTH / 2, y: r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS,
      vx: 0, vy: 0, radius: 28, color: '#00ffff', life: 1.0, type: 'beam'
    }]);
    for (let c = 0; c < colsInRow; c++) {
      if (newGrid[r][c]) {
        const b = newGrid[r][c]!;
        explode(b.x, b.y, '#ffffff', 16, 1.4);
        newGrid[r][c] = null;
        clearedCount++;
      }
    }
    const bonus = clearedCount * 25;
    setScore(s => { onScoreChange(s + bonus); return s + bonus; });
    return newGrid;
  }, [onScoreChange]);

  const triggerBomb = useCallback((r: number, c: number, currentGrid: (Bubble | null)[][], centerX?: number, centerY?: number) => {
    const newGrid = [...currentGrid.map(row => [...row])];

    // Determine the explosion center
    let cx = centerX;
    let cy = centerY;
    if (cx === undefined || cy === undefined) {
      const b = newGrid[r]?.[c];
      if (b) { cx = b.x; cy = b.y; }
      else { const coords = getBubbleCoords(r, c); cx = coords.x; cy = coords.y; }
    }

    audio.playBomb();
    setShake(30);
    explode(cx, cy, '#ff5500', 60, 1.8);
    let clearedCount = 0;
    const explosionRadius = BUBBLE_RADIUS * 6.5;
    for (let row = 0; row < GRID_ROWS; row++) {
      const cols = row % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let col = 0; col < cols; col++) {
        const b = newGrid[row][col];
        if (b) {
          const dist = getDistance(cx, cy, b.x, b.y);
          if (dist <= explosionRadius) {
            explode(b.x, b.y, palette[b.color] || '#ffffff', 12, 1.2);
            newGrid[row][col] = null;
            clearedCount++;
          }
        }
      }
    }
    if (newGrid[r] && newGrid[r][c] !== undefined) newGrid[r][c] = null;
    const bonus = clearedCount * 20;
    setScore(s => { onScoreChange(s + bonus); return s + bonus; });
    return newGrid;
  }, [palette, onScoreChange]);

  const collectPowerUp = useCallback((type: BubbleType, startX: number, startY: number) => {
    if (type === 'normal') return;
    setStoredPowerUp(type);
    audio.playWin(); // Use win sound for collection
    setParticles(prev => [...prev, {
      x: startX, y: startY,
      vx: 0, vy: 0, radius: 10,
      color: type === 'bomb' ? '#f97316' : '#38bdf8',
      life: 1.0, type: 'collection',
      targetX: SHOOTER_X, targetY: SHOOTER_Y
    }]);
  }, []);

  const dropGrid = useCallback(() => {
    setGrid(oldGrid => {
      const newGrid: (Bubble | null)[][] = [];
      for (let r = 0; r < GRID_ROWS; r++) {
        newGrid[r] = [];
        const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
        if (r === 0) {
          for (let c = 0; c < colsInRow; c++) {
            newGrid[r][c] = generateBubble(r, c);
          }
        } else {
          const prevRow = oldGrid[r - 1];
          const prevCols = (r - 1) % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < colsInRow; c++) {
            const source = c < prevCols ? prevRow[c] : null;
            const { x, y } = getBubbleCoords(r, c);
            if (source) {
              newGrid[r][c] = { ...source, x, y, row: r, col: c };
            } else {
              newGrid[r][c] = null;
            }
          }
        }
      }
      if (newGrid[GRID_ROWS - 3].some(b => b !== null)) onGameOver(score);
      return newGrid;
    });
  }, [score, onGameOver, generateBubble]);

  const handleShoot = useCallback(() => {
    if (projectile || isPaused) return;
    const dx = mousePos.current.x - SHOOTER_X;
    const dy = mousePos.current.y - SHOOTER_Y;
    const angle = Math.atan2(dy, dx);
    const speed = PROJECTILE_BASE_SPEED + (level * 0.15);
    explode(SHOOTER_X, SHOOTER_Y, palette[activeColor] || '#ffffff', 18, 0.9);
    setShake(5);

    setProjectile({
      x: SHOOTER_X, y: SHOOTER_Y, 
      vx: Math.cos(angle) * speed, 
      vy: Math.sin(angle) * speed, 
      color: activeColor,
      type: storedPowerUp
    });

    audio.playShoot();
    setStoredPowerUp('normal'); // Use it up
    setShotsTaken(prev => prev + 1);
    setActiveColor(nextColor);
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [projectile, activeColor, nextColor, level, palette, availableColors, isPaused, storedPowerUp]);

  useEffect(() => {
    let animationFrameId: number;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const update = () => {
      pulseRef.current += 0.05;
      if (!isPaused) {
        setParticles(prev => prev.map(p => {
          if (p.type === 'collection' && p.targetX !== undefined && p.targetY !== undefined) {
             const dx = p.targetX - p.x;
             const dy = p.targetY - p.y;
             return { ...p, x: p.x + dx * 0.1, y: p.y + dy * 0.1, life: p.life - 0.01 };
          }
          return {
            ...p, x: p.x + p.vx, y: p.y + p.vy, vx: p.vx * 0.97, vy: p.vy * 0.97, life: p.life - (p.type === 'beam' ? 0.02 : 0.015)
          };
        }).filter(p => p.life > 0));

        if (shake > 0) setShake(s => Math.max(0, s - 0.4));

        if (projectile) {
          const SUB_STEPS = 10;
          let collided = false;
          let hitBubble: Bubble | null = null;
          let bestR = -1, bestC = -1;

          for (let i = 0; i < SUB_STEPS && !collided; i++) {
            projectile.x += projectile.vx / SUB_STEPS;
            projectile.y += projectile.vy / SUB_STEPS;

            if (projectile.x - BUBBLE_RADIUS < 0) {
              projectile.x = BUBBLE_RADIUS;
              projectile.vx *= -1;
            } else if (projectile.x + BUBBLE_RADIUS > CANVAS_WIDTH) {
              projectile.x = CANVAS_WIDTH - BUBBLE_RADIUS;
              projectile.vx *= -1;
            }

            if (projectile.y - BUBBLE_RADIUS < 0) {
              collided = true;
              const slot = findClosestEmptySlot(projectile.x, projectile.y + 1, grid);
              bestR = slot.bestR;
              bestC = slot.bestC;
            } else {
              for (let r = 0; r < GRID_ROWS; r++) {
                const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
                for (let c = 0; c < cols; c++) {
                  const b = grid[r][c];
                  if (b && getDistance(projectile.x, projectile.y, b.x, b.y) < BUBBLE_RADIUS * COLLISION_THRESHOLD) {
                    collided = true;
                    hitBubble = b;
                    const backX = projectile.x - (projectile.vx / SUB_STEPS) * 1.5;
                    const backY = projectile.y - (projectile.vy / SUB_STEPS) * 1.5;
                    const slot = findClosestEmptySlot(backX, backY, grid);
                    bestR = slot.bestR;
                    bestC = slot.bestC;
                  }
                }
              }
            }
          }

          if (collided) {
            let updatedGrid = [...grid.map(row => [...row])];

            // Check if special projectile hit anything
            if (projectile.type === 'bomb') {
              updatedGrid = triggerBomb(bestR, bestC, updatedGrid, projectile.x, projectile.y);
            } else if (projectile.type === 'laser') {
              updatedGrid = triggerLaser(bestR === -1 ? 0 : bestR, updatedGrid);
            } else {
              // Standard projectile logic
              if (hitBubble?.type === 'bomb') {
                collectPowerUp('bomb', hitBubble.x, hitBubble.y);
                updatedGrid[hitBubble.row][hitBubble.col] = null;
              } else if (hitBubble?.type === 'laser') {
                collectPowerUp('laser', hitBubble.x, hitBubble.y);
                updatedGrid[hitBubble.row][hitBubble.col] = null;
              } else if (bestR !== -1) {
                const { x: px, y: py } = getBubbleCoords(bestR, bestC);
                updatedGrid[bestR][bestC] = { x: px, y: py, color: projectile.color, row: bestR, col: bestC, type: 'normal' };
                const matches: {r: number, c: number}[] = [{ r: bestR, c: bestC }];
                const visited = new Set<string>(); visited.add(`${bestR},${bestC}`);
                let mi = 0;
                while (mi < matches.length) {
                  const curr = matches[mi++];
                  for (const n of getNeighbors(curr.r, curr.c)) {
                    const b = updatedGrid[n.r][n.c];
                    if (b && b.color === projectile.color && b.type === 'normal' && !visited.has(`${n.r},${n.c}`)) {
                      visited.add(`${n.r},${n.c}`); matches.push(n);
                    }
                  }
                }
                if (matches.length >= 3) {
                  audio.playPop(450 + matches.length * 30);
                  setShake(4 + matches.length * 0.7);
                  matches.forEach(m => {
                    const b = updatedGrid[m.r][m.c];
                    if (b) {
                      explode(b.x, b.y, palette[b.color], 16, 1.1);
                      if (b.type && b.type !== 'normal') collectPowerUp(b.type, b.x, b.y);
                    }
                    updatedGrid[m.r][m.c] = null;
                  });
                  setScore(s => { onScoreChange(s + matches.length * 20); return s + matches.length * 20; });
                } else {
                  audio.playShoot();
                }
              }
            }

            const anchored = new Set<string>();
            const q: {r: number, c: number}[] = [];
            for (let c = 0; c < GRID_COLS; c++) { if (updatedGrid[0][c]) { anchored.add(`0,${c}`); q.push({ r: 0, c }); } }
            let qi = 0;
            while (qi < q.length) {
              const curr = q[qi++];
              for (const n of getNeighbors(curr.r, curr.c)) {
                if (updatedGrid[n.r][n.c] && !anchored.has(`${n.r},${n.c}`)) {
                  anchored.add(`${n.r},${n.c}`); q.push(n);
                }
              }
            }
            let fallingCount = 0;
            for (let r = 0; r < GRID_ROWS; r++) {
              const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
              for (let c = 0; c < cols; c++) {
                if (updatedGrid[r][c] && !anchored.has(`${r},${c}`)) {
                  const b = updatedGrid[r][c]!;
                  explode(b.x, b.y, palette[b.color], 10, 0.9);
                  if (b.type && b.type !== 'normal') collectPowerUp(b.type, b.x, b.y);
                  updatedGrid[r][c] = null;
                  fallingCount++;
                  setScore(s => { onScoreChange(s + 30); return s + 30; });
                }
              }
            }
            if (fallingCount > 0) audio.playPop(380);
            setGrid(updatedGrid);
            setProjectile(null);
            if (shotsTaken > 0 && shotsTaken % currentLevelShotsToDrop === 0) { dropGrid(); audio.playPop(250); setShake(6); }
            if (!updatedGrid.some(row => row.some(b => b !== null))) onWin();
            if (bestR >= GRID_ROWS - 3) onGameOver(score);
          }
        }
      }
      render();
      animationFrameId = requestAnimationFrame(update);
    };

    const drawBubble = (b: Bubble | Projectile, radius: number = BUBBLE_RADIUS, alpha: number = 1.0) => {
      const { x, y, color, type } = b;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.beginPath();
      ctx.arc(x, y, radius - 1, 0, Math.PI * 2);
      if (type === 'bomb') { ctx.fillStyle = '#1e1e2e'; ctx.shadowBlur = 20; ctx.shadowColor = '#f97316'; } 
      else if (type === 'laser') { ctx.fillStyle = '#0f172a'; ctx.shadowBlur = 20; ctx.shadowColor = '#38bdf8'; } 
      else { ctx.fillStyle = palette[color]; ctx.shadowBlur = 14; ctx.shadowColor = palette[color]; }
      ctx.fill();
      if (type === 'bomb') { ctx.fillStyle = '#f97316'; ctx.beginPath(); ctx.arc(x, y, radius / 2, 0, Math.PI * 2); ctx.fill(); ctx.fillStyle = '#ffffff'; ctx.fillRect(x - 2, y - 10, 4, 12); } 
      else if (type === 'laser') { ctx.strokeStyle = '#38bdf8'; ctx.lineWidth = 5; ctx.beginPath(); ctx.moveTo(x - radius/2, y); ctx.lineTo(x + radius/2, y); ctx.stroke(); } 
      else { ctx.beginPath(); ctx.arc(x - radius/3, y - radius/3, radius/4, 0, Math.PI * 2); ctx.fillStyle = 'rgba(255,255,255,0.5)'; ctx.fill(); }
      ctx.restore();
    };

    const render = () => {
      ctx.save();
      if (shake > 0) ctx.translate(Math.random() * shake - shake/2, Math.random() * shake - shake/2);
      ctx.clearRect(-40, -40, CANVAS_WIDTH + 80, CANVAS_HEIGHT + 80);
      ctx.beginPath();
      ctx.strokeStyle = 'rgba(244, 63, 94, 0.3)';
      ctx.setLineDash([5, 5]);
      const dangerY = (GRID_ROWS - 3) * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS * 2;
      ctx.moveTo(0, dangerY); ctx.lineTo(CANVAS_WIDTH, dangerY); ctx.stroke(); ctx.setLineDash([]);
      grid.forEach(row => row.forEach(b => b && drawBubble(b)));

      const dx = mousePos.current.x - SHOOTER_X, dy = mousePos.current.y - SHOOTER_Y;
      const angle = Math.atan2(dy, dx);

      if (!isPaused) {
        ctx.beginPath(); 
        ctx.setLineDash([6, 8]); 
        ctx.lineWidth = 2.5; 
        ctx.moveTo(SHOOTER_X, SHOOTER_Y); 
        ctx.lineTo(SHOOTER_X + Math.cos(angle) * 160, SHOOTER_Y + Math.sin(angle) * 160); 
        ctx.strokeStyle = 'rgba(255,255,255,0.4)'; 
        ctx.stroke(); 
        ctx.setLineDash([]);
      }

      if (projectile) drawBubble(projectile);

      particles.forEach(p => {
        if (p.type === 'beam') { ctx.save(); ctx.beginPath(); ctx.fillStyle = `rgba(0, 255, 255, ${p.life})`; ctx.fillRect(0, p.y - 15, CANVAS_WIDTH, 30); ctx.fillStyle = `rgba(255, 255, 255, ${p.life * 1.8})`; ctx.fillRect(0, p.y - 5, CANVAS_WIDTH, 10); ctx.restore(); } 
        else { ctx.save(); ctx.globalAlpha = p.life; ctx.beginPath(); ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2); ctx.fillStyle = p.color; ctx.fill(); ctx.restore(); }
      });

      const dropsIn = currentLevelShotsToDrop - (shotsTaken % currentLevelShotsToDrop);
      ctx.fillStyle = dropsIn <= 1 ? 'rgba(244, 63, 94, 1.0)' : 'rgba(255, 255, 255, 0.5)';
      ctx.font = '700 16px Luckiest Guy'; ctx.textAlign = 'left'; ctx.fillText(`THREAT IN: ${dropsIn}`, 20, CANVAS_HEIGHT - 20);

      // HUD Power-up slot
      if (storedPowerUp !== 'normal') {
        const glowScale = 1 + Math.sin(pulseRef.current * 4) * 0.1;
        ctx.save();
        ctx.shadowBlur = 20;
        ctx.shadowColor = storedPowerUp === 'bomb' ? '#f97316' : '#38bdf8';
        drawBubble({ x: CANVAS_WIDTH - 40, y: CANVAS_HEIGHT - 30, color: 'sky', row: 0, col: 0, type: storedPowerUp }, BUBBLE_RADIUS * glowScale);
        ctx.fillStyle = 'white';
        ctx.font = '800 10px Fredoka';
        ctx.textAlign = 'center';
        ctx.fillText('READY!', CANVAS_WIDTH - 40, CANVAS_HEIGHT - 5);
        ctx.restore();

        // Shooter Aura
        ctx.save();
        ctx.globalAlpha = 0.3 + Math.sin(pulseRef.current * 4) * 0.2;
        ctx.beginPath();
        ctx.arc(SHOOTER_X, SHOOTER_Y, BUBBLE_RADIUS + 15, 0, Math.PI * 2);
        ctx.fillStyle = storedPowerUp === 'bomb' ? '#f97316' : '#38bdf8';
        ctx.fill();
        ctx.restore();
      }

      drawBubble({ x: SHOOTER_X, y: SHOOTER_Y, color: activeColor, row: 0, col: 0, type: storedPowerUp }, BUBBLE_RADIUS + 4);
      drawBubble({ x: SHOOTER_X + 80, y: SHOOTER_Y + 15, color: nextColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS * 0.8);

      ctx.fillStyle = 'rgba(255,255,255,0.7)'; ctx.font = '600 12px Fredoka'; ctx.textAlign = 'center'; ctx.fillText('NEXT', SHOOTER_X + 80, SHOOTER_Y + 45);
      ctx.restore();
    };
    update();
    return () => cancelAnimationFrame(animationFrameId);
  }, [grid, projectile, activeColor, nextColor, particles, onGameOver, onScoreChange, onWin, score, palette, shotsTaken, dropGrid, triggerBomb, triggerLaser, shake, level, currentLevelShotsToDrop, isPaused, storedPowerUp, collectPowerUp]);

  const handlePointer = (e: React.PointerEvent) => {
    if (isPaused) return;
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    mousePos.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onPointerMove={handlePointer}
      onPointerDown={(e) => { handlePointer(e); handleShoot(); }}
      className={`w-full h-full cursor-crosshair touch-none select-none transition-opacity ${isPaused ? 'opacity-50' : 'opacity-100'}`}
    />
  );
};

export default GameBoard;

import React, { useRef, useEffect, useState, useCallback, useMemo } from 'react';
import { Bubble, BubbleColor, Projectile, Particle, BubbleType } from '../types';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, BUBBLE_RADIUS, GRID_ROWS, GRID_COLS, 
  COLOR_PALETTES, BUBBLE_COLORS, SHOOTER_X, SHOOTER_Y, 
  POWER_UP_CHANCE_BASE, PROJECTILE_BASE_SPEED, COLLISION_THRESHOLD,
  MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP
} from '../constants';
import { audio } from '../services/audioService';

interface GameBoardProps {
  level: number;
  isPaused: boolean;
  onScoreChange: (score: number) => void;
  onGameOver: (score: number) => void;
  onWin: () => void;
}

const GameBoard: React.FC<GameBoardProps> = ({ level, isPaused, onScoreChange, onGameOver, onWin }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [score, setScore] = useState(0);
  const [grid, setGrid] = useState<(Bubble | null)[][]>([]);
  const [projectile, setProjectile] = useState<Projectile | null>(null);
  const [nextColor, setNextColor] = useState<BubbleColor>(BUBBLE_COLORS[0]);
  const [activeColor, setActiveColor] = useState<BubbleColor>(BUBBLE_COLORS[1]);
  const [storedPowerUp, setStoredPowerUp] = useState<BubbleType>('normal');
  const [particles, setParticles] = useState<Particle[]>([]);
  const [shotsTaken, setShotsTaken] = useState(0);
  const [shake, setShake] = useState(0);
  const [showGoal, setShowGoal] = useState(false);

  const mousePos = useRef({ x: SHOOTER_X, y: 0 });
  const pulseRef = useRef(0);
  const palette = COLOR_PALETTES[(level - 1) % COLOR_PALETTES.length];

  const currentLevelShotsToDrop = useMemo(() => 
    Math.max(MIN_SHOTS_TO_DROP, MAX_SHOTS_TO_DROP - Math.floor((level - 1) / 3)), 
  [level]);

  const activeColorCount = useMemo(() => 
    Math.min(6, 4 + Math.floor((level - 1) / 2)), 
  [level]);

  const availableColors = useMemo(() => 
    BUBBLE_COLORS.slice(0, activeColorCount), 
  [activeColorCount]);

  const getBubbleCoords = (r: number, c: number) => {
    const x = (r % 2 === 0 ? c * BUBBLE_RADIUS * 2 : c * BUBBLE_RADIUS * 2 + BUBBLE_RADIUS) + BUBBLE_RADIUS;
    const y = r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS;
    return { x, y };
  };

  const generateBubble = useCallback((r: number, c: number): Bubble => {
    const { x, y } = getBubbleCoords(r, c);
    const powerUpChance = POWER_UP_CHANCE_BASE + (level * 0.005);
    const isPowerUp = Math.random() < powerUpChance;
    const type: BubbleType = isPowerUp ? (Math.random() > 0.5 ? 'bomb' : 'laser') : 'normal';

    return { 
      x, y, 
      color: availableColors[Math.floor(Math.random() * availableColors.length)],
      row: r,
      col: c,
      type
    };
  }, [availableColors, level]);

  useEffect(() => {
    const startRows = Math.min(GRID_ROWS - 4, 5 + Math.floor(level / 2));
    const newGrid: (Bubble | null)[][] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      newGrid[r] = [];
      const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let c = 0; c < colsInRow; c++) {
        if (r < startRows) {
          newGrid[r][c] = generateBubble(r, c);
        } else {
          newGrid[r][c] = null;
        }
      }
    }
    setGrid(newGrid);
    setShotsTaken(0);
    setStoredPowerUp('normal');
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
    setActiveColor(availableColors[Math.floor(Math.random() * availableColors.length)]);

    // Show level goal overlay
    setShowGoal(true);
    const timer = setTimeout(() => setShowGoal(false), 2500);
    return () => clearTimeout(timer);
  }, [level, generateBubble, availableColors]);

  const getDistance = (x1: number, y1: number, x2: number, y2: number) => {
    return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);
  };

  const getNeighbors = (r: number, c: number) => {
    const neighbors: { r: number, c: number }[] = [];
    const offsets = r % 2 === 0 
      ? [{ dr: -1, dc: -1 }, { dr: -1, dc: 0 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: -1 }, { dr: 1, dc: 0 }]
      : [{ dr: -1, dc: 0 }, { dr: -1, dc: 1 }, { dr: 0, dc: -1 }, { dr: 0, dc: 1 }, { dr: 1, dc: 0 }, { dr: 1, dc: 1 }];

    for (const off of offsets) {
      const nr = r + off.dr;
      const nc = c + off.dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < (nr % 2 === 0 ? GRID_COLS : GRID_COLS - 1)) {
        neighbors.push({ r: nr, c: nc });
      }
    }
    return neighbors;
  };

  const findClosestEmptySlot = (targetX: number, targetY: number, currentGrid: (Bubble | null)[][]) => {
    let bestR = -1;
    let bestC = -1;
    let minD = Infinity;

    const approxR = Math.round((targetY - BUBBLE_RADIUS) / (BUBBLE_RADIUS * 1.732));
    const startR = Math.max(0, approxR - 1);
    const endR = Math.min(GRID_ROWS - 1, approxR + 2);

    for (let r = startR; r <= endR; r++) {
      const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      const offsetX = r % 2 === 0 ? BUBBLE_RADIUS : BUBBLE_RADIUS * 2;
      const approxC = Math.round((targetX - offsetX) / (BUBBLE_RADIUS * 2));
      const startC = Math.max(0, approxC - 1);
      const endC = Math.min(cols - 1, approxC + 1);

      for (let c = startC; c <= endC; c++) {
        if (!currentGrid[r][c]) {
          const { x, y } = getBubbleCoords(r, c);
          const d = getDistance(targetX, targetY, x, y);
          if (d < minD) {
            minD = d;
            bestR = r;
            bestC = c;
          }
        }
      }
    }

    if (bestR === -1) {
       for (let r = 0; r < GRID_ROWS; r++) {
          const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < cols; c++) {
            if (!currentGrid[r][c]) return { bestR: r, bestC: c };
          }
       }
    }

    return { bestR, bestC };
  };

  const explode = (x: number, y: number, color: string, count: number = 12, velocityMult: number = 1.0) => {
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      newParticles.push({
        x, y,
        vx: (Math.random() - 0.5) * 12 * velocityMult,
        vy: (Math.random() - 0.5) * 12 * velocityMult,
        radius: Math.random() * 5 + 1.5,
        color,
        life: 1.0
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
  };

  const triggerLaser = useCallback((r: number, currentGrid: (Bubble | null)[][]) => {
    const newGrid = [...currentGrid.map(row => [...row])];
    const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
    let clearedCount = 0;
    audio.playLaser();
    setShake(10);
    setParticles(prev => [...prev, {
      x: CANVAS_WIDTH / 2, y: r * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS,
      vx: 0, vy: 0, radius: 28, color: '#00ffff', life: 1.0, type: 'beam'
    }]);
    for (let c = 0; c < colsInRow; c++) {
      if (newGrid[r][c]) {
        const b = newGrid[r][c]!;
        explode(b.x, b.y, '#ffffff', 16, 1.4);
        newGrid[r][c] = null;
        clearedCount++;
      }
    }
    const bonus = clearedCount * 25;
    setScore(s => { onScoreChange(s + bonus); return s + bonus; });
    return newGrid;
  }, [onScoreChange]);

  const triggerBomb = useCallback((r: number, c: number, currentGrid: (Bubble | null)[][], centerX?: number, centerY?: number) => {
    const newGrid = [...currentGrid.map(row => [...row])];

    let cx = centerX;
    let cy = centerY;
    if (cx === undefined || cy === undefined) {
      const b = newGrid[r]?.[c];
      if (b) { cx = b.x; cy = b.y; }
      else { const coords = getBubbleCoords(r, c); cx = coords.x; cy = coords.y; }
    }

    audio.playBomb();
    setShake(30);
    explode(cx, cy, '#ff5500', 60, 1.8);
    let clearedCount = 0;
    const explosionRadius = BUBBLE_RADIUS * 6.5;
    for (let row = 0; row < GRID_ROWS; row++) {
      const cols = row % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
      for (let col = 0; col < cols; col++) {
        const b = newGrid[row][col];
        if (b) {
          const dist = getDistance(cx, cy, b.x, b.y);
          if (dist <= explosionRadius) {
            explode(b.x, b.y, palette[b.color] || '#ffffff', 12, 1.2);
            newGrid[row][col] = null;
            clearedCount++;
          }
        }
      }
    }
    if (newGrid[r] && newGrid[r][c] !== undefined) newGrid[r][c] = null;
    const bonus = clearedCount * 20;
    setScore(s => { onScoreChange(s + bonus); return s + bonus; });
    return newGrid;
  }, [palette, onScoreChange]);

  const collectPowerUp = useCallback((type: BubbleType, startX: number, startY: number) => {
    if (type === 'normal') return;
    setStoredPowerUp(type);
    audio.playWin(); 
    setParticles(prev => [...prev, {
      x: startX, y: startY,
      vx: 0, vy: 0, radius: 10,
      color: type === 'bomb' ? '#f97316' : '#38bdf8',
      life: 1.0, type: 'collection',
      targetX: SHOOTER_X, targetY: SHOOTER_Y
    }]);
  }, []);

  const dropGrid = useCallback(() => {
    setGrid(oldGrid => {
      const newGrid: (Bubble | null)[][] = [];
      for (let r = 0; r < GRID_ROWS; r++) {
        newGrid[r] = [];
        const colsInRow = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
        if (r === 0) {
          for (let c = 0; c < colsInRow; c++) {
            newGrid[r][c] = generateBubble(r, c);
          }
        } else {
          const prevRow = oldGrid[r - 1];
          const prevCols = (r - 1) % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
          for (let c = 0; c < colsInRow; c++) {
            const source = c < prevCols ? prevRow[c] : null;
            const { x, y } = getBubbleCoords(r, c);
            if (source) {
              newGrid[r][c] = { ...source, x, y, row: r, col: c };
            } else {
              newGrid[r][c] = null;
            }
          }
        }
      }
      if (newGrid[GRID_ROWS - 3].some(b => b !== null)) onGameOver(score);
      return newGrid;
    });
  }, [score, onGameOver, generateBubble]);

  const handleShoot = useCallback(() => {
    if (projectile || isPaused) return;
    const dx = mousePos.current.x - SHOOTER_X;
    const dy = mousePos.current.y - SHOOTER_Y;
    const angle = Math.atan2(dy, dx);
    const speed = PROJECTILE_BASE_SPEED + (level * 0.15);
    explode(SHOOTER_X, SHOOTER_Y, palette[activeColor] || '#ffffff', 18, 0.9);
    setShake(5);

    setProjectile({
      x: SHOOTER_X, y: SHOOTER_Y, 
      vx: Math.cos(angle) * speed, 
      vy: Math.sin(angle) * speed, 
      color: activeColor,
      type: storedPowerUp
    });

    audio.playShoot();
    setStoredPowerUp('normal'); 
    setShotsTaken(prev => prev + 1);
    setActiveColor(nextColor);
    setNextColor(availableColors[Math.floor(Math.random() * availableColors.length)]);
  }, [projectile, activeColor, nextColor, level, palette, availableColors, isPaused, storedPowerUp]);

  useEffect(() => {
    let animationFrameId: number;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const update = () => {
      pulseRef.current += 0.05;
      if (!isPaused) {
        setParticles(prev => prev.map(p => {
          if (p.type === 'collection' && p.targetX !== undefined && p.targetY !== undefined) {
             const dx = p.targetX - p.x;
             const dy = p.targetY - p.y;
             return { ...p, x: p.x + dx * 0.1, y: p.y + dy * 0.1, life: p.life - 0.01 };
          }
          return {
            ...p, x: p.x + p.vx, y: p.y + p.vy, vx: p.vx * 0.97, vy: p.vy * 0.97, life: p.life - (p.type === 'beam' ? 0.02 : 0.015)
          };
        }).filter(p => p.life > 0));

        if (shake > 0) setShake(s => Math.max(0, s - 0.4));

        if (projectile) {
          const SUB_STEPS = 10;
          let collided = false;
          let hitBubble: Bubble | null = null;
          let bestR = -1, bestC = -1;

          for (let i = 0; i < SUB_STEPS && !collided; i++) {
            projectile.x += projectile.vx / SUB_STEPS;
            projectile.y += projectile.vy / SUB_STEPS;

            if (projectile.x - BUBBLE_RADIUS < 0) {
              projectile.x = BUBBLE_RADIUS;
              projectile.vx *= -1;
            } else if (projectile.x + BUBBLE_RADIUS > CANVAS_WIDTH) {
              projectile.x = CANVAS_WIDTH - BUBBLE_RADIUS;
              projectile.vx *= -1;
            }

            if (projectile.y - BUBBLE_RADIUS < 0) {
              collided = true;
              const slot = findClosestEmptySlot(projectile.x, projectile.y + 1, grid);
              bestR = slot.bestR;
              bestC = slot.bestC;
            } else {
              for (let r = 0; r < GRID_ROWS; r++) {
                const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
                for (let c = 0; c < cols; c++) {
                  const b = grid[r][c];
                  if (b && getDistance(projectile.x, projectile.y, b.x, b.y) < BUBBLE_RADIUS * COLLISION_THRESHOLD) {
                    collided = true;
                    hitBubble = b;
                    const backX = projectile.x - (projectile.vx / SUB_STEPS) * 1.5;
                    const backY = projectile.y - (projectile.vy / SUB_STEPS) * 1.5;
                    const slot = findClosestEmptySlot(backX, backY, grid);
                    bestR = slot.bestR;
                    bestC = slot.bestC;
                  }
                }
              }
            }
          }

          if (collided) {
            let updatedGrid = [...grid.map(row => [...row])];

            if (projectile.type === 'bomb') {
              updatedGrid = triggerBomb(bestR, bestC, updatedGrid, projectile.x, projectile.y);
            } else if (projectile.type === 'laser') {
              updatedGrid = triggerLaser(bestR === -1 ? 0 : bestR, updatedGrid);
            } else {
              if (hitBubble?.type === 'bomb') {
                collectPowerUp('bomb', hitBubble.x, hitBubble.y);
                updatedGrid[hitBubble.row][hitBubble.col] = null;
              } else if (hitBubble?.type === 'laser') {
                collectPowerUp('laser', hitBubble.x, hitBubble.y);
                updatedGrid[hitBubble.row][hitBubble.col] = null;
              } else if (bestR !== -1) {
                const { x: px, y: py } = getBubbleCoords(bestR, bestC);
                updatedGrid[bestR][bestC] = { x: px, y: py, color: projectile.color, row: bestR, col: bestC, type: 'normal' };
                const matches: {r: number, c: number}[] = [{ r: bestR, c: bestC }];
                const visited = new Set<string>(); visited.add(`${bestR},${bestC}`);
                let mi = 0;
                while (mi < matches.length) {
                  const curr = matches[mi++];
                  for (const n of getNeighbors(curr.r, curr.c)) {
                    const b = updatedGrid[n.r][n.c];
                    if (b && b.color === projectile.color && b.type === 'normal' && !visited.has(`${n.r},${n.c}`)) {
                      visited.add(`${n.r},${n.c}`); matches.push(n);
                    }
                  }
                }
                if (matches.length >= 3) {
                  audio.playPop(450 + matches.length * 30);
                  setShake(4 + matches.length * 0.7);
                  matches.forEach(m => {
                    const b = updatedGrid[m.r][m.c];
                    if (b) {
                      explode(b.x, b.y, palette[b.color], 16, 1.1);
                      if (b.type && b.type !== 'normal') collectPowerUp(b.type, b.x, b.y);
                    }
                    updatedGrid[m.r][m.c] = null;
                  });
                  setScore(s => { onScoreChange(s + matches.length * 20); return s + matches.length * 20; });
                } else {
                  audio.playShoot();
                }
              }
            }

            const anchored = new Set<string>();
            const q: {r: number, c: number}[] = [];
            for (let c = 0; c < GRID_COLS; c++) { if (updatedGrid[0][c]) { anchored.add(`0,${c}`); q.push({ r: 0, c }); } }
            let qi = 0;
            while (qi < q.length) {
              const curr = q[qi++];
              for (const n of getNeighbors(curr.r, curr.c)) {
                if (updatedGrid[n.r][n.c] && !anchored.has(`${n.r},${n.c}`)) {
                  anchored.add(`${n.r},${n.c}`); q.push(n);
                }
              }
            }
            let fallingCount = 0;
            for (let r = 0; r < GRID_ROWS; r++) {
              const cols = r % 2 === 0 ? GRID_COLS : GRID_COLS - 1;
              for (let c = 0; c < cols; c++) {
                if (updatedGrid[r][c] && !anchored.has(`${r},${c}`)) {
                  const b = updatedGrid[r][c]!;
                  explode(b.x, b.y, palette[b.color], 10, 0.9);
                  if (b.type && b.type !== 'normal') collectPowerUp(b.type, b.x, b.y);
                  updatedGrid[r][c] = null;
                  fallingCount++;
                  setScore(s => { onScoreChange(s + 30); return s + 30; });
                }
              }
            }
            if (fallingCount > 0) audio.playPop(380);
            setGrid(updatedGrid);
            setProjectile(null);
            if (shotsTaken > 0 && shotsTaken % currentLevelShotsToDrop === 0) { dropGrid(); audio.playPop(250); setShake(6); }
            if (!updatedGrid.some(row => row.some(b => b !== null))) onWin();
            if (bestR >= GRID_ROWS - 3) onGameOver(score);
          }
        }
      }
      render();
      animationFrameId = requestAnimationFrame(update);
    };

    const drawBubble = (b: Bubble | Projectile, radius: number = BUBBLE_RADIUS, alpha: number = 1.0) => {
      const { x, y, color, type } = b;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.beginPath();
      ctx.arc(x, y, radius - 1, 0, Math.PI * 2);
      if (type === 'bomb') { ctx.fillStyle = '#1e1e2e'; ctx.shadowBlur = 20; ctx.shadowColor = '#f97316'; } 
      else if (type === 'laser') { ctx.fillStyle = '#0f172a'; ctx.shadowBlur = 20; ctx.shadowColor = '#38bdf8'; } 
      else { ctx.fillStyle = palette[color]; ctx.shadowBlur = 14; ctx.shadowColor = palette[color]; }
      ctx.fill();
      if (type === 'bomb') { ctx.fillStyle = '#f97316'; ctx.beginPath(); ctx.arc(x, y, radius / 2, 0, Math.PI * 2); ctx.fill(); ctx.fillStyle = '#ffffff'; ctx.fillRect(x - 2, y - 10, 4, 12); } 
      else if (type === 'laser') { ctx.strokeStyle = '#38bdf8'; ctx.lineWidth = 5; ctx.beginPath(); ctx.moveTo(x - radius/2, y); ctx.lineTo(x + radius/2, y); ctx.stroke(); } 
      else { ctx.beginPath(); ctx.arc(x - radius/3, y - radius/3, radius/4, 0, Math.PI * 2); ctx.fillStyle = 'rgba(255,255,255,0.5)'; ctx.fill(); }
      ctx.restore();
    };

    const render = () => {
      ctx.save();
      if (shake > 0) ctx.translate(Math.random() * shake - shake/2, Math.random() * shake - shake/2);
      ctx.clearRect(-40, -40, CANVAS_WIDTH + 80, CANVAS_HEIGHT + 80);
      ctx.beginPath();
      ctx.strokeStyle = 'rgba(244, 63, 94, 0.3)';
      ctx.setLineDash([5, 5]);
      const dangerY = (GRID_ROWS - 3) * BUBBLE_RADIUS * 1.732 + BUBBLE_RADIUS * 2;
      ctx.moveTo(0, dangerY); ctx.lineTo(CANVAS_WIDTH, dangerY); ctx.stroke(); ctx.setLineDash([]);
      grid.forEach(row => row.forEach(b => b && drawBubble(b)));

      const dx = mousePos.current.x - SHOOTER_X, dy = mousePos.current.y - SHOOTER_Y;
      const angle = Math.atan2(dy, dx);

      if (!isPaused) {
        ctx.beginPath(); 
        ctx.setLineDash([6, 8]); 
        ctx.lineWidth = 2.5; 
        ctx.moveTo(SHOOTER_X, SHOOTER_Y); 
        ctx.lineTo(SHOOTER_X + Math.cos(angle) * 160, SHOOTER_Y + Math.sin(angle) * 160); 
        ctx.strokeStyle = 'rgba(255,255,255,0.4)'; 
        ctx.stroke(); 
        ctx.setLineDash([]);
      }

      if (projectile) drawBubble(projectile);

      particles.forEach(p => {
        if (p.type === 'beam') { ctx.save(); ctx.beginPath(); ctx.fillStyle = `rgba(0, 255, 255, ${p.life})`; ctx.fillRect(0, p.y - 15, CANVAS_WIDTH, 30); ctx.fillStyle = `rgba(255, 255, 255, ${p.life * 1.8})`; ctx.fillRect(0, p.y - 5, CANVAS_WIDTH, 10); ctx.restore(); } 
        else { ctx.save(); ctx.globalAlpha = p.life; ctx.beginPath(); ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2); ctx.fillStyle = p.color; ctx.fill(); ctx.restore(); }
      });

      const dropsIn = currentLevelShotsToDrop - (shotsTaken % currentLevelShotsToDrop);
      ctx.fillStyle = dropsIn <= 1 ? 'rgba(244, 63, 94, 1.0)' : 'rgba(255, 255, 255, 0.5)';
      ctx.font = '700 16px Luckiest Guy'; ctx.textAlign = 'left'; ctx.fillText(`THREAT IN: ${dropsIn}`, 20, CANVAS_HEIGHT - 20);

      if (storedPowerUp !== 'normal') {
        const glowScale = 1 + Math.sin(pulseRef.current * 4) * 0.1;
        ctx.save();
        ctx.shadowBlur = 20;
        ctx.shadowColor = storedPowerUp === 'bomb' ? '#f97316' : '#38bdf8';
        drawBubble({ x: CANVAS_WIDTH - 40, y: CANVAS_HEIGHT - 30, color: 'sky', row: 0, col: 0, type: storedPowerUp }, BUBBLE_RADIUS * glowScale);
        ctx.fillStyle = 'white';
        ctx.font = '800 10px Fredoka';
        ctx.textAlign = 'center';
        ctx.fillText('READY!', CANVAS_WIDTH - 40, CANVAS_HEIGHT - 5);
        ctx.restore();

        ctx.save();
        ctx.globalAlpha = 0.3 + Math.sin(pulseRef.current * 4) * 0.2;
        ctx.beginPath();
        ctx.arc(SHOOTER_X, SHOOTER_Y, BUBBLE_RADIUS + 15, 0, Math.PI * 2);
        ctx.fillStyle = storedPowerUp === 'bomb' ? '#f97316' : '#38bdf8';
        ctx.fill();
        ctx.restore();
      }

      drawBubble({ x: SHOOTER_X, y: SHOOTER_Y, color: activeColor, row: 0, col: 0, type: storedPowerUp }, BUBBLE_RADIUS + 4);
      drawBubble({ x: SHOOTER_X + 80, y: SHOOTER_Y + 15, color: nextColor, row: 0, col: 0, type: 'normal' }, BUBBLE_RADIUS * 0.8);

      ctx.fillStyle = 'rgba(255,255,255,0.7)'; ctx.font = '600 12px Fredoka'; ctx.textAlign = 'center'; ctx.fillText('NEXT', SHOOTER_X + 80, SHOOTER_Y + 45);
      ctx.restore();
    };
    update();
    return () => cancelAnimationFrame(animationFrameId);
  }, [grid, projectile, activeColor, nextColor, particles, onGameOver, onScoreChange, onWin, score, palette, shotsTaken, dropGrid, triggerBomb, triggerLaser, shake, level, currentLevelShotsToDrop, isPaused, storedPowerUp, collectPowerUp]);

  const handlePointer = (e: React.PointerEvent) => {
    if (isPaused) return;
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    mousePos.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  return (
    <div className="relative w-full h-full">
      <canvas
        ref={canvasRef}
        width={CANVAS_WIDTH}
        height={CANVAS_HEIGHT}
        onPointerMove={handlePointer}
        onPointerDown={(e) => { handlePointer(e); handleShoot(); }}
        className={`w-full h-full cursor-crosshair touch-none select-none transition-opacity ${isPaused ? 'opacity-50' : 'opacity-100'}`}
      />

      {/* Level Goal Overlay */}
      {showGoal && (
        <div className="absolute inset-0 flex items-center justify-center z-40 pointer-events-none">
          <div className="bg-slate-900/80 backdrop-blur-md px-10 py-8 rounded-[40px] border-4 border-cyan-500/50 shadow-2xl flex flex-col items-center animate-in fade-in zoom-in duration-300">
            <h3 className="text-cyan-400 font-game text-4xl mb-2">LEVEL {level}</h3>
            <p className="text-white font-game text-xl tracking-wider uppercase">GOAL: CLEAR ALL BUBBLES</p>
            <div className="mt-4 w-12 h-1 bg-cyan-500/30 rounded-full overflow-hidden">
               <div className="h-full bg-cyan-400 animate-[progress_2s_ease-in-out_infinite]"></div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

